window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["NJ"] = {"code":"NJ","name":"New Jersey","agency":"New Jersey MVC","agencyShort":"MVC","handbook":"https://www.nj.gov/mvc/drivertopics/cdlmanual.htm","links":{},"en":[{"q":"On New Jersey highways, what is the maximum height of a vehicle or combination of vehicles, including its load?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","14 feet 6 inches"],"answer":0,"explanation":"New Jersey law (N.J.S.A. 39:3-84) sets the maximum height of any vehicle or combination, including load or contents, at 13 feet 6 inches on all highways. (Source: N.J.S.A. 39:3-84; NJDOT Commercial Vehicle Size and Weight Guidebook.)","handbook":"","hbref":""},{"q":"What is the maximum total gross weight of a vehicle allowed on New Jersey highways without an overweight permit?","options":["80,000 pounds","73,280 pounds","88,000 pounds","76,000 pounds"],"answer":0,"explanation":"New Jersey caps maximum total gross vehicle weight at 80,000 pounds, matching the federal limit (N.J.S.A. 39:3-84). Anything above this on a non-divisible load requires an overweight permit. (Source: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)","handbook":"","hbref":""},{"q":"On most New Jersey roads that are NOT part of the designated 102-inch or National Network, what is the maximum legal vehicle width?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","90 inches (7 feet 6 inches)"],"answer":0,"explanation":"While the designated National Network and New Jersey 102-inch truck network allow 102 inches (8'6\"), other public roads are limited to 96 inches (8 feet). (Source: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)","handbook":"","hbref":""},{"q":"What is the maximum width, including load, allowed for trucks on New Jersey's designated National Network and 102-inch truck route network?","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","120 inches (10 feet)","114 inches (9 feet 6 inches)"],"answer":0,"explanation":"On the designated National Network and the New Jersey 102-inch truck route network, the maximum outside width is 102 inches (8 feet 6 inches), per N.J.S.A. 39:3-84. (Source: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)","handbook":"","hbref":""},{"q":"Under New Jersey law, what is the maximum gross weight that may be carried on any single axle?","options":["22,400 pounds","20,000 pounds","34,000 pounds","24,000 pounds"],"answer":0,"explanation":"New Jersey allows up to 22,400 pounds on a single axle, which is higher than the basic federal 20,000-pound single-axle figure (N.J.S.A. 39:3-84). (Source: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)","handbook":"","hbref":""},{"q":"What is the maximum gross weight permitted on a tandem axle group on New Jersey highways?","options":["34,000 pounds","22,400 pounds","40,000 pounds","36,000 pounds"],"answer":0,"explanation":"New Jersey limits a tandem axle group to 34,000 pounds, the same as the federal standard (N.J.S.A. 39:3-84). (Source: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)","handbook":"","hbref":""},{"q":"What is the maximum overall length of a single (straight) truck on New Jersey highways when not hauling an indivisible load?","options":["40 feet","35 feet","45 feet","53 feet"],"answer":0,"explanation":"N.J.S.A. 39:3-84 limits a single vehicle's overall length to 40 feet (extended to 50 feet only when carrying poles, pilings, or other articles that cannot be divided). (Source: N.J.S.A. 39:3-84.)","handbook":"","hbref":""},{"q":"Under New Jersey statute, what is the maximum overall length of a truck-tractor and semitrailer COMBINATION (the power unit plus its load) on general highways?","options":["62 feet","53 feet","65 feet","75 feet"],"answer":0,"explanation":"N.J.S.A. 39:3-84 sets the overall length of a combination of vehicles, including load, at 62 feet. Note that on the National Network a tractor-semitrailer instead has no overall length limit, with the semitrailer itself capped at 53 feet. (Source: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)","handbook":"","hbref":""},{"q":"On New Jersey's National Network and designated 102-inch routes, what is the maximum length of a SEMITRAILER operating in a tractor-semitrailer combination?","options":["53 feet","48 feet","57 feet","45 feet"],"answer":0,"explanation":"A semitrailer may be up to 53 feet on the National Network and the NJ 102-inch network (48 feet on other highways), per NJDOT rules and N.J.S.A. 39:3-84. (Source: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)","handbook":"","hbref":""},{"q":"For a 48-to-53-foot semitrailer operating on the New Jersey designated network, what is the maximum allowable distance from the kingpin to the center of the rear axle?","options":["41 feet","37 feet","46 feet","53 feet"],"answer":0,"explanation":"For trailers greater than 48 feet up to 53 feet, the kingpin-to-center-of-rear-axle distance cannot exceed 41 feet on the Interstate/designated network. (Source: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)","handbook":"","hbref":""},{"q":"In a twin-trailer (double) combination operating on New Jersey's designated network, what is the maximum length of EACH trailing unit?","options":["28 feet","33 feet","40 feet","53 feet"],"answer":0,"explanation":"Each trailer in a New Jersey twin-trailer combination is limited to 28 feet, consistent with the federal STAA double standard recognized under N.J.S.A. 39:3-84. (Source: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)","handbook":"","hbref":""},{"q":"What is the maximum gross load New Jersey allows per inch of tire width?","options":["800 pounds","650 pounds","500 pounds","1,000 pounds"],"answer":0,"explanation":"New Jersey limits load to 800 pounds per inch of tire width (N.J.S.A. 39:3-84). (Source: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)","handbook":"","hbref":""},{"q":"The federal bridge formula used in New Jersey, W = 500[LN/(N-1) + 12N + 36], determines what value?","options":["The maximum gross weight allowed on a group of consecutive axles based on their spacing and number","The maximum height of a vehicle based on its wheelbase","The maximum width based on the number of tires","The required minimum stopping distance for a loaded combination"],"answer":0,"explanation":"The Federal Bridge Formula, applied in New Jersey, computes the maximum allowable gross weight (W) on any group of two or more consecutive axles, where L is the spacing between outer axles and N is the number of axles. (Source: 23 CFR 658 / Federal Bridge Formula as applied by NJDOT; NJDOT Size and Weight Guidebook.)","handbook":"","hbref":""},{"q":"In the federal bridge formula as used in New Jersey, what does the variable 'L' represent?","options":["The distance in feet between the outer axles of the axle group","The total length of the trailer","The legal load limit in pounds","The lift-axle weight allowance"],"answer":0,"explanation":"In W = 500[LN/(N-1) + 12N + 36], 'L' is the distance in feet between the outermost axles of the group under consideration, and 'N' is the number of axles in that group. (Source: Federal Bridge Formula, 23 CFR 658, as applied by NJDOT.)","handbook":"","hbref":""},{"q":"When is a New Jersey oversize/overweight (OS/OW) permit issued for a load that exceeds the legal size or weight limits?","options":["Only when the load is non-divisible (cannot be dismantled or divided to meet legal limits)","For any load, divisible or not, as long as a fee is paid","Only for loads of agricultural produce","Only on weekends and holidays"],"answer":0,"explanation":"NJDOT issues OS/OW permits only for non-divisible loads, defined as loads that cannot be dismembered, dismantled, or divided so as to meet the weight and dimensional limits. (Source: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)","handbook":"","hbref":""},{"q":"How does a carrier in New Jersey apply for an oversize/overweight hauling permit?","options":["Online 24/7 through NJDOT's OS/OW permit website (nj.gotpermits.com)","Only in person at a county clerk's office during business hours","By mailing a notarized form to the State Police","Automatically with the issuance of a CDL"],"answer":0,"explanation":"Carriers may apply for NJDOT OS/OW permits online 24 hours a day, 7 days a week at the NJDOT OS/OW permit website (nj.gotpermits.com), either directly or through a registered permit service. (Source: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)","handbook":"","hbref":""},{"q":"At what load width (including the load) does New Jersey require at least one escort vehicle for a permitted oversize move?","options":["When width exceeds 14 feet","When width exceeds 10 feet","When width exceeds 8 feet 6 inches","When width exceeds 16 feet"],"answer":0,"explanation":"Under NJDOT permit rules, one escort vehicle is required when the width including load exceeds 14 feet; two escorts are required when width exceeds 16 feet. (Source: NJDOT OS/OW Permit Reference Guide; oversize.io NJ regulations.)","handbook":"","hbref":""},{"q":"A carrier wants to move a single, non-divisible piece of machinery on a tractor-semitrailer that will be 110,000 pounds gross and 12 feet wide on a New Jersey state highway. What must the carrier do?","options":["Obtain an NJDOT oversize/overweight permit before the move, since both weight and width exceed legal limits","Nothing, because non-divisible loads are automatically exempt from all limits","Only register the vehicle as agricultural to be exempt","Travel only at night without any permit"],"answer":0,"explanation":"The load exceeds the 80,000-pound gross limit and the 102-inch (8'6\") width limit, so an NJDOT OS/OW permit is required for this non-divisible load before travel, obtained via nj.gotpermits.com. A 12-foot width is below the 14-foot escort threshold. (Source: N.J.S.A. 39:3-84; NJDOT OS/OW Permit Reference Guide.)","handbook":"","hbref":""},{"q":"In New Jersey, which CDL class is required to operate a combination vehicle with a gross combination weight rating (GCWR) of 26,001 or more pounds, where the towed unit has a GVWR of more than 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"The NJ CDL Manual defines Class A as any combination of vehicles with a GCWR of 26,001 or more pounds, provided the GVWR of the towed unit(s) is more than 10,000 pounds. Source: NJ MVC Commercial Driver License Manual (Class definitions).","handbook":"","hbref":""},{"q":"Under New Jersey rules, a single vehicle with a GVWR of 26,001 or more pounds, or such a vehicle towing a unit not over 10,000 pounds GVWR, requires which CDL class?","options":["Class A","Class B","Class C","Class E"],"answer":1,"explanation":"The NJ CDL Manual defines Class B as any single vehicle with a GVWR of 26,001 or more pounds, or that vehicle towing a unit whose GVWR is 10,000 pounds or less. Source: NJ MVC Commercial Driver License Manual.","handbook":"","hbref":""},{"q":"In New Jersey, a vehicle designed to transport 16 or more passengers (including the driver), or a smaller vehicle hauling placarded hazardous materials, requires at minimum which CDL class?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"The NJ CDL Manual defines Class C as a vehicle that does not meet Class A or B criteria but is designed to transport 16 or more passengers including the operator, or is used to transport hazardous materials requiring placarding. Source: NJ MVC Commercial Driver License Manual.","handbook":"","hbref":""},{"q":"A New Jersey vehicle is designed to carry 16 or more passengers including the driver but weighs under 26,001 pounds. What is the minimum CDL class needed?","options":["No CDL required","Class A","Class B","Class C"],"answer":3,"explanation":"Even when under the weight thresholds for Class A or B, a vehicle designed to carry 16 or more people including the operator falls into Class C in New Jersey. Source: NJ MVC Commercial Driver License Manual (Class C definition).","handbook":"","hbref":""},{"q":"Which endorsement does a New Jersey CDL holder need to drive a vehicle transporting liquids or gases in bulk in a permanently mounted tank?","options":["N (Tank Vehicle)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"answer":0,"explanation":"The N (Tank Vehicle) endorsement is required in New Jersey to operate vehicles that transport liquids or gases in bulk. Source: NJ MVC Endorsements page.","handbook":"","hbref":""},{"q":"In New Jersey, which endorsement is required to pull two or three trailers, and what class of CDL must the driver hold?","options":["T endorsement, with a Class A CDL","N endorsement, with a Class B CDL","T endorsement, with a Class C CDL","P endorsement, with a Class A CDL"],"answer":0,"explanation":"The T (Doubles/Triples) endorsement is needed to pull two or three trailers, and a Class A CDL is required to hold it. Source: NJ MVC Endorsements page.","handbook":"","hbref":""},{"q":"Before New Jersey will issue a HazMat (H) endorsement, the applicant must clear a background check conducted by which agency?","options":["The Transportation Security Administration (TSA)","The New Jersey MVC fraud unit","The Federal Motor Carrier Safety Administration (FMCSA)","The New Jersey State Police only"],"answer":0,"explanation":"New Jersey requires applicants for the HazMat (H) endorsement to be fingerprinted and pass a Transportation Security Administration (TSA) threat assessment before the endorsement is issued. Source: NJ MVC Hazardous Material Endorsements (HME) page; TSA HME program.","handbook":"","hbref":""},{"q":"To drive a school bus in New Jersey, which combination of CDL endorsements is required?","options":["Both P (Passenger) and S (School Bus)","S (School Bus) only","P (Passenger) only","S and H"],"answer":0,"explanation":"New Jersey requires school bus drivers to hold both the P (Passenger) and the S (School Bus) endorsements, plus pass a knowledge and road test and a background check. Source: NJ MVC Endorsements page.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a New Jersey CDL restricted to intrastate (within New Jersey only) operation?","options":["18 years old","21 years old","19 years old","17 years old"],"answer":0,"explanation":"A driver may obtain a New Jersey CDL at 18, but operation is limited to intrastate commerce (within New Jersey) until age 21. Source: NJ MVC Getting Your CDL page.","handbook":"","hbref":""},{"q":"What is the minimum age required to operate a commercial motor vehicle in interstate commerce with a New Jersey CDL?","options":["21 years old","18 years old","23 years old","19 years old"],"answer":0,"explanation":"Drivers under 21 with a New Jersey CDL may only operate intrastate; interstate commerce (and hazmat) requires the driver to be at least 21. Source: NJ MVC Getting Your CDL page.","handbook":"","hbref":""},{"q":"Under federal rules applied in New Jersey, how long must a Commercial Learner Permit (CLP) holder wait after the CLP is issued before taking the CDL skills test?","options":["A minimum of 14 days","A minimum of 30 days","A minimum of 7 days","A minimum of 60 days"],"answer":0,"explanation":"New Jersey applies the federal requirement that a CLP holder must wait a minimum of 14 days before taking the skills test. Source: NJ MVC Getting Your CDL / CLP pages.","handbook":"","hbref":""},{"q":"Once issued, how long is a New Jersey Commercial Learner Permit (CLP) valid?","options":["180 days","1 year","90 days","60 days"],"answer":0,"explanation":"A New Jersey CLP is valid for 180 days when issued. Source: NJ MVC Commercial Learner Permits (CLP) page.","handbook":"","hbref":""},{"q":"When operating a commercial motor vehicle on a New Jersey Commercial Learner Permit, the driver must also have in possession what?","options":["A valid New Jersey driver's license","A passport","A second CLP","Nothing additional"],"answer":0,"explanation":"A New Jersey CLP must be accompanied by a valid New Jersey driver's license when the holder operates a CMV. Source: NJ MVC Commercial Learner Permits (CLP) page.","handbook":"","hbref":""},{"q":"New Jersey requires CDL applicants to satisfy its identity verification standard by presenting how many points of identification?","options":["6 Points of ID","4 Points of ID","8 Points of ID","2 Points of ID"],"answer":0,"explanation":"New Jersey uses the 6 Points of ID system, requiring documents that establish identity, Social Security number, proof of address, and proof of legal presence in the U.S. Source: NJ MVC Getting Your CDL / 6 Points of ID.","handbook":"","hbref":""},{"q":"Which of the following documents is specifically required as part of New Jersey's CDL identity verification?","options":["Social Security card and proof of legal presence in the U.S.","A birth certificate from any country only","A union membership card","An employer letter only"],"answer":0,"explanation":"New Jersey's 6 Points of ID for a CDL include the Social Security card, proof of address, and proof of legal presence in the United States. Source: NJ MVC Getting Your CDL page.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) required before a first-time New Jersey CDL skills test must be obtained from a provider that is:","options":["Listed on the FMCSA Training Provider Registry","Approved by the NJ MVC only","Any commercial driving school","Certified by the TSA"],"answer":0,"explanation":"Since February 7, 2022, ELDT must be completed through a provider listed on the FMCSA Training Provider Registry before taking the skills test (or the knowledge test for HazMat). Source: NJ MVC Getting Your CDL; FMCSA TPR.","handbook":"","hbref":""},{"q":"For which endorsement must New Jersey ELDT be completed BEFORE the knowledge (written) test, rather than before the skills test?","options":["H (Hazardous Materials)","P (Passenger)","S (School Bus)","N (Tank Vehicle)"],"answer":0,"explanation":"For the HazMat (H) endorsement, ELDT must be completed before the knowledge test; for first-time Class A/B and the P and S endorsements, ELDT is required before the skills test. Source: NJ MVC CLP/CDL pages; FMCSA ELDT rule.","handbook":"","hbref":""},{"q":"A New Jersey CDL driver who operates only within New Jersey and must meet a state medical examiner's certificate requirement should self-certify under which category?","options":["Non-Excepted Intrastate","Non-Excepted Interstate","Excepted Interstate","Excepted Intrastate"],"answer":0,"explanation":"Non-Excepted Intrastate (NA) applies to drivers operating only within New Jersey who must meet medical certificate requirements. Source: NJ MVC CDL Holder Self-Certification; FMCSA medical certification categories.","handbook":"","hbref":""},{"q":"Which medical self-certification category applies to a New Jersey CDL holder who drives across state lines and must hold a valid DOT medical examiner's certificate?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"answer":0,"explanation":"Non-Excepted Interstate (NI) drivers operate in interstate commerce and must meet federal DOT medical card requirements, keeping a certificate from a National Registry examiner on file. Source: NJ MVC CDL Self-Certification; FMCSA categories.","handbook":"","hbref":""},{"q":"A New Jersey driver who self-certifies as Non-Excepted Interstate must obtain a medical examiner's certificate from a provider who is:","options":["Listed on the FMCSA National Registry of Certified Medical Examiners","Any licensed New Jersey physician","Approved by the local county clerk","Certified by the TSA"],"answer":0,"explanation":"Non-excepted drivers must be examined by a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners and keep the certificate on file. Source: NJ MVC CDL Self-Certification; FMCSA National Registry.","handbook":"","hbref":""},{"q":"In New Jersey, what is the maximum legal blood alcohol concentration (BAC) for a person operating a commercial motor vehicle (CMV)?","options":["0.02","0.04","0.08","0.10"],"answer":1,"explanation":"New Jersey follows the federal CMV standard: it is illegal to operate a CMV with a BAC of 0.04 percent or higher. This is stricter than the 0.08 limit for a personal vehicle. Source: NJ MVC CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under New Jersey's implied-consent rules for CDL holders, what happens if a driver refuses to submit to a test for alcohol concentration when operating a CMV?","options":["Only a fine is imposed, with no disqualification","It is treated as a major offense, disqualifying the driver just as a DUI conviction would","The driver receives a warning for a first refusal","The CDL is suspended for only 30 days"],"answer":1,"explanation":"By holding a CDL and driving in New Jersey, a driver gives implied consent to alcohol testing. Refusing the test is treated as a major offense and carries the same disqualification as a DUI conviction (1 year for a first offense). Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"In New Jersey, what is the minimum CDL disqualification period for a first major offense, such as a first DUI conviction while operating a non-placarded CMV?","options":["60 days","120 days","1 year","3 years"],"answer":2,"explanation":"A first major offense (including DUI, a BAC of 0.04 or higher, or test refusal) results in at least a 1-year CDL disqualification. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"If a New Jersey CDL driver commits a first major offense (such as DUI) while operating a vehicle that is placarded for hazardous materials, what is the disqualification period?","options":["1 year","18 months","3 years","5 years"],"answer":2,"explanation":"A first major offense committed while transporting placarded hazardous materials raises the disqualification from 1 year to 3 years. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in New Jersey for a second major offense (for example, a second DUI conviction at any time)?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"A second major offense results in a lifetime CDL disqualification. New Jersey follows the federal rule that two separate major offenses mean the driver loses the CDL for life. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"In New Jersey, how many serious traffic violations within a 3-year period (in separate incidents) trigger a 60-day CDL disqualification?","options":["1","2","3","4"],"answer":1,"explanation":"A second serious traffic violation within 3 years (in a separate incident) results in a 60-day disqualification. The first serious violation alone does not cause disqualification. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in New Jersey for a third serious traffic violation within a 3-year period (in separate incidents)?","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"A third serious traffic violation within 3 years results in a 120-day disqualification. The second within 3 years is 60 days. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Which of the following is classified as a serious traffic violation for a New Jersey CDL holder?","options":["Parking a CMV in a no-parking zone","Speeding 15 mph or more over the posted speed limit","A burned-out clearance lamp","Failing to keep a logbook neat"],"answer":1,"explanation":"Excessive speeding, defined as 15 mph or more above the posted limit, is a serious traffic violation. Others include reckless driving, improper lane changes, following too closely, and texting while driving. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"In New Jersey, what is the minimum CDL disqualification for a first conviction of a railroad-highway grade crossing violation while operating a CMV?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation results in a minimum 60-day disqualification. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification in New Jersey for a second railroad-highway grade crossing violation within a 3-year period?","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"A second railroad-highway grade crossing violation within 3 years results in a minimum 120-day disqualification. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification in New Jersey for a third railroad-highway grade crossing violation within a 3-year period?","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third railroad-highway grade crossing violation within 3 years results in a minimum 1-year disqualification. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"In New Jersey, what is the minimum disqualification for a CDL driver's first conviction of violating an out-of-service (OOS) order while not carrying hazardous materials or passengers?","options":["90 days","120 days","180 days","1 year"],"answer":2,"explanation":"A first conviction for violating an out-of-service order carries a disqualification of at least 180 days (up to 1 year). Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"What is the disqualification range in New Jersey for a second out-of-service order violation within a 10-year period (non-hazmat, non-passenger)?","options":["180 days to 1 year","1 to 2 years","2 to 5 years","3 to 5 years"],"answer":2,"explanation":"A second out-of-service order violation within 10 years results in a disqualification of 2 to 5 years. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"What is the disqualification range in New Jersey for a third or subsequent out-of-service order violation within a 10-year period (non-hazmat, non-passenger)?","options":["180 days to 1 year","2 to 5 years","3 to 5 years","Lifetime"],"answer":2,"explanation":"A third or subsequent out-of-service order violation within 10 years results in a disqualification of 3 to 5 years. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"In New Jersey, in addition to disqualification, what civil penalty fine does a CDL driver face for a first conviction of violating an out-of-service order?","options":["At least $1,000","At least $2,500","At least $5,000","At least $10,000"],"answer":1,"explanation":"Beyond the disqualification, a driver who violates an out-of-service order is subject to a civil penalty of at least $2,500 for a first offense, and at least $5,000 for a subsequent offense. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.53.","handbook":"","hbref":""},{"q":"A New Jersey CDL driver violating an out-of-service order while transporting placarded hazardous materials faces what minimum disqualification for a first offense?","options":["120 days","180 days","1 year","2 years"],"answer":1,"explanation":"A first out-of-service order violation while transporting hazardous materials requiring placards (or while operating a vehicle designed to carry 16+ passengers) carries a disqualification of at least 180 days, up to 2 years. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"Under New Jersey and federal rules, texting while driving a CMV is classified as which type of violation for a CDL holder?","options":["A non-chargeable infraction","A serious traffic violation","A major offense","An out-of-service order violation"],"answer":1,"explanation":"Texting and using a hand-held mobile phone while driving a CMV are serious traffic violations. Two such violations within 3 years lead to a 60-day disqualification; three lead to 120 days. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2 and 392.80/392.82.","handbook":"","hbref":""},{"q":"What is the maximum driver fine for using a hand-held mobile phone or texting while operating a CMV that applies to New Jersey CDL drivers?","options":["Up to $500","Up to $1,000","Up to $2,750","Up to $5,000"],"answer":2,"explanation":"A CDL driver who uses a hand-held phone or texts while driving a CMV may be fined up to $2,750, and the offense counts as a serious traffic violation. Source: NJ MVC CDL Manual, Section 1; 49 CFR 392.82.","handbook":"","hbref":""},{"q":"Using a CMV in the commission of a felony involving manufacturing, distributing, or dispensing a controlled substance carries what New Jersey CDL disqualification?","options":["1 year","3 years","10 years","Lifetime with no possibility of reinstatement"],"answer":3,"explanation":"Using a CMV to commit a felony involving controlled substances is a major offense that results in a lifetime disqualification with no possibility of reinstatement. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"A New Jersey CDL holder accumulates a first DUI conviction, then later a separate conviction for leaving the scene of an accident in a CMV. What is the result of this second major offense?","options":["A 120-day disqualification","A 1-year disqualification","A 3-year disqualification","A lifetime disqualification"],"answer":3,"explanation":"DUI and leaving the scene of an accident in a CMV are both major offenses. Any two major offenses (in separate incidents) result in a lifetime CDL disqualification, even if they are different types of major offense. Source: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Under New Jersey's Move Over law, what must a driver of a commercial vehicle do when approaching a stopped emergency vehicle, tow truck, or highway maintenance vehicle displaying flashing lights on a multi-lane highway?","options":["Change lanes into a lane not adjacent to the stopped vehicle, if it can be done safely","Come to a complete stop until the stopped vehicle moves away","Continue at the posted speed but sound the horn while passing","Pull onto the shoulder and wait for an officer to wave traffic through"],"answer":0,"explanation":"New Jersey's Move Over law (N.J.S.A. 39:4-92.2) requires an approaching driver on a multi-lane road to change lanes into a lane not adjacent to the stopped vehicle when it is safe to do so. Source: N.J.S.A. 39:4-92.2; NJ MVC.","handbook":"","hbref":""},{"q":"Under the New Jersey Move Over law, if a driver cannot safely change lanes away from a stopped emergency or service vehicle with flashing lights, what is required?","options":["Reduce speed to a reasonable and proper speed below the posted limit and proceed with caution","Maintain the posted speed limit to avoid blocking traffic","Stop completely in the current lane until the lights are turned off","Move onto the median regardless of conditions"],"answer":0,"explanation":"N.J.S.A. 39:4-92.2 provides that when a lane change cannot be made safely, the driver must slow to a reasonable and proper speed below the posted limit and be prepared to stop. Source: N.J.S.A. 39:4-92.2; NJ MVC.","handbook":"","hbref":""},{"q":"In New Jersey, a bus must stop how far from the nearest rail of a railroad-highway grade crossing before proceeding?","options":["Between 15 and 50 feet","Between 5 and 15 feet","Between 50 and 100 feet","Between 10 and 25 feet"],"answer":0,"explanation":"The New Jersey CDL Manual (Section 4, Transporting Passengers) requires a bus to stop between 15 and 50 feet before a railroad crossing, then look and listen for trains. Source: NJ MVC Commercial Driver License Manual, Sec. 4.3.5.","handbook":"","hbref":""},{"q":"A placarded hazardous-materials vehicle in New Jersey must stop within what distance of the nearest rail before crossing railroad tracks?","options":["No closer than 15 feet and no farther than 50 feet","No closer than 25 feet and no farther than 75 feet","No closer than 10 feet and no farther than 40 feet","No closer than 5 feet and no farther than 30 feet"],"answer":0,"explanation":"The New Jersey CDL Manual (Section 9, Hazardous Materials) states a placarded vehicle, one carrying any amount of chlorine, or one with cargo tanks used for hazmat must stop 15 to 50 feet before the nearest rail. Source: NJ MVC CDL Manual, Sec. 9.6.12.","handbook":"","hbref":""},{"q":"On a two-lane, undivided New Jersey highway, a school bus is stopped with red lights flashing to pick up children. A vehicle approaching or overtaking the bus must stop at least how far away?","options":["25 feet","10 feet","20 feet","50 feet"],"answer":0,"explanation":"N.J.S.A. 39:4-128.1 requires a driver approaching or overtaking a school bus with flashing red lights on an undivided roadway to stop at least 25 feet away and remain stopped until the lights stop flashing. Source: N.J.S.A. 39:4-128.1.","handbook":"","hbref":""},{"q":"Under New Jersey law, a driver on a SEPARATE roadway of a dual or divided highway who approaches a school bus stopped with flashing red lights on the other roadway must do what?","options":["Reduce speed to no more than 10 mph and proceed with caution past the bus","Stop at least 25 feet from the bus and wait until the lights stop flashing","Stop completely and wait for the bus driver to wave traffic on","Continue at the posted speed because no action is required"],"answer":0,"explanation":"N.J.S.A. 39:4-128.1 provides a divided-highway exception: a driver on another roadway of a dual or divided highway need not stop but must slow to not more than 10 mph until past the bus and any children. Source: N.J.S.A. 39:4-128.1.","handbook":"","hbref":""},{"q":"When a New Jersey CMV is stopped on a one-way or divided highway, the driver must place the three warning devices (triangles) at which distances toward approaching traffic?","options":["10 feet, 100 feet, and 200 feet","10 feet, 50 feet, and 100 feet","25 feet, 100 feet, and 150 feet","10 feet, 200 feet, and 300 feet"],"answer":0,"explanation":"The New Jersey CDL Manual directs that on a one-way or divided highway, warning devices be placed 10 feet, 100 feet, and 200 feet toward approaching traffic. Source: NJ MVC CDL Manual, Sec. 2 (Driving Safely).","handbook":"","hbref":""},{"q":"After stopping a CMV on the shoulder of a New Jersey road, within how many minutes must the driver put out the emergency warning devices?","options":["10 minutes","5 minutes","15 minutes","30 minutes"],"answer":0,"explanation":"The New Jersey CDL Manual requires that if you must stop on a road or shoulder, you put out emergency warning devices within 10 minutes. Source: NJ MVC CDL Manual, Sec. 2 (Driving Safely).","handbook":"","hbref":""},{"q":"On a two-lane road carrying traffic in both directions in New Jersey, where should a stopped CMV's warning triangles be placed?","options":["Within 10 feet of the vehicle and 100 feet behind and ahead of it","100 feet and 200 feet behind the vehicle only","Within 25 feet of the vehicle and 200 feet behind it","10 feet, 100 feet, and 200 feet behind the vehicle only"],"answer":0,"explanation":"The New Jersey CDL Manual directs that on a two-lane road carrying traffic in both directions, place a triangle within 10 feet of the front or rear corners and others 100 feet behind and ahead of the vehicle. Source: NJ MVC CDL Manual, Sec. 2 (Driving Safely).","handbook":"","hbref":""},{"q":"Commercial vehicles with a registered gross weight over 10,000 pounds are prohibited from using the Garden State Parkway north of which interchange?","options":["Interchange 105","Interchange 80","Interchange 142","Interchange 9"],"answer":0,"explanation":"Commercial vehicles registered over 10,000 lbs are banned from the Garden State Parkway north of Interchange 105 (with limited exceptions for buses, permitted, and authority vehicles). Source: NJ Turnpike Authority Parkway regulations; N.J.A.C. 19:9-1.9.","handbook":"","hbref":""},{"q":"On the New Jersey Turnpike's 'dual-dual' section, what is true of the inner roadway between the southern split and the northern merge?","options":["It is restricted to cars only, while the outer roadway carries cars and trucks","It is restricted to trucks only, while the outer roadway carries cars only","It is reserved exclusively for buses and emergency vehicles","It carries northbound traffic only, regardless of vehicle type"],"answer":0,"explanation":"On the New Jersey Turnpike's dual-dual configuration, the inner roadway is designated car-only while the outer roadway carries both cars and trucks; trucks and buses are directed to the outer lanes. Source: NJ Turnpike Authority; NJ MVC.","handbook":"","hbref":""},{"q":"Under New Jersey's keep-right statute, on a multi-lane highway a driver who is not passing or preparing to turn left must do what?","options":["Stay in the right-hand lane available for traffic","Use the center lane at all times","Use whichever lane has the least traffic","Stay in the left-hand lane to keep the right clear for trucks"],"answer":0,"explanation":"N.J.S.A. 39:4-82 requires drivers to keep to the right and drive in the right-hand lane except when passing or preparing for a left turn; penalties are set under N.J.S.A. 39:4-88.1. Source: N.J.S.A. 39:4-82, 39:4-88.1.","handbook":"","hbref":""},{"q":"Under New Jersey regulations, when may a truck over five tons operate in a left lane of a multi-lane divided highway?","options":["Only to enter or leave the roadway, in an emergency, or when within one mile of a left turn","Anytime it is overtaking a slower vehicle","Only between midnight and 6 a.m.","Anytime traffic in the right lane is heavy"],"answer":0,"explanation":"New Jersey restricts trucks over five tons on divided highways to the right lanes, permitting the left lane only to enter/exit the roadway, in an emergency, or when within one mile of a left turn. Source: NJ keep-right rules; N.J.S.A. 39:4-82 and related Title 39 provisions.","handbook":"","hbref":""},{"q":"Under N.J.S.A. 39:4-98.1, the Commissioner of Transportation may set a lower maximum speed limit for trucks of 10,000 pounds or more registered weight at a differential of how much below the posted limit on qualifying multi-lane state highways?","options":["5 mph","10 mph","15 mph","20 mph"],"answer":0,"explanation":"N.J.S.A. 39:4-98.1 authorizes a posted lower truck speed limit at a 5 mph differential for trucks of 10,000 lbs or more on state highways of four or more lanes where the limit is 50 mph or greater. Source: N.J.S.A. 39:4-98.1.","handbook":"","hbref":""},{"q":"Under New Jersey's general speed statute, absent a posted limit, what is the statutory speed limit for 'all other locations' (not business, residential, or school zones)?","options":["50 mph","55 mph","65 mph","45 mph"],"answer":0,"explanation":"N.J.S.A. 39:4-98 sets prima facie limits of 25 mph in business/residential districts, 35 mph in certain suburban districts, and 50 mph in all other locations, unless a different limit is posted. Source: N.J.S.A. 39:4-98.","handbook":"","hbref":""},{"q":"While crossing railroad tracks in a New Jersey CMV after a required stop, what must the driver NOT do?","options":["Shift gears while any part of the vehicle is on the tracks","Use the four-way emergency flashers while approaching","Look and listen in both directions for a train","Roll down the window before crossing"],"answer":0,"explanation":"The New Jersey CDL Manual instructs drivers not to shift gears while crossing railroad tracks, so the vehicle does not stall on the crossing. Source: NJ MVC CDL Manual, Secs. 2.15 and 9.6.12.","handbook":"","hbref":""},{"q":"A New Jersey bus driver is NOT required to stop at a railroad crossing in which of the following situations?","options":["The crossing is marked 'exempt' or 'abandoned'","The crossing has a crossbuck but no gate","The crossing has two sets of tracks","The crossing is in a rural area with no signals"],"answer":0,"explanation":"The New Jersey CDL Manual lists exceptions to the bus stop requirement, including where a police officer or flagman directs traffic, where a traffic signal is green, and at crossings marked 'exempt' or 'abandoned.' Source: NJ MVC CDL Manual, Sec. 4.3.5.","handbook":"","hbref":""},{"q":"In New Jersey, at a railroad crossing with a crossbuck but no white stop line painted on the pavement, vehicles required to stop must stop within what range of the nearest rail?","options":["No closer than 15 feet and no farther than 50 feet","No closer than 10 feet and no farther than 30 feet","No closer than 20 feet and no farther than 60 feet","No closer than 25 feet and no farther than 100 feet"],"answer":0,"explanation":"The New Jersey CDL Manual states that where no white stop line is painted, vehicles required to stop must stop no closer than 15 feet and no more than 50 feet from the nearest rail. Source: NJ MVC CDL Manual, Sec. 2.15.","handbook":"","hbref":""},{"q":"Without an oversize permit, what is the maximum legal vehicle width on New Jersey highways?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"answer":0,"explanation":"New Jersey's legal maximum width is 8 feet 6 inches (102 inches); loads exceeding this require an oversize permit from NJDOT. Standard legal height is 13 feet 6 inches and gross weight is 80,000 lbs. Source: NJDOT Commercial Vehicle size/weight regulations; Title 39.","handbook":"","hbref":""},{"q":"A school bus is stalled on a railroad-highway crossing in New Jersey. According to the New Jersey CDL Manual, what should the driver do first?","options":["Evacuate the students and lead them at least 100 feet away from the tracks at an angle toward any oncoming train","Keep students seated and attempt to restart the engine while on the crossing","Have students lie on the floor of the bus until help arrives","Leave the bus and run down the tracks to flag the train"],"answer":0,"explanation":"The New Jersey CDL Manual (School Bus section) directs the driver to evacuate immediately and lead students to a safe place at least 100 feet off the tracks, moving toward and away from an approaching train at an angle so they are not struck by debris. Source: NJ MVC CDL Manual, Sec. 10 (School Buses).","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in New Jersey?","options":["The New Jersey Motor Vehicle Commission (MVC)","The New Jersey Department of Transportation (NJDOT)","The New Jersey State Police Commercial Bureau","The federal Motor Carrier Safety Administration (FMCSA)"],"answer":0,"explanation":"In New Jersey, CDLs are issued by the New Jersey Motor Vehicle Commission (MVC). NJDOT handles roads and oversize/overweight permits, and FMCSA sets federal standards but does not issue the license. Source: NJ MVC, Getting your Commercial Driver License (nj.gov/mvc/drivertopics/gettingcdl.htm).","handbook":"","hbref":""},{"q":"Before a first-time New Jersey applicant can be tested for a CDL, how many points of identification must they present to the MVC?","options":["6 points of identification","4 points of identification","8 points of identification","2 points of identification"],"answer":0,"explanation":"New Jersey uses a 6 Points of ID verification program; CDL applicants must establish six points of identification (including proof of Social Security number, address, and legal presence). Source: NJ MVC, Getting your Commercial Driver License and the NJ MVC 6 Points of ID Program.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a New Jersey CDL for INTRASTATE (within New Jersey only) operation?","options":["18 years old","21 years old","19 years old","20 years old"],"answer":0,"explanation":"A person must be at least 18 to obtain a NJ CDL for intrastate driving; drivers under 21 are restricted to intrastate operation and must self-certify to commerce category 3 or 4. Interstate operation requires age 21. Source: NJ MVC, Getting your Commercial Driver License and Commercial Learner Permits (CLP).","handbook":"","hbref":""},{"q":"A 20-year-old New Jersey CDL holder is limited to which type of operation?","options":["Intrastate only (within New Jersey)","Interstate only (across state lines)","Both interstate and intrastate","Hazardous materials transport only"],"answer":0,"explanation":"Drivers under 21 may operate only in intrastate commerce (within New Jersey) and must select self-certification commerce category 3 or 4. Interstate operation is not permitted until age 21. Source: NJ MVC, Commercial Learner Permits (CLP).","handbook":"","hbref":""},{"q":"What training must a New Jersey applicant complete before taking the CDL skills test for the first time?","options":["Entry-Level Driver Training (ELDT) from an FMCSA Training Provider Registry provider","A state-run defensive driving course at an MVC agency","A 40-hour OSHA commercial safety certification","A NJDOT-approved oversize load handling class"],"answer":0,"explanation":"Effective February 7, 2022, applicants must complete Entry-Level Driver Training (ELDT) from a provider listed on the FMCSA Training Provider Registry before taking the CDL skills test (and before the HAZMAT knowledge test). Source: NJ MVC, Getting your Commercial Driver License; FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"The New Jersey CDL self-certification has how many commerce categories from which an applicant must choose?","options":["4 categories","2 categories","3 categories","5 categories"],"answer":0,"explanation":"There are four self-certification commerce categories: (1) non-excepted interstate, (2) excepted interstate, (3) non-excepted intrastate, and (4) excepted intrastate. The applicant must select one. Source: NJ MVC, CDL Self-Certification and Medical Examiner Certificate (cdlmedcert.htm).","handbook":"","hbref":""},{"q":"Which self-certification categories REQUIRE a CDL holder to have a valid Medical Examiner's Certificate on file in New Jersey?","options":["Non-excepted interstate (1) and non-excepted intrastate (3)","Excepted interstate (2) and excepted intrastate (4)","Non-excepted interstate (1) and excepted interstate (2)","Only non-excepted interstate (1)"],"answer":0,"explanation":"The 'non-excepted' categories (1 and 3) require a valid Medical Examiner's Certificate. The 'excepted' categories (2 and 4) do not require one unless the driver holds a passenger (P) or school bus (S) endorsement. Source: NJ MVC, CDL Self-Certification and Medical Examiner Certificate.","handbook":"","hbref":""},{"q":"How does a driver's medical examiner's certificate normally reach the New Jersey MVC under current rules?","options":["Electronically, transmitted from FMCSA's National Registry to the state licensing agency","The driver mails a notarized paper copy to NJDOT headquarters","The driver's employer files it with the New Jersey State Police","It is faxed by the trucking company to the local MVC agency"],"answer":0,"explanation":"Medical examiners electronically submit exam results to FMCSA's National Registry, and the certification is electronically transmitted to the State Driver Licensing Agency (NJ MVC); no paper certificate (Form MCSA-5876) is required as proof. Source: NJ MVC, CDL Self-Certification and Medical Examiner Certificate.","handbook":"","hbref":""},{"q":"Who is authorized to perform the physical examination for a CDL holder's Medical Examiner's Certificate?","options":["A medical examiner listed on FMCSA's National Registry of Certified Medical Examiners","Any licensed New Jersey physician, regardless of registry status","A nurse at an MVC licensing agency","A NJDOT-employed occupational health officer"],"answer":0,"explanation":"The exam must be performed by a federally certified medical examiner listed on FMCSA's National Registry of Certified Medical Examiners; that examiner submits results electronically. Source: NJ MVC, CDL Self-Certification and Medical Examiner Certificate.","handbook":"","hbref":""},{"q":"What does a New Jersey applicant receive after passing the CDL knowledge test(s)?","options":["A Commercial Learner's Permit (CLP)","A full Commercial Driver License (CDL)","A temporary HAZMAT endorsement card","A skills-test waiver certificate"],"answer":0,"explanation":"Passing the required knowledge test(s) qualifies the applicant for a Commercial Learner's Permit (CLP), which allows supervised practice before the skills test. The CDL is issued only after passing the skills test. Source: NJ MVC, Getting your Commercial Driver License and Commercial Learner Permits (CLP).","handbook":"","hbref":""},{"q":"What minimum percentage must an applicant score to pass a New Jersey CDL knowledge test?","options":["80%","70%","75%","90%"],"answer":0,"explanation":"Each applicant must answer at least 80% of the questions correctly to pass a CDL knowledge test in New Jersey. Source: NJ MVC, CDL Tests (cdltest.htm).","handbook":"","hbref":""},{"q":"The general knowledge CDL test in New Jersey consists of how many questions?","options":["50 questions","30 questions","100 questions","25 questions"],"answer":0,"explanation":"The CDL knowledge exam includes a 50-question general test, plus separate additional tests for each endorsement sought. Source: NJ MVC, CDL Tests (cdltest.htm).","handbook":"","hbref":""},{"q":"How long is a New Jersey Commercial Learner's Permit (CLP) valid after it is issued?","options":["180 days","90 days","1 year","60 days"],"answer":0,"explanation":"A New Jersey CLP is valid for 180 days from issuance. Source: NJ MVC, Commercial Learner Permits (CLP) (cdlclp.htm).","handbook":"","hbref":""},{"q":"How many times may a New Jersey Commercial Learner's Permit (CLP) be renewed?","options":["Once","It cannot be renewed","Twice","An unlimited number of times"],"answer":0,"explanation":"A NJ CLP is valid for 180 days and may be renewed only once (for an additional period) without retaking the knowledge tests. Source: NJ MVC, Commercial Learner Permits (CLP).","handbook":"","hbref":""},{"q":"After a New Jersey CLP is issued, what is the minimum time a driver must hold it before taking the CDL skills test?","options":["14 days","30 days","7 days","10 days"],"answer":0,"explanation":"A CLP holder must wait a minimum of 14 days after the permit is issued before taking the CDL skills (road) test. Source: NJ MVC, Getting your Commercial Driver License; federal CLP rule (49 CFR 383.25).","handbook":"","hbref":""},{"q":"The New Jersey CDL skills test is made up of which three parts, in order?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written knowledge, vision screening, and on-road driving","Air-brake check, parallel parking, and highway merging","Coupling test, backing test, and HAZMAT handling"],"answer":0,"explanation":"The CDL skills (road) test has three parts taken in sequence: the pre-trip inspection, the basic vehicle control skills test, and the on-road driving test. Source: NJ MVC, CDL Tests (cdltest.htm).","handbook":"","hbref":""},{"q":"During the New Jersey pre-trip inspection portion of the skills test, the applicant must demonstrate the ability to do what?","options":["Identify and explain the components that should be inspected and why","Repair a failed air-brake chamber in under five minutes","Recite the entire CDL manual from memory","Disassemble and reassemble the fifth wheel"],"answer":0,"explanation":"In the pre-trip inspection test, the applicant must show they can identify each component to be inspected and explain why it is checked, proving the vehicle is safe to drive. Source: NJ MVC, CDL Tests (cdltest.htm).","handbook":"","hbref":""},{"q":"For the skills test, the applicant must supply a representative commercial motor vehicle that meets which condition?","options":["Current inspection, valid registration and insurance, and no cargo or hazardous materials","A vehicle loaded to its maximum gross weight rating","A vehicle no more than two years old","A vehicle owned only by a licensed motor carrier"],"answer":0,"explanation":"Applicants must provide an appropriate CMV representative of the class sought with a current inspection, valid registration and insurance, proper GVWR/placarding, and no cargo or hazardous materials aboard. Source: NJ MVC, CDL Tests (cdltest.htm).","handbook":"","hbref":""},{"q":"How often must a New Jersey CDL be renewed?","options":["Every 4 years","Every 2 years","Every 5 years","Every 8 years"],"answer":0,"explanation":"A standard New Jersey CDL is issued for a four-year term and must be renewed every 4 years (a first CDL may be prorated to match the basic license's expiration). Source: NJ MVC, Getting your Commercial Driver License (gettingcdl.htm).","handbook":"","hbref":""},{"q":"Which statement about renewing a New Jersey CDL is correct?","options":["It must be renewed in person at an MVC agency, not online or by mail","It can be fully renewed online like a basic Class D license","It can be renewed by mail only if no endorsements are held","It is renewed automatically with no driver action required"],"answer":0,"explanation":"Unlike a basic driver license, a New Jersey CDL cannot be renewed online or by mail; the holder must renew in person at an MVC agency and present required documents and current medical certification status. Note: exact fees can change, so confirm current amounts with MVC. Source: NJ MVC CDL renewal guidance.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная высота транспортного средства или состава транспортных средств, включая груз, на автомагистралях Нью-Джерси?","options":["13 футов 6 дюймов","13 футов 0 дюймов","14 футов 0 дюймов","14 футов 6 дюймов"],"explanation":"Закон Нью-Джерси (N.J.S.A. 39:3-84) устанавливает максимальную высоту любого транспортного средства или состава, включая груз или содержимое, в 13 футов 6 дюймов на всех автомагистралях. (Источник: N.J.S.A. 39:3-84; NJDOT Commercial Vehicle Size and Weight Guidebook.)"},"1":{"q":"Какова максимальная полная масса транспортного средства, разрешённая на автомагистралях Нью-Джерси без разрешения на перевозку сверхтяжёлого груза?","options":["80 000 фунтов","73 280 фунтов","88 000 фунтов","76 000 фунтов"],"explanation":"Нью-Джерси ограничивает максимальную полную массу транспортного средства до 80 000 фунтов, что соответствует федеральному ограничению (N.J.S.A. 39:3-84). Всё, что превышает этот предел для неделимого груза, требует разрешения на перевозку сверхтяжёлого груза. (Источник: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"2":{"q":"На большинстве дорог Нью-Джерси, которые НЕ входят в обозначенную сеть для 102 дюймов или Национальную сеть, какова максимальная допустимая ширина транспортного средства?","options":["96 дюймов (8 футов)","102 дюйма (8 футов 6 дюймов)","108 дюймов (9 футов)","90 дюймов (7 футов 6 дюймов)"],"explanation":"Хотя обозначенная Национальная сеть и сеть грузовых маршрутов Нью-Джерси для 102 дюймов допускают ширину 102 дюйма (8'6\"), на других дорогах общего пользования ширина ограничена 96 дюймами (8 футов). (Источник: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)"},"3":{"q":"Какова максимальная ширина, включая груз, разрешённая для грузовиков на обозначенной Национальной сети Нью-Джерси и сети грузовых маршрутов для 102 дюймов?","options":["102 дюйма (8 футов 6 дюймов)","96 дюймов (8 футов)","120 дюймов (10 футов)","114 дюймов (9 футов 6 дюймов)"],"explanation":"На обозначенной Национальной сети и сети грузовых маршрутов Нью-Джерси для 102 дюймов максимальная наружная ширина составляет 102 дюйма (8 футов 6 дюймов) согласно N.J.S.A. 39:3-84. (Источник: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"4":{"q":"Согласно закону Нью-Джерси, какова максимальная масса, которую можно перевозить на одной оси?","options":["22 400 фунтов","20 000 фунтов","34 000 фунтов","24 000 фунтов"],"explanation":"Нью-Джерси допускает до 22 400 фунтов на одну ось, что выше базового федерального показателя в 20 000 фунтов на одну ось (N.J.S.A. 39:3-84). (Источник: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)"},"5":{"q":"Какова максимальная масса, допустимая на сдвоенную группу осей на автомагистралях Нью-Джерси?","options":["34 000 фунтов","22 400 фунтов","40 000 фунтов","36 000 фунтов"],"explanation":"Нью-Джерси ограничивает сдвоенную группу осей до 34 000 фунтов, что соответствует федеральному стандарту (N.J.S.A. 39:3-84). (Источник: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"6":{"q":"Какова максимальная общая длина одиночного (бескапотного цельного) грузовика на автомагистралях Нью-Джерси, когда он не перевозит неделимый груз?","options":["40 футов","35 футов","45 футов","53 фута"],"explanation":"N.J.S.A. 39:3-84 ограничивает общую длину одиночного транспортного средства до 40 футов (увеличивается до 50 футов только при перевозке столбов, свай или других предметов, которые невозможно разделить). (Источник: N.J.S.A. 39:3-84.)"},"7":{"q":"Согласно закону Нью-Джерси, какова максимальная общая длина СОСТАВА из тягача и полуприцепа (тягача с грузом) на дорогах общего пользования?","options":["62 фута","53 фута","65 футов","75 футов"],"explanation":"N.J.S.A. 39:3-84 устанавливает общую длину состава транспортных средств, включая груз, в 62 фута. Обратите внимание, что в Национальной сети для состава из тягача и полуприцепа общего ограничения по длине нет, при этом сам полуприцеп ограничен 53 футами. (Источник: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"8":{"q":"В Национальной сети Нью-Джерси и на обозначенных маршрутах для 102 дюймов, какова максимальная длина ПОЛУПРИЦЕПА, работающего в составе из тягача и полуприцепа?","options":["53 фута","48 футов","57 футов","45 футов"],"explanation":"Полуприцеп может иметь длину до 53 футов в Национальной сети и сети Нью-Джерси для 102 дюймов (48 футов на других автомагистралях) согласно правилам NJDOT и N.J.S.A. 39:3-84. (Источник: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)"},"9":{"q":"Для полуприцепа длиной от 48 до 53 футов, работающего в обозначенной сети Нью-Джерси, каково максимально допустимое расстояние от шкворня до центра задней оси?","options":["41 фут","37 футов","46 футов","53 фута"],"explanation":"Для прицепов длиной более 48 футов и до 53 футов расстояние от шкворня до центра задней оси не может превышать 41 фут на межштатной/обозначенной сети. (Источник: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)"},"10":{"q":"В сдвоенном (двойном) составе с двумя прицепами, работающем в обозначенной сети Нью-Джерси, какова максимальная длина КАЖДОГО прицепляемого звена?","options":["28 футов","33 фута","40 футов","53 фута"],"explanation":"Каждый прицеп в сдвоенном составе с двумя прицепами в Нью-Джерси ограничен 28 футами, что соответствует федеральному стандарту STAA для двойных составов, признанному согласно N.J.S.A. 39:3-84. (Источник: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)"},"11":{"q":"Какую максимальную нагрузку на дюйм ширины шины допускает Нью-Джерси?","options":["800 фунтов","650 фунтов","500 фунтов","1 000 фунтов"],"explanation":"Нью-Джерси ограничивает нагрузку до 800 фунтов на дюйм ширины шины (N.J.S.A. 39:3-84). (Источник: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)"},"12":{"q":"Федеральная формула мостовой нагрузки, применяемая в Нью-Джерси, W = 500[LN/(N-1) + 12N + 36], определяет какое значение?","options":["Максимальную полную массу, допустимую на группу последовательных осей, исходя из их расстояния и количества","Максимальную высоту транспортного средства, исходя из его колёсной базы","Максимальную ширину, исходя из количества шин","Требуемую минимальную тормозную дистанцию для гружёного состава"],"explanation":"Федеральная формула мостовой нагрузки, применяемая в Нью-Джерси, вычисляет максимально допустимую полную массу (W) на любую группу из двух или более последовательных осей, где L — расстояние между крайними осями, а N — количество осей. (Источник: 23 CFR 658 / Federal Bridge Formula в применении NJDOT; NJDOT Size and Weight Guidebook.)"},"13":{"q":"В федеральной формуле мостовой нагрузки, применяемой в Нью-Джерси, что обозначает переменная 'L'?","options":["Расстояние в футах между крайними осями группы осей","Общую длину прицепа","Допустимый предел нагрузки в фунтах","Допуск по массе для подъёмной оси"],"explanation":"В формуле W = 500[LN/(N-1) + 12N + 36] 'L' — это расстояние в футах между крайними осями рассматриваемой группы, а 'N' — количество осей в этой группе. (Источник: Federal Bridge Formula, 23 CFR 658, в применении NJDOT.)"},"14":{"q":"Когда в Нью-Джерси выдаётся разрешение на негабаритный/сверхтяжёлый груз (OS/OW) для груза, превышающего допустимые пределы по размеру или массе?","options":["Только когда груз неделим (не может быть разобран или разделён для соблюдения допустимых пределов)","Для любого груза, делимого или нет, при условии оплаты сбора","Только для грузов сельскохозяйственной продукции","Только в выходные и праздничные дни"],"explanation":"NJDOT выдаёт разрешения OS/OW только для неделимых грузов, определяемых как грузы, которые невозможно разъединить, разобрать или разделить так, чтобы соответствовать пределам по массе и габаритам. (Источник: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)"},"15":{"q":"Как перевозчик в Нью-Джерси подаёт заявку на разрешение для перевозки негабаритного/сверхтяжёлого груза?","options":["Онлайн круглосуточно через сайт разрешений OS/OW NJDOT (nj.gotpermits.com)","Только лично в офисе окружного клерка в рабочие часы","Отправив нотариально заверенную форму по почте в полицию штата","Автоматически при выдаче CDL"],"explanation":"Перевозчики могут подавать заявки на разрешения OS/OW NJDOT онлайн 24 часа в сутки, 7 дней в неделю на сайте разрешений OS/OW NJDOT (nj.gotpermits.com), напрямую или через зарегистрированную службу оформления разрешений. (Источник: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)"},"16":{"q":"При какой ширине груза (включая груз) Нью-Джерси требует наличия хотя бы одного автомобиля сопровождения для разрешённой перевозки негабаритного груза?","options":["Когда ширина превышает 14 футов","Когда ширина превышает 10 футов","Когда ширина превышает 8 футов 6 дюймов","Когда ширина превышает 16 футов"],"explanation":"Согласно правилам разрешений NJDOT, один автомобиль сопровождения требуется, когда ширина, включая груз, превышает 14 футов; два автомобиля сопровождения требуются, когда ширина превышает 16 футов. (Источник: NJDOT OS/OW Permit Reference Guide; oversize.io NJ regulations.)"},"17":{"q":"Перевозчик хочет перевезти единичную, неделимую единицу оборудования на тягаче с полуприцепом, полная масса которого составит 110 000 фунтов, а ширина — 12 футов, по автомагистрали штата Нью-Джерси. Что должен сделать перевозчик?","options":["Получить разрешение NJDOT на негабаритный/сверхтяжёлый груз до перевозки, поскольку и масса, и ширина превышают допустимые пределы","Ничего, поскольку неделимые грузы автоматически освобождены от всех ограничений","Только зарегистрировать транспортное средство как сельскохозяйственное, чтобы получить освобождение","Перевозить только ночью без какого-либо разрешения"],"explanation":"Груз превышает предел полной массы в 80 000 фунтов и предел ширины в 102 дюйма (8'6\"), поэтому для этого неделимого груза до перевозки требуется разрешение NJDOT OS/OW, оформляемое через nj.gotpermits.com. Ширина 12 футов ниже порога в 14 футов для автомобиля сопровождения. (Источник: N.J.S.A. 39:3-84; NJDOT OS/OW Permit Reference Guide.)"},"18":{"q":"В Нью-Джерси какой класс CDL требуется для управления составом транспортных средств с полной массой состава (GCWR) 26 001 фунт или более, где буксируемое звено имеет GVWR более 10 000 фунтов?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Руководство CDL Нью-Джерси определяет класс A как любой состав транспортных средств с GCWR 26 001 фунт или более при условии, что GVWR буксируемого звена (звеньев) превышает 10 000 фунтов. Источник: NJ MVC Commercial Driver License Manual (определения классов)."},"19":{"q":"Согласно правилам Нью-Джерси, одиночное транспортное средство с GVWR 26 001 фунт или более, или такое транспортное средство, буксирующее звено с GVWR не более 10 000 фунтов, требует какого класса CDL?","options":["Класс A","Класс B","Класс C","Класс E"],"explanation":"Руководство CDL Нью-Джерси определяет класс B как любое одиночное транспортное средство с GVWR 26 001 фунт или более, или такое транспортное средство, буксирующее звено, GVWR которого составляет 10 000 фунтов или менее. Источник: NJ MVC Commercial Driver License Manual."},"20":{"q":"В Нью-Джерси транспортное средство, предназначенное для перевозки 16 или более пассажиров (включая водителя), или меньшее транспортное средство, перевозящее опасные материалы, требующие табличек, требует как минимум какого класса CDL?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"Руководство CDL Нью-Джерси определяет класс C как транспортное средство, которое не соответствует критериям класса A или B, но предназначено для перевозки 16 или более пассажиров, включая водителя, или используется для перевозки опасных материалов, требующих установки табличек. Источник: NJ MVC Commercial Driver License Manual."},"21":{"q":"Транспортное средство в Нью-Джерси предназначено для перевозки 16 или более пассажиров, включая водителя, но весит менее 26 001 фунта. Какой минимальный класс CDL необходим?","options":["CDL не требуется","Класс A","Класс B","Класс C"],"explanation":"Даже при массе ниже пороговых значений для класса A или B, транспортное средство, предназначенное для перевозки 16 или более человек, включая водителя, относится к классу C в Нью-Джерси. Источник: NJ MVC Commercial Driver License Manual (определение класса C)."},"22":{"q":"Какое подтверждение необходимо держателю CDL в Нью-Джерси, чтобы управлять транспортным средством, перевозящим жидкости или газы наливом в стационарно установленной цистерне?","options":["N (цистерна)","T (двойные/тройные прицепы)","H (опасные материалы)","P (пассажиры)"],"explanation":"Подтверждение N (цистерна) требуется в Нью-Джерси для управления транспортными средствами, перевозящими жидкости или газы наливом. Источник: NJ MVC Endorsements page."},"23":{"q":"В Нью-Джерси какое подтверждение требуется для буксировки двух или трёх прицепов, и какой класс CDL должен иметь водитель?","options":["Подтверждение T, с CDL класса A","Подтверждение N, с CDL класса B","Подтверждение T, с CDL класса C","Подтверждение P, с CDL класса A"],"explanation":"Подтверждение T (двойные/тройные прицепы) необходимо для буксировки двух или трёх прицепов, и для его получения требуется CDL класса A. Источник: NJ MVC Endorsements page."},"24":{"q":"Прежде чем Нью-Джерси выдаст подтверждение HazMat (H), заявитель должен пройти проверку благонадёжности, проводимую каким ведомством?","options":["Transportation Security Administration (TSA)","Отдел по борьбе с мошенничеством New Jersey MVC","Federal Motor Carrier Safety Administration (FMCSA)","Только полиция штата Нью-Джерси"],"explanation":"Нью-Джерси требует, чтобы заявители на подтверждение HazMat (H) сдали отпечатки пальцев и прошли оценку угрозы Transportation Security Administration (TSA) до выдачи подтверждения. Источник: NJ MVC Hazardous Material Endorsements (HME) page; TSA HME program."},"25":{"q":"Для управления школьным автобусом в Нью-Джерси какое сочетание подтверждений CDL требуется?","options":["Оба: P (пассажиры) и S (школьный автобус)","Только S (школьный автобус)","Только P (пассажиры)","S и H"],"explanation":"Нью-Джерси требует, чтобы водители школьных автобусов имели оба подтверждения — P (пассажиры) и S (школьный автобус), а также сдали теоретический и дорожный экзамены и прошли проверку благонадёжности. Источник: NJ MVC Endorsements page."},"26":{"q":"Каков минимальный возраст для получения CDL в Нью-Джерси с ограничением на внутриштатную (только в пределах Нью-Джерси) деятельность?","options":["18 лет","21 год","19 лет","17 лет"],"explanation":"Водитель может получить CDL в Нью-Джерси в 18 лет, но деятельность ограничена внутриштатными перевозками (в пределах Нью-Джерси) до достижения 21 года. Источник: NJ MVC Getting Your CDL page."},"27":{"q":"Каков минимальный возраст, необходимый для управления коммерческим автотранспортным средством в межштатных перевозках с CDL Нью-Джерси?","options":["21 год","18 лет","23 года","19 лет"],"explanation":"Водители младше 21 года с CDL Нью-Джерси могут осуществлять только внутриштатные перевозки; межштатные перевозки (и опасные материалы) требуют, чтобы водителю было не менее 21 года. Источник: NJ MVC Getting Your CDL page."},"28":{"q":"Согласно федеральным правилам, применяемым в Нью-Джерси, сколько времени должен ждать держатель ученического коммерческого разрешения (CLP) после выдачи CLP, прежде чем сдавать практический экзамен на CDL?","options":["Минимум 14 дней","Минимум 30 дней","Минимум 7 дней","Минимум 60 дней"],"explanation":"Нью-Джерси применяет федеральное требование, согласно которому держатель CLP должен ждать минимум 14 дней перед сдачей практического экзамена. Источник: NJ MVC Getting Your CDL / CLP pages."},"29":{"q":"Сколько времени действует ученическое коммерческое разрешение (CLP) Нью-Джерси после выдачи?","options":["180 дней","1 год","90 дней","60 дней"],"explanation":"CLP Нью-Джерси действует 180 дней с момента выдачи. Источник: NJ MVC Commercial Learner Permits (CLP) page."},"30":{"q":"При управлении коммерческим автотранспортным средством по ученическому коммерческому разрешению Нью-Джерси водитель также должен иметь при себе что?","options":["Действующее водительское удостоверение Нью-Джерси","Паспорт","Второе CLP","Ничего дополнительно"],"explanation":"CLP Нью-Джерси должно сопровождаться действующим водительским удостоверением Нью-Джерси, когда держатель управляет CMV. Источник: NJ MVC Commercial Learner Permits (CLP) page."},"31":{"q":"Нью-Джерси требует, чтобы заявители на CDL удовлетворяли стандарту подтверждения личности, предъявив сколько баллов идентификации?","options":["6 баллов ID","4 балла ID","8 баллов ID","2 балла ID"],"explanation":"Нью-Джерси использует систему 6 баллов ID, требующую документы, подтверждающие личность, номер социального страхования, подтверждение адреса и подтверждение законного нахождения в США. Источник: NJ MVC Getting Your CDL / 6 Points of ID."},"32":{"q":"Какой из следующих документов конкретно требуется в рамках подтверждения личности для CDL в Нью-Джерси?","options":["Карта социального страхования и подтверждение законного нахождения в США","Только свидетельство о рождении из любой страны","Карта членства в профсоюзе","Только письмо от работодателя"],"explanation":"6 баллов ID для CDL в Нью-Джерси включают карту социального страхования, подтверждение адреса и подтверждение законного нахождения в США. Источник: NJ MVC Getting Your CDL page."},"33":{"q":"Обучение водителей начального уровня (ELDT), требуемое перед первым практическим экзаменом на CDL в Нью-Джерси, должно быть получено у поставщика, который:","options":["Включён в реестр поставщиков обучения FMCSA (Training Provider Registry)","Одобрен только NJ MVC","Любая коммерческая автошкола","Сертифицирован TSA"],"explanation":"С 7 февраля 2022 года ELDT должно быть пройдено у поставщика, включённого в реестр поставщиков обучения FMCSA (Training Provider Registry), до сдачи практического экзамена (или теоретического экзамена для HazMat). Источник: NJ MVC Getting Your CDL; FMCSA TPR."},"34":{"q":"Для какого подтверждения в Нью-Джерси ELDT должно быть пройдено ДО теоретического (письменного) экзамена, а не до практического экзамена?","options":["H (опасные материалы)","P (пассажиры)","S (школьный автобус)","N (цистерна)"],"explanation":"Для подтверждения HazMat (H) ELDT должно быть пройдено до теоретического экзамена; для впервые получаемых класса A/B и подтверждений P и S ELDT требуется до практического экзамена. Источник: NJ MVC CLP/CDL pages; FMCSA ELDT rule."},"35":{"q":"Водитель с CDL Нью-Джерси, который осуществляет перевозки только в пределах Нью-Джерси и должен соответствовать требованию о наличии сертификата медицинского эксперта штата, должен самостоятельно подтвердить (self-certify) свою категорию как какую?","options":["Non-Excepted Intrastate","Non-Excepted Interstate","Excepted Interstate","Excepted Intrastate"],"explanation":"Non-Excepted Intrastate (NA) применяется к водителям, осуществляющим перевозки только в пределах Нью-Джерси, которые должны соответствовать требованиям к медицинскому сертификату. Источник: NJ MVC CDL Holder Self-Certification; FMCSA medical certification categories."},"36":{"q":"Какая категория медицинского самоподтверждения применяется к держателю CDL Нью-Джерси, который ездит через границы штатов и должен иметь действующий медицинский сертификат эксперта DOT?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Водители Non-Excepted Interstate (NI) осуществляют межштатные перевозки и должны соответствовать требованиям федеральной медицинской карты DOT, храня сертификат от эксперта из национального реестра. Источник: NJ MVC CDL Self-Certification; FMCSA categories."},"37":{"q":"Водитель в Нью-Джерси, который самостоятельно подтверждает категорию Non-Excepted Interstate, должен получить медицинский сертификат эксперта у поставщика, который:","options":["Включён в Национальный реестр сертифицированных медицинских экспертов FMCSA (National Registry of Certified Medical Examiners)","Любой лицензированный врач Нью-Джерси","Одобрен местным окружным клерком","Сертифицирован TSA"],"explanation":"Не освобождённые (non-excepted) водители должны пройти обследование у медицинского эксперта, включённого в Национальный реестр сертифицированных медицинских экспертов FMCSA, и хранить сертификат. Источник: NJ MVC CDL Self-Certification; FMCSA National Registry."},"38":{"q":"В Нью-Джерси какова максимальная допустимая концентрация алкоголя в крови (BAC) для лица, управляющего коммерческим автотранспортным средством (CMV)?","options":["0,02","0,04","0,08","0,10"],"explanation":"Нью-Джерси следует федеральному стандарту для CMV: незаконно управлять CMV с BAC 0,04 процента или выше. Это строже, чем предел 0,08 для личного автомобиля. Источник: NJ MVC CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51."},"39":{"q":"Согласно правилам подразумеваемого согласия Нью-Джерси для держателей CDL, что происходит, если водитель отказывается пройти тест на концентрацию алкоголя при управлении CMV?","options":["Налагается только штраф, без дисквалификации","Это рассматривается как серьёзное правонарушение (major offense), дисквалифицирующее водителя так же, как и осуждение за вождение в нетрезвом виде (DUI)","Водитель получает предупреждение за первый отказ","CDL приостанавливается только на 30 дней"],"explanation":"Имея CDL и управляя транспортным средством в Нью-Джерси, водитель даёт подразумеваемое согласие на тестирование на алкоголь. Отказ от теста рассматривается как серьёзное правонарушение и влечёт ту же дисквалификацию, что и осуждение за DUI (1 год за первое правонарушение). Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"40":{"q":"В Нью-Джерси каков минимальный срок дисквалификации CDL за первое серьёзное правонарушение, например, первое осуждение за DUI при управлении CMV без табличек об опасном грузе?","options":["60 дней","120 дней","1 год","3 года"],"explanation":"Первое серьёзное правонарушение (включая DUI, BAC 0,04 или выше, или отказ от теста) влечёт дисквалификацию CDL не менее чем на 1 год. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"41":{"q":"Если водитель с CDL Нью-Джерси совершает первое серьёзное правонарушение (например, DUI) при управлении транспортным средством с табличками об опасных материалах, каков срок дисквалификации?","options":["1 год","18 месяцев","3 года","5 лет"],"explanation":"Первое серьёзное правонарушение, совершённое при перевозке опасных материалов с табличками, увеличивает срок дисквалификации с 1 года до 3 лет. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"42":{"q":"Каков срок дисквалификации CDL в Нью-Джерси за второе серьёзное правонарушение (например, второе осуждение за DUI в любое время)?","options":["3 года","5 лет","10 лет","Пожизненно"],"explanation":"Второе серьёзное правонарушение влечёт пожизненную дисквалификацию CDL. Нью-Джерси следует федеральному правилу, согласно которому два отдельных серьёзных правонарушения означают, что водитель теряет CDL пожизненно. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"43":{"q":"В Нью-Джерси сколько серьёзных нарушений правил дорожного движения в течение 3-летнего периода (в отдельных случаях) влекут дисквалификацию CDL на 60 дней?","options":["1","2","3","4"],"explanation":"Второе серьёзное нарушение правил дорожного движения в течение 3 лет (в отдельном случае) влечёт дисквалификацию на 60 дней. Одно лишь первое серьёзное нарушение не влечёт дисквалификации. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2."},"44":{"q":"Каков срок дисквалификации CDL в Нью-Джерси за третье серьёзное нарушение правил дорожного движения в течение 3-летнего периода (в отдельных случаях)?","options":["60 дней","90 дней","120 дней","1 год"],"explanation":"Третье серьёзное нарушение правил дорожного движения в течение 3 лет влечёт дисквалификацию на 120 дней. Второе в течение 3 лет — 60 дней. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2."},"45":{"q":"Что из перечисленного классифицируется как серьёзное нарушение правил дорожного движения для держателя CDL Нью-Джерси?","options":["Парковка CMV в зоне, где парковка запрещена","Превышение скорости на 15 mph или более сверх установленного ограничения скорости","Перегоревший габаритный фонарь","Неаккуратное ведение бортового журнала"],"explanation":"Чрезмерное превышение скорости, определяемое как 15 mph или более сверх установленного ограничения, является серьёзным нарушением правил дорожного движения. К другим относятся неосторожное вождение, неправильная смена полосы движения, слишком близкое следование и отправка текстовых сообщений за рулём. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2."},"46":{"q":"В Нью-Джерси какова минимальная дисквалификация CDL за первое осуждение за нарушение на железнодорожном переезде при управлении CMV?","options":["30 дней","60 дней","120 дней","1 год"],"explanation":"Первое нарушение на железнодорожном переезде влечёт дисквалификацию минимум на 60 дней. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3."},"47":{"q":"Какова минимальная дисквалификация CDL в Нью-Джерси за второе нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["60 дней","90 дней","120 дней","1 год"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет влечёт дисквалификацию минимум на 120 дней. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3."},"48":{"q":"Какова минимальная дисквалификация CDL в Нью-Джерси за третье нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["120 дней","180 дней","1 год","3 года"],"explanation":"Третье нарушение на железнодорожном переезде в течение 3 лет влечёт дисквалификацию минимум на 1 год. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3."},"49":{"q":"В Нью-Джерси какова минимальная дисквалификация за первое осуждение водителя с CDL за нарушение предписания о выводе из эксплуатации (OOS), когда он не перевозит опасные материалы или пассажиров?","options":["90 дней","120 дней","180 дней","1 год"],"explanation":"Первое осуждение за нарушение предписания о выводе из эксплуатации влечёт дисквалификацию не менее чем на 180 дней (до 1 года). Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4."},"50":{"q":"Каков диапазон дисквалификации в Нью-Джерси за второе нарушение предписания о выводе из эксплуатации в течение 10-летнего периода (без опасных грузов, без пассажиров)?","options":["От 180 дней до 1 года","От 1 до 2 лет","От 2 до 5 лет","От 3 до 5 лет"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10 лет влечёт дисквалификацию на срок от 2 до 5 лет. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4."},"51":{"q":"Каков диапазон дисквалификации в Нью-Джерси за третье или последующее нарушение предписания о выводе из эксплуатации в течение 10-летнего периода (без опасных грузов, без пассажиров)?","options":["От 180 дней до 1 года","От 2 до 5 лет","От 3 до 5 лет","Пожизненно"],"explanation":"Третье или последующее нарушение предписания о выводе из эксплуатации в течение 10 лет влечёт дисквалификацию на срок от 3 до 5 лет. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4."},"52":{"q":"В Нью-Джерси, помимо дисквалификации, какой гражданско-правовой штраф грозит водителю с CDL за первое осуждение за нарушение предписания о выводе из эксплуатации?","options":["Не менее $1,000","Не менее $2,500","Не менее $5,000","Не менее $10,000"],"explanation":"Помимо дисквалификации, водитель, нарушивший предписание о выводе из эксплуатации, подвергается гражданско-правовому штрафу не менее $2,500 за первое правонарушение и не менее $5,000 за последующее правонарушение. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.53."},"53":{"q":"Водителю с CDL Нью-Джерси, нарушившему предписание о выводе из эксплуатации при перевозке опасных материалов с табличками, грозит какая минимальная дисквалификация за первое правонарушение?","options":["120 дней","180 дней","1 год","2 года"],"explanation":"Первое нарушение предписания о выводе из эксплуатации при перевозке опасных материалов, требующих табличек (или при управлении транспортным средством, предназначенным для перевозки 16+ пассажиров), влечёт дисквалификацию не менее чем на 180 дней, до 2 лет. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4."},"54":{"q":"Согласно правилам Нью-Джерси и федеральным правилам, отправка текстовых сообщений за рулём CMV классифицируется как какой тип нарушения для держателя CDL?","options":["Незачётное нарушение","Серьёзное нарушение правил дорожного движения","Серьёзное правонарушение (major offense)","Нарушение предписания о выводе из эксплуатации"],"explanation":"Отправка текстовых сообщений и использование ручного мобильного телефона за рулём CMV являются серьёзными нарушениями правил дорожного движения. Два таких нарушения в течение 3 лет влекут дисквалификацию на 60 дней; три — на 120 дней. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2 and 392.80/392.82."},"55":{"q":"Каков максимальный штраф для водителя за использование ручного мобильного телефона или отправку текстовых сообщений за рулём CMV, применяемый к водителям с CDL Нью-Джерси?","options":["До $500","До $1,000","До $2,750","До $5,000"],"explanation":"Водитель с CDL, который использует ручной телефон или отправляет текстовые сообщения за рулём CMV, может быть оштрафован на сумму до $2,750, и это правонарушение засчитывается как серьёзное нарушение правил дорожного движения. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 392.82."},"56":{"q":"Использование CMV при совершении тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества, влечёт какую дисквалификацию CDL в Нью-Джерси?","options":["1 год","3 года","10 лет","Пожизненно без возможности восстановления"],"explanation":"Использование CMV для совершения тяжкого преступления, связанного с контролируемыми веществами, является серьёзным правонарушением, которое влечёт пожизненную дисквалификацию без возможности восстановления. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"57":{"q":"Держатель CDL Нью-Джерси накапливает первое осуждение за DUI, а затем — отдельное осуждение за оставление места дорожно-транспортного происшествия на CMV. Каков результат этого второго серьёзного правонарушения?","options":["Дисквалификация на 120 дней","Дисквалификация на 1 год","Дисквалификация на 3 года","Пожизненная дисквалификация"],"explanation":"DUI и оставление места дорожно-транспортного происшествия на CMV — оба являются серьёзными правонарушениями. Любые два серьёзных правонарушения (в отдельных случаях) влекут пожизненную дисквалификацию CDL, даже если это разные типы серьёзных правонарушений. Источник: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"58":{"q":"Согласно закону Нью-Джерси «Move Over», что должен сделать водитель коммерческого транспортного средства, приближаясь к остановившемуся аварийному автомобилю, эвакуатору или машине дорожного обслуживания с включёнными проблесковыми маячками на многополосной автомагистрали?","options":["Перестроиться в полосу, не примыкающую к остановившемуся транспортному средству, если это можно сделать безопасно","Полностью остановиться, пока остановившееся транспортное средство не отъедет","Продолжать движение с разрешённой скоростью, но подавать звуковой сигнал при проезде","Съехать на обочину и ждать, пока сотрудник полиции не пропустит движение"],"explanation":"Закон Нью-Джерси «Move Over» (N.J.S.A. 39:4-92.2) требует, чтобы приближающийся водитель на многополосной дороге перестраивался в полосу, не примыкающую к остановившемуся транспортному средству, когда это безопасно. Источник: N.J.S.A. 39:4-92.2; NJ MVC."},"59":{"q":"Согласно закону Нью-Джерси «Move Over», если водитель не может безопасно перестроиться от остановившегося аварийного или служебного автомобиля с включёнными проблесковыми маячками, что требуется сделать?","options":["Снизить скорость до разумной и надлежащей, ниже разрешённого предела, и продолжать движение с осторожностью","Сохранять разрешённую скорость, чтобы не создавать помех движению","Полностью остановиться в текущей полосе, пока маячки не будут выключены","Выехать на разделительную полосу независимо от условий"],"explanation":"N.J.S.A. 39:4-92.2 предусматривает, что, когда перестроение невозможно выполнить безопасно, водитель должен снизить скорость до разумной и надлежащей, ниже разрешённого предела, и быть готовым остановиться. Источник: N.J.S.A. 39:4-92.2; NJ MVC."},"60":{"q":"В Нью-Джерси автобус должен остановиться на каком расстоянии от ближайшего рельса железнодорожного переезда перед тем, как продолжить движение?","options":["Между 15 и 50 футами","Между 5 и 15 футами","Между 50 и 100 футами","Между 10 и 25 футами"],"explanation":"Руководство CDL Нью-Джерси (Раздел 4, Перевозка пассажиров) требует, чтобы автобус останавливался между 15 и 50 футами перед железнодорожным переездом, а затем осматривался и прислушивался к приближению поездов. Источник: NJ MVC Commercial Driver License Manual, Sec. 4.3.5."},"61":{"q":"Транспортное средство с табличками, перевозящее опасные грузы, в Нью-Джерси должно остановиться в пределах какого расстояния от ближайшего рельса перед пересечением железнодорожных путей?","options":["Не ближе 15 футов и не дальше 50 футов","Не ближе 25 футов и не дальше 75 футов","Не ближе 10 футов и не дальше 40 футов","Не ближе 5 футов и не дальше 30 футов"],"explanation":"Руководство CDL Нью-Джерси (Раздел 9, Опасные материалы) гласит, что транспортное средство с табличками, перевозящее любое количество хлора, или с цистернами, используемыми для опасных грузов, должно остановиться в 15–50 футах перед ближайшим рельсом. Источник: NJ MVC CDL Manual, Sec. 9.6.12."},"62":{"q":"На двухполосной автомагистрали без разделения в Нью-Джерси школьный автобус остановился с мигающими красными огнями, чтобы забрать детей. Транспортное средство, приближающееся к автобусу или обгоняющее его, должно остановиться на расстоянии не менее скольки?","options":["25 футов","10 футов","20 футов","50 футов"],"explanation":"N.J.S.A. 39:4-128.1 требует, чтобы водитель, приближающийся к школьному автобусу с мигающими красными огнями или обгоняющий его на дороге без разделения, останавливался на расстоянии не менее 25 футов и оставался на месте, пока огни не перестанут мигать. Источник: N.J.S.A. 39:4-128.1."},"63":{"q":"Согласно закону Нью-Джерси, водитель на ОТДЕЛЬНОЙ проезжей части двойной или разделённой автомагистрали, который приближается к школьному автобусу, остановившемуся с мигающими красными огнями на другой проезжей части, должен сделать что?","options":["Снизить скорость до не более 10 mph и проехать мимо автобуса с осторожностью","Остановиться на расстоянии не менее 25 футов от автобуса и ждать, пока огни не перестанут мигать","Полностью остановиться и ждать, пока водитель автобуса не пропустит движение","Продолжать движение с разрешённой скоростью, поскольку никаких действий не требуется"],"explanation":"N.J.S.A. 39:4-128.1 предусматривает исключение для разделённых автомагистралей: водитель на другой проезжей части двойной или разделённой автомагистрали не обязан останавливаться, но должен снизить скорость до не более 10 mph, пока не проедет автобус и детей. Источник: N.J.S.A. 39:4-128.1."},"64":{"q":"Когда CMV в Нью-Джерси остановлен на дороге с односторонним движением или разделённой автомагистрали, водитель должен разместить три предупреждающих устройства (треугольники) на каких расстояниях в сторону приближающегося потока?","options":["10 футов, 100 футов и 200 футов","10 футов, 50 футов и 100 футов","25 футов, 100 футов и 150 футов","10 футов, 200 футов и 300 футов"],"explanation":"Руководство CDL Нью-Джерси предписывает, чтобы на дороге с односторонним движением или разделённой автомагистрали предупреждающие устройства размещались в 10 футах, 100 футах и 200 футах в сторону приближающегося потока. Источник: NJ MVC CDL Manual, Sec. 2 (Driving Safely)."},"65":{"q":"После остановки CMV на обочине дороги в Нью-Джерси, в течение скольки минут водитель должен выставить аварийные предупреждающие устройства?","options":["10 минут","5 минут","15 минут","30 минут"],"explanation":"Руководство CDL Нью-Джерси требует, чтобы при необходимости остановки на дороге или обочине вы выставили аварийные предупреждающие устройства в течение 10 минут. Источник: NJ MVC CDL Manual, Sec. 2 (Driving Safely)."},"66":{"q":"На двухполосной дороге с движением в обоих направлениях в Нью-Джерси, где следует размещать предупреждающие треугольники остановившегося CMV?","options":["В пределах 10 футов от транспортного средства и в 100 футах позади и впереди него","Только в 100 футах и 200 футах позади транспортного средства","В пределах 25 футов от транспортного средства и в 200 футах позади него","Только в 10 футах, 100 футах и 200 футах позади транспортного средства"],"explanation":"Руководство CDL Нью-Джерси предписывает, чтобы на двухполосной дороге с движением в обоих направлениях треугольник размещался в пределах 10 футов от передних или задних углов, а остальные — в 100 футах позади и впереди транспортного средства. Источник: NJ MVC CDL Manual, Sec. 2 (Driving Safely)."},"67":{"q":"Коммерческим транспортным средствам с зарегистрированной полной массой более 10 000 фунтов запрещено использовать Garden State Parkway к северу от какой развязки?","options":["Развязка 105","Развязка 80","Развязка 142","Развязка 9"],"explanation":"Коммерческим транспортным средствам, зарегистрированным с массой более 10 000 lbs, запрещён проезд по Garden State Parkway к северу от развязки 105 (с ограниченными исключениями для автобусов, транспорта с разрешением и транспорта дорожного управления). Источник: NJ Turnpike Authority Parkway regulations; N.J.A.C. 19:9-1.9."},"68":{"q":"На участке New Jersey Turnpike с конфигурацией «dual-dual» что верно в отношении внутренней проезжей части между южным разделением и северным слиянием?","options":["Она предназначена только для легковых автомобилей, тогда как внешняя проезжая часть пропускает легковые автомобили и грузовики","Она предназначена только для грузовиков, тогда как внешняя проезжая часть пропускает только легковые автомобили","Она зарезервирована исключительно для автобусов и аварийных служб","Она пропускает только движение в северном направлении независимо от типа транспортного средства"],"explanation":"В конфигурации «dual-dual» на New Jersey Turnpike внутренняя проезжая часть предназначена только для легковых автомобилей, тогда как внешняя пропускает как легковые автомобили, так и грузовики; грузовики и автобусы направляются во внешние полосы. Источник: NJ Turnpike Authority; NJ MVC."},"69":{"q":"Согласно закону Нью-Джерси о движении по правой стороне, на многополосной автомагистрали водитель, который не совершает обгон и не готовится к повороту налево, должен сделать что?","options":["Оставаться в правой полосе, доступной для движения","Постоянно использовать центральную полосу","Использовать ту полосу, где меньше всего движения","Оставаться в левой полосе, чтобы освободить правую для грузовиков"],"explanation":"N.J.S.A. 39:4-82 требует, чтобы водители держались правой стороны и двигались по правой полосе, за исключением случаев обгона или подготовки к повороту налево; штрафы установлены согласно N.J.S.A. 39:4-88.1. Источник: N.J.S.A. 39:4-82, 39:4-88.1."},"70":{"q":"Согласно правилам Нью-Джерси, когда грузовик массой более пяти тонн может двигаться по левой полосе многополосной разделённой автомагистрали?","options":["Только для въезда на проезжую часть или съезда с неё, в аварийной ситуации, или когда до поворота налево остаётся менее одной мили","В любое время при обгоне более медленного транспортного средства","Только в период с полуночи до 6 часов утра","В любое время, когда движение в правой полосе плотное"],"explanation":"Нью-Джерси ограничивает движение грузовиков массой более пяти тонн на разделённых автомагистралях правыми полосами, разрешая левую полосу только для въезда/съезда с проезжей части, в аварийной ситуации или когда до поворота налево остаётся менее одной мили. Источник: NJ keep-right rules; N.J.S.A. 39:4-82 и связанные положения Title 39."},"71":{"q":"Согласно N.J.S.A. 39:4-98.1, комиссар транспорта может установить более низкий максимальный предел скорости для грузовиков с зарегистрированной массой 10 000 фунтов и более с разницей на сколько ниже установленного предела на соответствующих многополосных автомагистралях штата?","options":["5 mph","10 mph","15 mph","20 mph"],"explanation":"N.J.S.A. 39:4-98.1 разрешает устанавливать более низкий предел скорости для грузовиков с разницей 5 mph для грузовиков массой 10 000 lbs и более на автомагистралях штата с четырьмя и более полосами, где предел составляет 50 mph или выше. Источник: N.J.S.A. 39:4-98.1."},"72":{"q":"Согласно общему закону Нью-Джерси о скорости, при отсутствии установленного знаком предела, какой установленный законом предел скорости действует для «всех прочих мест» (не деловых, жилых или школьных зон)?","options":["50 mph","55 mph","65 mph","45 mph"],"explanation":"N.J.S.A. 39:4-98 устанавливает презюмируемые пределы 25 mph в деловых/жилых районах, 35 mph в некоторых пригородных районах и 50 mph во всех прочих местах, если не установлен иной предел знаком. Источник: N.J.S.A. 39:4-98."},"73":{"q":"При пересечении железнодорожных путей на CMV в Нью-Джерси после обязательной остановки, что водитель НЕ должен делать?","options":["Переключать передачи, пока какая-либо часть транспортного средства находится на путях","Использовать четырёхстороннюю аварийную сигнализацию при приближении","Смотреть и прислушиваться в обоих направлениях, нет ли поезда","Опустить стекло перед пересечением"],"explanation":"Руководство CDL Нью-Джерси предписывает водителям не переключать передачи при пересечении железнодорожных путей, чтобы транспортное средство не заглохло на переезде. Источник: NJ MVC CDL Manual, Secs. 2.15 и 9.6.12."},"74":{"q":"Водитель автобуса в Нью-Джерси НЕ обязан останавливаться на железнодорожном переезде в какой из следующих ситуаций?","options":["Переезд обозначен как «exempt» (освобождённый) или «abandoned» (заброшенный)","На переезде есть знак-крестовина, но нет шлагбаума","На переезде два комплекта путей","Переезд находится в сельской местности без сигнализации"],"explanation":"Руководство CDL Нью-Джерси перечисляет исключения из требования об остановке автобуса, в том числе когда движением управляет сотрудник полиции или регулировщик, когда светофор зелёный, и на переездах, обозначенных как «exempt» или «abandoned». Источник: NJ MVC CDL Manual, Sec. 4.3.5."},"75":{"q":"В Нью-Джерси на железнодорожном переезде со знаком-крестовиной, но без белой стоп-линии, нанесённой на покрытие, транспортные средства, обязанные остановиться, должны остановиться в каком диапазоне от ближайшего рельса?","options":["Не ближе 15 футов и не дальше 50 футов","Не ближе 10 футов и не дальше 30 футов","Не ближе 20 футов и не дальше 60 футов","Не ближе 25 футов и не дальше 100 футов"],"explanation":"Руководство CDL Нью-Джерси гласит, что там, где не нанесена белая стоп-линия, транспортные средства, обязанные остановиться, должны остановиться не ближе 15 футов и не дальше 50 футов от ближайшего рельса. Источник: NJ MVC CDL Manual, Sec. 2.15."},"76":{"q":"Без разрешения на негабаритный груз, какова максимальная допустимая ширина транспортного средства на автомагистралях Нью-Джерси?","options":["8 футов 6 дюймов","8 футов 0 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Допустимая максимальная ширина в Нью-Джерси составляет 8 футов 6 дюймов (102 inches); грузы, превышающие этот размер, требуют разрешения на негабаритный груз от NJDOT. Стандартная допустимая высота — 13 футов 6 дюймов, а полная масса — 80 000 lbs. Источник: NJDOT Commercial Vehicle size/weight regulations; Title 39."},"77":{"q":"Школьный автобус заглох на железнодорожном переезде в Нью-Джерси. Согласно Руководству CDL Нью-Джерси, что водитель должен сделать в первую очередь?","options":["Эвакуировать учеников и отвести их на расстояние не менее 100 футов от путей под углом навстречу любому приближающемуся поезду","Оставить учеников на местах и попытаться завести двигатель, находясь на переезде","Уложить учеников на пол автобуса, пока не прибудет помощь","Покинуть автобус и побежать вдоль путей, чтобы остановить поезд"],"explanation":"Руководство CDL Нью-Джерси (раздел о школьных автобусах) предписывает водителю немедленно провести эвакуацию и отвести учеников в безопасное место на расстоянии не менее 100 футов от путей, двигаясь к приближающемуся поезду и от него под углом, чтобы их не задело осколками. Источник: NJ MVC CDL Manual, Sec. 10 (School Buses)."},"78":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Нью-Джерси?","options":["New Jersey Motor Vehicle Commission (MVC)","Департамент транспорта Нью-Джерси (NJDOT)","Коммерческое бюро полиции штата Нью-Джерси","Федеральное управление безопасности автоперевозчиков (FMCSA)"],"explanation":"В Нью-Джерси удостоверения CDL выдаёт New Jersey Motor Vehicle Commission (MVC). NJDOT занимается дорогами и разрешениями на негабаритные/тяжеловесные грузы, а FMCSA устанавливает федеральные стандарты, но не выдаёт удостоверение. Источник: NJ MVC, Getting your Commercial Driver License (nj.gov/mvc/drivertopics/gettingcdl.htm)."},"79":{"q":"Прежде чем впервые подающий заявление кандидат в Нью-Джерси сможет пройти тестирование на CDL, сколько баллов идентификации он должен предъявить в MVC?","options":["6 баллов идентификации","4 балла идентификации","8 баллов идентификации","2 балла идентификации"],"explanation":"Нью-Джерси использует программу проверки 6 Points of ID; кандидаты на CDL должны набрать шесть баллов идентификации (включая подтверждение номера социального страхования, адреса и законного пребывания). Источник: NJ MVC, Getting your Commercial Driver License и NJ MVC 6 Points of ID Program."},"80":{"q":"Каков минимальный возраст для получения CDL Нью-Джерси для ВНУТРИШТАТНОЙ (только в пределах Нью-Джерси) деятельности?","options":["18 лет","21 год","19 лет","20 лет"],"explanation":"Лицо должно быть не моложе 18 лет, чтобы получить CDL Нью-Джерси для внутриштатного вождения; водители младше 21 года ограничены внутриштатной деятельностью и должны самостоятельно сертифицироваться по категории коммерции 3 или 4. Межштатная деятельность требует возраста 21 год. Источник: NJ MVC, Getting your Commercial Driver License и Commercial Learner Permits (CLP)."},"81":{"q":"20-летний обладатель CDL Нью-Джерси ограничен каким типом деятельности?","options":["Только внутриштатной (в пределах Нью-Джерси)","Только межштатной (через границы штатов)","Как межштатной, так и внутриштатной","Только перевозкой опасных материалов"],"explanation":"Водители младше 21 года могут осуществлять деятельность только во внутриштатной коммерции (в пределах Нью-Джерси) и должны выбрать категорию самосертификации коммерции 3 или 4. Межштатная деятельность не разрешена до достижения 21 года. Источник: NJ MVC, Commercial Learner Permits (CLP)."},"82":{"q":"Какое обучение должен пройти кандидат в Нью-Джерси, прежде чем впервые сдать экзамен по практическим навыкам на CDL?","options":["Entry-Level Driver Training (ELDT) у провайдера из FMCSA Training Provider Registry","Государственный курс безопасного вождения в агентстве MVC","40-часовая сертификация коммерческой безопасности OSHA","Одобренный NJDOT курс по обращению с негабаритными грузами"],"explanation":"С 7 февраля 2022 года кандидаты должны пройти Entry-Level Driver Training (ELDT) у провайдера, указанного в FMCSA Training Provider Registry, прежде чем сдавать экзамен по практическим навыкам на CDL (и перед экзаменом на знание HAZMAT). Источник: NJ MVC, Getting your Commercial Driver License; FMCSA ELDT rule (49 CFR Part 380)."},"83":{"q":"Самосертификация на CDL в Нью-Джерси включает сколько категорий коммерции, из которых кандидат должен выбрать?","options":["4 категории","2 категории","3 категории","5 категорий"],"explanation":"Существует четыре категории самосертификации коммерции: (1) межштатная без исключений, (2) межштатная с исключениями, (3) внутриштатная без исключений и (4) внутриштатная с исключениями. Кандидат должен выбрать одну. Источник: NJ MVC, CDL Self-Certification and Medical Examiner Certificate (cdlmedcert.htm)."},"84":{"q":"Какие категории самосертификации ТРЕБУЮТ, чтобы у обладателя CDL в Нью-Джерси имелся действующий Medical Examiner's Certificate?","options":["Межштатная без исключений (1) и внутриштатная без исключений (3)","Межштатная с исключениями (2) и внутриштатная с исключениями (4)","Межштатная без исключений (1) и межштатная с исключениями (2)","Только межштатная без исключений (1)"],"explanation":"Категории «без исключений» (1 и 3) требуют действующего Medical Examiner's Certificate. Категории «с исключениями» (2 и 4) не требуют его, если только водитель не имеет пассажирского (P) или школьно-автобусного (S) эндорсемента. Источник: NJ MVC, CDL Self-Certification and Medical Examiner Certificate."},"85":{"q":"Каким образом медицинский сертификат водителя обычно поступает в MVC Нью-Джерси согласно действующим правилам?","options":["Электронно, передаётся из National Registry FMCSA в лицензирующее ведомство штата","Водитель отправляет нотариально заверенную бумажную копию по почте в штаб-квартиру NJDOT","Работодатель водителя подаёт его в полицию штата Нью-Джерси","Его отправляет по факсу транспортная компания в местное агентство MVC"],"explanation":"Медицинские эксперты электронно подают результаты обследования в National Registry FMCSA, и сертификация электронно передаётся в State Driver Licensing Agency (NJ MVC); бумажный сертификат (Form MCSA-5876) в качестве доказательства не требуется. Источник: NJ MVC, CDL Self-Certification and Medical Examiner Certificate."},"86":{"q":"Кто уполномочен проводить медицинское обследование для Medical Examiner's Certificate обладателя CDL?","options":["Медицинский эксперт, указанный в FMCSA National Registry of Certified Medical Examiners","Любой лицензированный врач Нью-Джерси, независимо от статуса в реестре","Медсестра в лицензирующем агентстве MVC","Сотрудник по гигиене труда, нанятый NJDOT"],"explanation":"Обследование должно проводиться федерально сертифицированным медицинским экспертом, указанным в FMCSA National Registry of Certified Medical Examiners; этот эксперт подаёт результаты электронно. Источник: NJ MVC, CDL Self-Certification and Medical Examiner Certificate."},"87":{"q":"Что получает кандидат в Нью-Джерси после сдачи экзамена(ов) на знание CDL?","options":["Commercial Learner's Permit (CLP)","Полноценное коммерческое водительское удостоверение (CDL)","Временную карточку эндорсемента HAZMAT","Сертификат освобождения от экзамена по практическим навыкам"],"explanation":"Сдача требуемого экзамена(ов) на знание квалифицирует кандидата для получения Commercial Learner's Permit (CLP), который позволяет практиковаться под наблюдением до экзамена по практическим навыкам. CDL выдаётся только после сдачи экзамена по практическим навыкам. Источник: NJ MVC, Getting your Commercial Driver License и Commercial Learner Permits (CLP)."},"88":{"q":"Какой минимальный процент должен набрать кандидат, чтобы сдать экзамен на знание CDL в Нью-Джерси?","options":["80%","70%","75%","90%"],"explanation":"Каждый кандидат должен правильно ответить не менее чем на 80% вопросов, чтобы сдать экзамен на знание CDL в Нью-Джерси. Источник: NJ MVC, CDL Tests (cdltest.htm)."},"89":{"q":"Общий экзамен на знание CDL в Нью-Джерси состоит из скольки вопросов?","options":["50 вопросов","30 вопросов","100 вопросов","25 вопросов"],"explanation":"Экзамен на знание CDL включает общий тест из 50 вопросов, а также отдельные дополнительные тесты для каждого запрашиваемого эндорсемента. Источник: NJ MVC, CDL Tests (cdltest.htm)."},"90":{"q":"Сколько действует Commercial Learner's Permit (CLP) Нью-Джерси после его выдачи?","options":["180 дней","90 дней","1 год","60 дней"],"explanation":"CLP Нью-Джерси действителен в течение 180 дней с момента выдачи. Источник: NJ MVC, Commercial Learner Permits (CLP) (cdlclp.htm)."},"91":{"q":"Сколько раз можно продлить Commercial Learner's Permit (CLP) Нью-Джерси?","options":["Один раз","Его нельзя продлить","Дважды","Неограниченное количество раз"],"explanation":"CLP Нью-Джерси действителен в течение 180 дней и может быть продлён только один раз (на дополнительный период) без повторной сдачи экзаменов на знание. Источник: NJ MVC, Commercial Learner Permits (CLP)."},"92":{"q":"После выдачи CLP Нью-Джерси, каков минимальный срок, в течение которого водитель должен владеть им, прежде чем сдавать экзамен по практическим навыкам на CDL?","options":["14 дней","30 дней","7 дней","10 дней"],"explanation":"Обладатель CLP должен выждать минимум 14 дней после выдачи разрешения, прежде чем сдавать экзамен по практическим навыкам (дорожный) на CDL. Источник: NJ MVC, Getting your Commercial Driver License; federal CLP rule (49 CFR 383.25)."},"93":{"q":"Экзамен по практическим навыкам на CDL в Нью-Джерси состоит из каких трёх частей, по порядку?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Письменный экзамен на знание, проверка зрения и вождение по дороге","Проверка пневматических тормозов, параллельная парковка и слияние на автомагистрали","Тест на сцепку, тест на движение задним ходом и обращение с HAZMAT"],"explanation":"Экзамен по практическим навыкам (дорожный) на CDL состоит из трёх частей, сдаваемых последовательно: предрейсовый осмотр, тест базовых навыков управления транспортным средством и тест вождения по дороге. Источник: NJ MVC, CDL Tests (cdltest.htm)."},"94":{"q":"Во время предрейсового осмотра в рамках экзамена по практическим навыкам в Нью-Джерси кандидат должен продемонстрировать способность сделать что?","options":["Определить и объяснить компоненты, которые следует осмотреть, и почему","Отремонтировать неисправную камеру пневматического тормоза менее чем за пять минут","Воспроизвести всё руководство CDL по памяти","Разобрать и собрать седельно-сцепное устройство"],"explanation":"В тесте предрейсового осмотра кандидат должен показать, что может определить каждый компонент, подлежащий осмотру, и объяснить, почему он проверяется, подтверждая, что транспортное средство безопасно для вождения. Источник: NJ MVC, CDL Tests (cdltest.htm)."},"95":{"q":"Для экзамена по практическим навыкам кандидат должен предоставить репрезентативное коммерческое транспортное средство, отвечающее какому условию?","options":["Действующий техосмотр, действующая регистрация и страховка, и отсутствие груза или опасных материалов","Транспортное средство, загруженное до максимальной полной массы","Транспортное средство не старше двух лет","Транспортное средство, принадлежащее только лицензированному автоперевозчику"],"explanation":"Кандидаты должны предоставить подходящий CMV, репрезентативный для запрашиваемого класса, с действующим техосмотром, действующей регистрацией и страховкой, надлежащим GVWR/табличками, и без груза или опасных материалов на борту. Источник: NJ MVC, CDL Tests (cdltest.htm)."},"96":{"q":"Как часто необходимо продлевать CDL Нью-Джерси?","options":["Каждые 4 года","Каждые 2 года","Каждые 5 лет","Каждые 8 лет"],"explanation":"Стандартный CDL Нью-Джерси выдаётся на четырёхлетний срок и должен продлеваться каждые 4 года (первый CDL может быть пропорционально привязан к сроку действия основного удостоверения). Источник: NJ MVC, Getting your Commercial Driver License (gettingcdl.htm)."},"97":{"q":"Какое утверждение о продлении CDL Нью-Джерси верно?","options":["Его необходимо продлевать лично в агентстве MVC, а не онлайн или по почте","Его можно полностью продлить онлайн, как базовое удостоверение Class D","Его можно продлить по почте, только если нет эндорсементов","Оно продлевается автоматически без каких-либо действий со стороны водителя"],"explanation":"В отличие от базового водительского удостоверения, CDL Нью-Джерси нельзя продлить онлайн или по почте; обладатель должен продлевать его лично в агентстве MVC, предъявив необходимые документы и текущий статус медицинской сертификации. Примечание: точные размеры сборов могут меняться, поэтому уточняйте актуальные суммы в MVC. Источник: NJ MVC CDL renewal guidance."}},"tr":{"0":{"q":"New Jersey karayollarında, yükü dahil bir aracın veya araç kombinasyonunun azami yüksekliği nedir?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","14 feet 6 inches"],"explanation":"New Jersey yasası (N.J.S.A. 39:3-84), herhangi bir aracın veya kombinasyonun, yük veya içerik dahil olmak üzere azami yüksekliğini tüm karayollarında 13 feet 6 inches olarak belirler. (Kaynak: N.J.S.A. 39:3-84; NJDOT Commercial Vehicle Size and Weight Guidebook.)"},"1":{"q":"Aşırı yük izni olmadan New Jersey karayollarında bir araca izin verilen azami toplam brüt ağırlık nedir?","options":["80,000 pounds","73,280 pounds","88,000 pounds","76,000 pounds"],"explanation":"New Jersey, azami toplam brüt araç ağırlığını federal sınırla uyumlu olarak 80,000 pounds ile sınırlandırır (N.J.S.A. 39:3-84). Bölünemeyen bir yükte bunun üzerindeki her şey aşırı yük izni gerektirir. (Kaynak: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"2":{"q":"Belirlenmiş 102-inch ağına veya National Network'e dahil OLMAYAN çoğu New Jersey yolunda azami yasal araç genişliği nedir?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","90 inches (7 feet 6 inches)"],"explanation":"Belirlenmiş National Network ve New Jersey 102-inch kamyon ağı 102 inches (8'6\") genişliğe izin verirken, diğer kamu yolları 96 inches (8 feet) ile sınırlıdır. (Kaynak: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)"},"3":{"q":"New Jersey'nin belirlenmiş National Network ve 102-inch kamyon güzergah ağında kamyonlar için yük dahil izin verilen azami genişlik nedir?","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","120 inches (10 feet)","114 inches (9 feet 6 inches)"],"explanation":"Belirlenmiş National Network ve New Jersey 102-inch kamyon güzergah ağında, azami dış genişlik N.J.S.A. 39:3-84 uyarınca 102 inches (8 feet 6 inches) olarak belirlenmiştir. (Kaynak: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"4":{"q":"New Jersey yasalarına göre, tek bir aksta taşınabilecek azami brüt ağırlık nedir?","options":["22,400 pounds","20,000 pounds","34,000 pounds","24,000 pounds"],"explanation":"New Jersey, tek bir aksta 22,400 pounds'a kadar izin verir; bu, temel federal 20,000-pound tek aks değerinden daha yüksektir (N.J.S.A. 39:3-84). (Kaynak: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)"},"5":{"q":"New Jersey karayollarında tandem bir aks grubunda izin verilen azami brüt ağırlık nedir?","options":["34,000 pounds","22,400 pounds","40,000 pounds","36,000 pounds"],"explanation":"New Jersey, bir tandem aks grubunu federal standartla aynı şekilde 34,000 pounds ile sınırlandırır (N.J.S.A. 39:3-84). (Kaynak: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"6":{"q":"Bölünemeyen bir yük taşımadığında, New Jersey karayollarında tek (düz) bir kamyonun azami toplam uzunluğu nedir?","options":["40 feet","35 feet","45 feet","53 feet"],"explanation":"N.J.S.A. 39:3-84, tek bir aracın toplam uzunluğunu 40 feet ile sınırlandırır (yalnızca direk, kazık veya bölünemeyen diğer maddeler taşırken 50 feet'e kadar uzatılır). (Kaynak: N.J.S.A. 39:3-84.)"},"7":{"q":"New Jersey yasalarına göre, genel karayollarında bir çekici-yarı römork KOMBİNASYONUNUN (güç ünitesi artı yükü) azami toplam uzunluğu nedir?","options":["62 feet","53 feet","65 feet","75 feet"],"explanation":"N.J.S.A. 39:3-84, yük dahil bir araç kombinasyonunun toplam uzunluğunu 62 feet olarak belirler. National Network üzerinde bir çekici-yarı römorkun toplam uzunluk sınırı bulunmadığını, yarı römorkun kendisinin ise 53 feet ile sınırlı olduğunu unutmayın. (Kaynak: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"8":{"q":"New Jersey'nin National Network ve belirlenmiş 102-inch güzergahlarında, bir çekici-yarı römork kombinasyonunda çalışan bir YARI RÖMORKUN azami uzunluğu nedir?","options":["53 feet","48 feet","57 feet","45 feet"],"explanation":"Bir yarı römork, NJDOT kuralları ve N.J.S.A. 39:3-84 uyarınca National Network ve NJ 102-inch ağında 53 feet'e kadar olabilir (diğer karayollarında 48 feet). (Kaynak: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)"},"9":{"q":"New Jersey belirlenmiş ağında çalışan 48 ila 53 feet'lik bir yarı römork için, kingpin'den arka aks merkezine kadar izin verilen azami mesafe nedir?","options":["41 feet","37 feet","46 feet","53 feet"],"explanation":"48 feet'ten büyük ve 53 feet'e kadar olan römorklar için, kingpin'den arka aks merkezine kadar olan mesafe Interstate/belirlenmiş ağda 41 feet'i aşamaz. (Kaynak: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)"},"10":{"q":"New Jersey'nin belirlenmiş ağında çalışan ikiz römorklu (double) bir kombinasyonda, HER bir çekilen ünitenin azami uzunluğu nedir?","options":["28 feet","33 feet","40 feet","53 feet"],"explanation":"New Jersey ikiz römorklu kombinasyonundaki her römork, N.J.S.A. 39:3-84 kapsamında tanınan federal STAA double standardıyla uyumlu olarak 28 feet ile sınırlıdır. (Kaynak: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)"},"11":{"q":"New Jersey'nin lastik genişliğinin her inch'i başına izin verdiği azami brüt yük nedir?","options":["800 pounds","650 pounds","500 pounds","1,000 pounds"],"explanation":"New Jersey, yükü lastik genişliğinin her inch'i başına 800 pounds ile sınırlandırır (N.J.S.A. 39:3-84). (Kaynak: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)"},"12":{"q":"New Jersey'de kullanılan federal köprü formülü, W = 500[LN/(N-1) + 12N + 36], hangi değeri belirler?","options":["Aralarındaki mesafeye ve sayılarına göre ardışık bir aks grubunda izin verilen azami brüt ağırlık","Dingil mesafesine göre bir aracın azami yüksekliği","Lastik sayısına göre azami genişlik","Yüklü bir kombinasyon için gereken asgari durma mesafesi"],"explanation":"New Jersey'de uygulanan Federal Köprü Formülü, iki veya daha fazla ardışık aks grubundaki izin verilen azami brüt ağırlığı (W) hesaplar; burada L dış akslar arasındaki mesafe ve N aks sayısıdır. (Kaynak: NJDOT tarafından uygulanan 23 CFR 658 / Federal Bridge Formula; NJDOT Size and Weight Guidebook.)"},"13":{"q":"New Jersey'de kullanılan federal köprü formülünde 'L' değişkeni neyi temsil eder?","options":["Aks grubunun dış aksları arasındaki feet cinsinden mesafe","Römorkun toplam uzunluğu","Pounds cinsinden yasal yük sınırı","Kaldırma aksı ağırlık toleransı"],"explanation":"W = 500[LN/(N-1) + 12N + 36] formülünde, 'L' ele alınan grubun en dıştaki aksları arasındaki feet cinsinden mesafedir ve 'N' o gruptaki aks sayısıdır. (Kaynak: NJDOT tarafından uygulanan Federal Bridge Formula, 23 CFR 658.)"},"14":{"q":"Yasal boyut veya ağırlık sınırlarını aşan bir yük için New Jersey oversize/overweight (OS/OW) izni ne zaman verilir?","options":["Yalnızca yük bölünemez olduğunda (yasal sınırları karşılamak için parçalanamaz veya bölünemez olduğunda)","Bir ücret ödendiği sürece bölünebilir olsun olmasın herhangi bir yük için","Yalnızca tarımsal ürün yükleri için","Yalnızca hafta sonları ve tatillerde"],"explanation":"NJDOT, OS/OW izinlerini yalnızca bölünemeyen yükler için verir; bunlar ağırlık ve boyut sınırlarını karşılamak için parçalanamayan, sökülemeyen veya bölünemeyen yükler olarak tanımlanır. (Kaynak: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)"},"15":{"q":"New Jersey'de bir taşıyıcı oversize/overweight taşıma izni için nasıl başvurur?","options":["NJDOT'un OS/OW izin web sitesi (nj.gotpermits.com) aracılığıyla 7/24 çevrimiçi","Yalnızca mesai saatleri içinde bir ilçe katipliği ofisinde şahsen","State Police'e noter onaylı bir form göndererek","Bir CDL verilmesiyle otomatik olarak"],"explanation":"Taşıyıcılar, NJDOT OS/OW izinleri için NJDOT OS/OW izin web sitesinde (nj.gotpermits.com) haftanın 7 günü, günde 24 saat doğrudan veya kayıtlı bir izin hizmeti aracılığıyla çevrimiçi başvurabilir. (Kaynak: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)"},"16":{"q":"İzin verilmiş bir oversize taşıma için, New Jersey hangi yük genişliğinde (yük dahil) en az bir refakat aracı gerektirir?","options":["Genişlik 14 feet'i aştığında","Genişlik 10 feet'i aştığında","Genişlik 8 feet 6 inches'i aştığında","Genişlik 16 feet'i aştığında"],"explanation":"NJDOT izin kurallarına göre, yük dahil genişlik 14 feet'i aştığında bir refakat aracı gereklidir; genişlik 16 feet'i aştığında iki refakat aracı gereklidir. (Kaynak: NJDOT OS/OW Permit Reference Guide; oversize.io NJ regulations.)"},"17":{"q":"Bir taşıyıcı, bir New Jersey eyalet karayolunda 110,000 pounds brüt ve 12 feet genişlikte olacak bir çekici-yarı römork üzerinde tek parça, bölünemez bir makine taşımak istiyor. Taşıyıcı ne yapmalıdır?","options":["Hareket öncesinde bir NJDOT oversize/overweight izni almalıdır, çünkü hem ağırlık hem de genişlik yasal sınırları aşmaktadır","Hiçbir şey, çünkü bölünemez yükler tüm sınırlardan otomatik olarak muaftır","Muaf olmak için yalnızca aracı tarımsal olarak kaydettirmek","Herhangi bir izin olmadan yalnızca geceleri seyahat etmek"],"explanation":"Yük, 80,000-pound brüt sınırını ve 102-inch (8'6\") genişlik sınırını aştığından, bu bölünemez yük için seyahat öncesinde nj.gotpermits.com üzerinden alınacak bir NJDOT OS/OW izni gereklidir. 12 feet'lik bir genişlik, 14 feet'lik refakat eşiğinin altındadır. (Kaynak: N.J.S.A. 39:3-84; NJDOT OS/OW Permit Reference Guide.)"},"18":{"q":"New Jersey'de, çekilen ünitenin GVWR'si 10,000 pounds'tan fazla olan ve 26,001 pounds veya daha fazla brüt kombinasyon ağırlık derecesine (GCWR) sahip bir kombinasyon aracı kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"NJ CDL Manual, Class A'yı, çekilen ünite(ler)in GVWR'sinin 10,000 pounds'tan fazla olması koşuluyla, GCWR'si 26,001 pounds veya daha fazla olan herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: NJ MVC Commercial Driver License Manual (Sınıf tanımları)."},"19":{"q":"New Jersey kurallarına göre, GVWR'si 26,001 pounds veya daha fazla olan tek bir araç ya da 10,000 pounds GVWR'yi geçmeyen bir ünite çeken böyle bir araç hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Class E"],"explanation":"NJ CDL Manual, Class B'yi, GVWR'si 26,001 pounds veya daha fazla olan herhangi bir tek araç ya da GVWR'si 10,000 pounds veya daha az olan bir ünite çeken o araç olarak tanımlar. Kaynak: NJ MVC Commercial Driver License Manual."},"20":{"q":"New Jersey'de, 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış bir araç ya da plakalı tehlikeli madde taşıyan daha küçük bir araç en az hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Class M"],"explanation":"NJ CDL Manual, Class C'yi, Class A veya B kriterlerini karşılamayan ancak operatör dahil 16 veya daha fazla yolcu taşımak için tasarlanmış ya da plakalama gerektiren tehlikeli madde taşımak için kullanılan bir araç olarak tanımlar. Kaynak: NJ MVC Commercial Driver License Manual."},"21":{"q":"Bir New Jersey aracı, sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmıştır ancak 26,001 pounds'un altında ağırlığa sahiptir. Gereken asgari CDL sınıfı nedir?","options":["CDL gerekmez","Class A","Class B","Class C"],"explanation":"Class A veya B için ağırlık eşiklerinin altında olsa bile, operatör dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir araç New Jersey'de Class C'ye girer. Kaynak: NJ MVC Commercial Driver License Manual (Class C tanımı)."},"22":{"q":"Bir New Jersey CDL sahibinin, kalıcı olarak monte edilmiş bir tankta sıvı veya gazları dökme olarak taşıyan bir aracı kullanmak için hangi yetki belgesine (endorsement) ihtiyacı vardır?","options":["N (Tank Vehicle)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"explanation":"Sıvı veya gazları dökme olarak taşıyan araçları kullanmak için New Jersey'de N (Tank Vehicle) yetki belgesi gereklidir. Kaynak: NJ MVC Endorsements sayfası."},"23":{"q":"New Jersey'de, iki veya üç römork çekmek için hangi yetki belgesi gereklidir ve sürücünün hangi CDL sınıfına sahip olması gerekir?","options":["T yetki belgesi, Class A CDL ile","N yetki belgesi, Class B CDL ile","T yetki belgesi, Class C CDL ile","P yetki belgesi, Class A CDL ile"],"explanation":"İki veya üç römork çekmek için T (Doubles/Triples) yetki belgesi gereklidir ve buna sahip olmak için Class A CDL gereklidir. Kaynak: NJ MVC Endorsements sayfası."},"24":{"q":"New Jersey bir HazMat (H) yetki belgesi vermeden önce, başvuru sahibinin hangi kurum tarafından yürütülen bir geçmiş kontrolünü geçmesi gerekir?","options":["Transportation Security Administration (TSA)","New Jersey MVC dolandırıcılık birimi","Federal Motor Carrier Safety Administration (FMCSA)","Yalnızca New Jersey State Police"],"explanation":"New Jersey, HazMat (H) yetki belgesi başvuru sahiplerinin yetki belgesi verilmeden önce parmak izlerinin alınmasını ve bir Transportation Security Administration (TSA) tehdit değerlendirmesini geçmelerini gerektirir. Kaynak: NJ MVC Hazardous Material Endorsements (HME) sayfası; TSA HME programı."},"25":{"q":"New Jersey'de bir okul otobüsü kullanmak için hangi CDL yetki belgeleri kombinasyonu gereklidir?","options":["Hem P (Passenger) hem de S (School Bus)","Yalnızca S (School Bus)","Yalnızca P (Passenger)","S ve H"],"explanation":"New Jersey, okul otobüsü sürücülerinin hem P (Passenger) hem de S (School Bus) yetki belgelerine sahip olmasını, ayrıca bir bilgi ve yol testini ve bir geçmiş kontrolünü geçmesini gerektirir. Kaynak: NJ MVC Endorsements sayfası."},"26":{"q":"Eyalet içi (yalnızca New Jersey içinde) kullanımla sınırlı bir New Jersey CDL almak için asgari yaş nedir?","options":["18 years old","21 years old","19 years old","17 years old"],"explanation":"Bir sürücü 18 yaşında New Jersey CDL alabilir, ancak kullanım 21 yaşına kadar eyalet içi ticaretle (New Jersey içinde) sınırlıdır. Kaynak: NJ MVC Getting Your CDL sayfası."},"27":{"q":"New Jersey CDL ile eyaletler arası ticarette bir ticari motorlu araç kullanmak için gereken asgari yaş nedir?","options":["21 years old","18 years old","23 years old","19 years old"],"explanation":"New Jersey CDL'ye sahip 21 yaşından küçük sürücüler yalnızca eyalet içinde çalışabilir; eyaletler arası ticaret (ve hazmat) sürücünün en az 21 yaşında olmasını gerektirir. Kaynak: NJ MVC Getting Your CDL sayfası."},"28":{"q":"New Jersey'de uygulanan federal kurallara göre, bir Commercial Learner Permit (CLP) sahibi, CDL beceri testine girmeden önce CLP verildikten sonra ne kadar beklemek zorundadır?","options":["En az 14 days","En az 30 days","En az 7 days","En az 60 days"],"explanation":"New Jersey, bir CLP sahibinin beceri testine girmeden önce en az 14 days beklemesi gerektiği federal şartı uygular. Kaynak: NJ MVC Getting Your CDL / CLP sayfaları."},"29":{"q":"Verildikten sonra, bir New Jersey Commercial Learner Permit (CLP) ne kadar süre geçerlidir?","options":["180 days","1 year","90 days","60 days"],"explanation":"Bir New Jersey CLP, verildiğinde 180 days geçerlidir. Kaynak: NJ MVC Commercial Learner Permits (CLP) sayfası."},"30":{"q":"Bir New Jersey Commercial Learner Permit ile ticari bir motorlu araç kullanırken, sürücünün ayrıca yanında ne bulundurması gerekir?","options":["Geçerli bir New Jersey sürücü belgesi","Bir pasaport","İkinci bir CLP","Ek hiçbir şey"],"explanation":"Bir New Jersey CLP, sahibi bir CMV kullanırken geçerli bir New Jersey sürücü belgesi ile birlikte bulundurulmalıdır. Kaynak: NJ MVC Commercial Learner Permits (CLP) sayfası."},"31":{"q":"New Jersey, CDL başvuru sahiplerinin kimlik doğrulama standardını kaç puanlık kimlik göstererek karşılamasını gerektirir?","options":["6 Points of ID","4 Points of ID","8 Points of ID","2 Points of ID"],"explanation":"New Jersey, kimliği, Social Security numarasını, adres kanıtını ve ABD'de yasal varlık kanıtını belirleyen belgeleri gerektiren 6 Points of ID sistemini kullanır. Kaynak: NJ MVC Getting Your CDL / 6 Points of ID."},"32":{"q":"Aşağıdaki belgelerden hangisi özellikle New Jersey'nin CDL kimlik doğrulamasının bir parçası olarak gereklidir?","options":["Social Security kartı ve ABD'de yasal varlık kanıtı","Yalnızca herhangi bir ülkeden bir doğum belgesi","Bir sendika üyelik kartı","Yalnızca bir işveren mektubu"],"explanation":"New Jersey'nin bir CDL için 6 Points of ID'si, Social Security kartını, adres kanıtını ve Amerika Birleşik Devletleri'nde yasal varlık kanıtını içerir. Kaynak: NJ MVC Getting Your CDL sayfası."},"33":{"q":"İlk kez bir New Jersey CDL beceri testinden önce gereken Entry-Level Driver Training (ELDT), hangisi olan bir sağlayıcıdan alınmalıdır:","options":["FMCSA Training Provider Registry'de listelenen","Yalnızca NJ MVC tarafından onaylanan","Herhangi bir ticari sürücü okulu","TSA tarafından sertifikalandırılan"],"explanation":"7 Şubat 2022'den bu yana, beceri testine girmeden önce (veya HazMat için bilgi testinden önce) ELDT, FMCSA Training Provider Registry'de listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır. Kaynak: NJ MVC Getting Your CDL; FMCSA TPR."},"34":{"q":"New Jersey ELDT'nin hangi yetki belgesi için beceri testinden önce değil, bilgi (yazılı) testinden ÖNCE tamamlanması gerekir?","options":["H (Hazardous Materials)","P (Passenger)","S (School Bus)","N (Tank Vehicle)"],"explanation":"HazMat (H) yetki belgesi için, ELDT bilgi testinden önce tamamlanmalıdır; ilk kez Class A/B ve P ve S yetki belgeleri için, ELDT beceri testinden önce gereklidir. Kaynak: NJ MVC CLP/CDL sayfaları; FMCSA ELDT kuralı."},"35":{"q":"Yalnızca New Jersey içinde çalışan ve bir eyalet tıbbi muayene belgesi şartını karşılaması gereken bir New Jersey CDL sürücüsü hangi kategori altında kendi beyanını yapmalıdır?","options":["Non-Excepted Intrastate","Non-Excepted Interstate","Excepted Interstate","Excepted Intrastate"],"explanation":"Non-Excepted Intrastate (NA), yalnızca New Jersey içinde çalışan ve tıbbi muayene belgesi şartlarını karşılaması gereken sürücüler için geçerlidir. Kaynak: NJ MVC CDL Holder Self-Certification; FMCSA tıbbi sertifikasyon kategorileri."},"36":{"q":"Eyalet sınırlarını geçerek araç kullanan ve geçerli bir DOT tıbbi muayene belgesi bulundurması gereken bir New Jersey CDL sahibi için hangi tıbbi kendi beyan kategorisi geçerlidir?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Non-Excepted Interstate (NI) sürücüleri eyaletler arası ticarette çalışır ve federal DOT tıbbi kartı şartlarını karşılamalı, dosyada bir National Registry muayenecisinden bir belge bulundurmalıdır. Kaynak: NJ MVC CDL Self-Certification; FMCSA kategorileri."},"37":{"q":"Kendisini Non-Excepted Interstate olarak beyan eden bir New Jersey sürücüsü, hangisi olan bir sağlayıcıdan tıbbi muayene belgesi almalıdır:","options":["FMCSA National Registry of Certified Medical Examiners'da listelenen","Herhangi bir lisanslı New Jersey doktoru","Yerel ilçe katibi tarafından onaylanan","TSA tarafından sertifikalandırılan"],"explanation":"Muaf olmayan sürücüler, FMCSA National Registry of Certified Medical Examiners'da listelenen bir tıbbi muayene tarafından muayene edilmeli ve belgeyi dosyada bulundurmalıdır. Kaynak: NJ MVC CDL Self-Certification; FMCSA National Registry."},"38":{"q":"New Jersey'de, bir ticari motorlu araç (CMV) kullanan bir kişi için azami yasal kan alkol konsantrasyonu (BAC) nedir?","options":["0.02","0.04","0.08","0.10"],"explanation":"New Jersey federal CMV standardını izler: bir CMV'yi 0.04 yüzde veya daha yüksek bir BAC ile kullanmak yasa dışıdır. Bu, kişisel bir araç için olan 0.08 sınırından daha katıdır. Kaynak: NJ MVC CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51."},"39":{"q":"New Jersey'nin CDL sahipleri için zımni rıza kurallarına göre, bir sürücü bir CMV kullanırken alkol konsantrasyonu testine girmeyi reddederse ne olur?","options":["Yalnızca para cezası uygulanır, ehliyetten men edilmez","Bir DUI mahkumiyetinin yapacağı gibi sürücüyü ehliyetten men eden bir major offense olarak ele alınır","Sürücü ilk ret için bir uyarı alır","CDL yalnızca 30 days askıya alınır"],"explanation":"Bir CDL'ye sahip olarak ve New Jersey'de araç kullanarak, bir sürücü alkol testine zımni rıza gösterir. Testi reddetmek bir major offense olarak ele alınır ve bir DUI mahkumiyeti ile aynı ehliyetten men cezasını taşır (ilk suç için 1 year). Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"40":{"q":"New Jersey'de, plakasız bir CMV kullanırken ilk DUI mahkumiyeti gibi ilk major offense için asgari CDL ehliyetten men süresi nedir?","options":["60 days","120 days","1 year","3 years"],"explanation":"İlk major offense (DUI, 0.04 veya daha yüksek bir BAC ya da test reddi dahil) en az 1 year CDL ehliyetten men ile sonuçlanır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"41":{"q":"Bir New Jersey CDL sürücüsü, tehlikeli maddeler için plakalanmış bir araç kullanırken ilk major offense'i (DUI gibi) işlerse, ehliyetten men süresi nedir?","options":["1 year","18 months","3 years","5 years"],"explanation":"Plakalanmış tehlikeli maddeler taşırken işlenen bir ilk major offense, ehliyetten men süresini 1 year'dan 3 years'a yükseltir. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"42":{"q":"New Jersey'de ikinci bir major offense (örneğin, herhangi bir zamanda ikinci bir DUI mahkumiyeti) için CDL ehliyetten men süresi nedir?","options":["3 years","5 years","10 years","Ömür boyu"],"explanation":"İkinci bir major offense, ömür boyu CDL ehliyetten men ile sonuçlanır. New Jersey, iki ayrı major offense'in sürücünün CDL'yi ömür boyu kaybetmesi anlamına geldiği federal kuralı izler. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"43":{"q":"New Jersey'de, 3 yıllık bir dönem içinde (ayrı olaylarda) kaç ciddi trafik ihlali 60 günlük bir CDL ehliyetten men tetikler?","options":["1","2","3","4"],"explanation":"3 yıl içinde (ayrı bir olayda) ikinci bir ciddi trafik ihlali, 60 günlük bir ehliyetten men ile sonuçlanır. İlk ciddi ihlal tek başına ehliyetten mene neden olmaz. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2."},"44":{"q":"New Jersey'de 3 yıllık bir dönem içinde (ayrı olaylarda) üçüncü bir ciddi trafik ihlali için CDL ehliyetten men süresi nedir?","options":["60 days","90 days","120 days","1 year"],"explanation":"3 yıl içinde üçüncü bir ciddi trafik ihlali, 120 günlük bir ehliyetten men ile sonuçlanır. 3 yıl içindeki ikincisi 60 gündür. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2."},"45":{"q":"Aşağıdakilerden hangisi bir New Jersey CDL sahibi için ciddi trafik ihlali olarak sınıflandırılır?","options":["Bir CMV'yi park yasağı bölgesine park etmek","Belirlenen hız sınırının 15 mph veya daha fazla üzerinde hız yapmak","Yanmış bir gabari lambası","Bir seyir defterini düzenli tutmamak"],"explanation":"Belirlenen sınırın 15 mph veya daha fazla üzerinde olarak tanımlanan aşırı hız, ciddi bir trafik ihlalidir. Diğerleri arasında dikkatsiz sürüş, yanlış şerit değişiklikleri, çok yakından takip etme ve araç kullanırken mesaj yazma yer alır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2."},"46":{"q":"New Jersey'de, bir CMV kullanırken demiryolu-karayolu hemzemin geçit ihlalinin ilk mahkumiyeti için asgari CDL ehliyetten men süresi nedir?","options":["30 days","60 days","120 days","1 year"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, asgari 60 günlük bir ehliyetten men ile sonuçlanır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3."},"47":{"q":"New Jersey'de 3 yıllık bir dönem içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali için asgari CDL ehliyetten men süresi nedir?","options":["60 days","90 days","120 days","1 year"],"explanation":"3 yıl içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali, asgari 120 günlük bir ehliyetten men ile sonuçlanır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3."},"48":{"q":"New Jersey'de 3 yıllık bir dönem içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali için asgari CDL ehliyetten men süresi nedir?","options":["120 days","180 days","1 year","3 years"],"explanation":"3 yıl içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali, asgari 1 year'lık bir ehliyetten men ile sonuçlanır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3."},"49":{"q":"New Jersey'de, tehlikeli madde veya yolcu taşımazken bir CDL sürücüsünün bir out-of-service (OOS) emrini ihlal etmesinin ilk mahkumiyeti için asgari ehliyetten men süresi nedir?","options":["90 days","120 days","180 days","1 year"],"explanation":"Bir out-of-service emrini ihlal etmenin ilk mahkumiyeti, en az 180 days (1 year'a kadar) ehliyetten men taşır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4."},"50":{"q":"New Jersey'de 10 yıllık bir dönem içinde ikinci bir out-of-service emri ihlali (hazmat olmayan, yolcu olmayan) için ehliyetten men aralığı nedir?","options":["180 days ile 1 year arası","1 ile 2 years arası","2 ile 5 years arası","3 ile 5 years arası"],"explanation":"10 yıl içinde ikinci bir out-of-service emri ihlali, 2 ile 5 years arası bir ehliyetten men ile sonuçlanır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4."},"51":{"q":"New Jersey'de 10 yıllık bir dönem içinde üçüncü veya sonraki bir out-of-service emri ihlali (hazmat olmayan, yolcu olmayan) için ehliyetten men aralığı nedir?","options":["180 days ile 1 year arası","2 ile 5 years arası","3 ile 5 years arası","Ömür boyu"],"explanation":"10 yıl içinde üçüncü veya sonraki bir out-of-service emri ihlali, 3 ile 5 years arası bir ehliyetten men ile sonuçlanır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4."},"52":{"q":"New Jersey'de, ehliyetten mene ek olarak, bir CDL sürücüsü bir out-of-service emrini ihlal etmenin ilk mahkumiyeti için hangi hukuki para cezasıyla karşı karşıya kalır?","options":["En az $1,000","En az $2,500","En az $5,000","En az $10,000"],"explanation":"Ehliyetten menin ötesinde, bir out-of-service emrini ihlal eden bir sürücü, ilk suç için en az $2,500 ve sonraki suç için en az $5,000 hukuki para cezasına tabidir. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.53."},"53":{"q":"Plakalanmış tehlikeli maddeler taşırken bir out-of-service emrini ihlal eden bir New Jersey CDL sürücüsü, ilk suç için hangi asgari ehliyetten men ile karşı karşıya kalır?","options":["120 days","180 days","1 year","2 years"],"explanation":"Plaka gerektiren tehlikeli maddeler taşırken (ya da 16+ yolcu taşımak için tasarlanmış bir araç kullanırken) ilk out-of-service emri ihlali, en az 180 days, 2 years'a kadar bir ehliyetten men taşır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4."},"54":{"q":"New Jersey ve federal kurallara göre, bir CMV kullanırken mesaj yazmak bir CDL sahibi için hangi tür ihlal olarak sınıflandırılır?","options":["Ceza puanı verilmeyen bir kabahat","Bir ciddi trafik ihlali","Bir major offense","Bir out-of-service emri ihlali"],"explanation":"Bir CMV kullanırken mesaj yazmak ve el tipi mobil telefon kullanmak ciddi trafik ihlalleridir. 3 yıl içinde iki böyle ihlal 60 günlük bir ehliyetten mene yol açar; üç tanesi 120 güne yol açar. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2 ve 392.80/392.82."},"55":{"q":"Bir CMV kullanırken el tipi mobil telefon kullanmak veya mesaj yazmak için New Jersey CDL sürücülerine uygulanan azami sürücü para cezası nedir?","options":["Up to $500","Up to $1,000","Up to $2,750","Up to $5,000"],"explanation":"Bir CMV kullanırken el tipi telefon kullanan veya mesaj yazan bir CDL sürücüsü up to $2,750 para cezasına çarptırılabilir ve bu suç bir ciddi trafik ihlali olarak sayılır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 392.82."},"56":{"q":"Bir kontrollü maddenin üretilmesi, dağıtılması veya temin edilmesini içeren bir suçun işlenmesinde bir CMV kullanmak, hangi New Jersey CDL ehliyetten menini taşır?","options":["1 year","3 years","10 years","Geri verme olasılığı olmadan ömür boyu"],"explanation":"Kontrollü maddeleri içeren bir suç işlemek için bir CMV kullanmak, geri verme olasılığı olmadan ömür boyu ehliyetten men ile sonuçlanan bir major offense'tir. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"57":{"q":"Bir New Jersey CDL sahibi, ilk bir DUI mahkumiyeti, ardından daha sonra bir CMV'de kaza yerinden ayrılma için ayrı bir mahkumiyet biriktiriyor. Bu ikinci major offense'in sonucu nedir?","options":["120 günlük bir ehliyetten men","1 year'lık bir ehliyetten men","3 years'lık bir ehliyetten men","Ömür boyu bir ehliyetten men"],"explanation":"Bir CMV'de DUI ve kaza yerinden ayrılma her ikisi de major offense'tir. Herhangi iki major offense (ayrı olaylarda), farklı türde major offense olsalar bile, ömür boyu CDL ehliyetten men ile sonuçlanır. Kaynak: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1."},"58":{"q":"New Jersey'nin Move Over (Şerit Değiştir) yasası uyarınca, bir ticari araç sürücüsü çok şeritli bir karayolunda yanıp sönen ışıklar yakan, durmuş bir acil durum aracına, çekiciye veya yol bakım aracına yaklaşırken ne yapmalıdır?","options":["Güvenli bir şekilde yapılabiliyorsa, durmuş araca bitişik olmayan bir şeride geçmek","Durmuş araç uzaklaşana kadar tamamen durmak","Belirlenen hızda devam etmek ancak geçerken korna çalmak","Banket üzerine çekmek ve bir memurun trafiği geçirmesini beklemek"],"explanation":"New Jersey'nin Move Over yasası (N.J.S.A. 39:4-92.2), çok şeritli bir yolda yaklaşan bir sürücünün, güvenli olduğunda durmuş araca bitişik olmayan bir şeride geçmesini gerektirir. Kaynak: N.J.S.A. 39:4-92.2; NJ MVC."},"59":{"q":"New Jersey Move Over yasası uyarınca, bir sürücü yanıp sönen ışıklar yakan, durmuş bir acil durum veya hizmet aracından uzağa güvenli bir şekilde şerit değiştiremiyorsa ne yapması gerekir?","options":["Hızı belirlenen sınırın altında makul ve uygun bir hıza düşürmek ve dikkatle ilerlemek","Trafiği engellememek için belirlenen hız sınırını korumak","Işıklar kapanana kadar mevcut şeritte tamamen durmak","Koşullar ne olursa olsun orta refüje geçmek"],"explanation":"N.J.S.A. 39:4-92.2, şerit değişikliğinin güvenli bir şekilde yapılamadığı durumlarda, sürücünün hızını belirlenen sınırın altında makul ve uygun bir hıza düşürmesi ve durmaya hazır olması gerektiğini öngörür. Kaynak: N.J.S.A. 39:4-92.2; NJ MVC."},"60":{"q":"New Jersey'de bir otobüs, ilerlemeden önce bir demiryolu-karayolu hemzemin geçidinin en yakın rayından ne kadar uzakta durmalıdır?","options":["15 ile 50 feet arasında","5 ile 15 feet arasında","50 ile 100 feet arasında","10 ile 25 feet arasında"],"explanation":"New Jersey CDL Kılavuzu (Bölüm 4, Yolcu Taşıma), bir otobüsün demiryolu geçidinden önce 15 ile 50 feet arasında durmasını, ardından trenler için bakıp dinlemesini gerektirir. Kaynak: NJ MVC Commercial Driver License Manual, Sec. 4.3.5."},"61":{"q":"New Jersey'de plaketli (tehlikeli madde levhalı) bir tehlikeli madde aracı, demiryolu raylarını geçmeden önce en yakın raydan ne kadar mesafe içinde durmalıdır?","options":["15 feet'ten yakın olmadan ve 50 feet'ten uzak olmadan","25 feet'ten yakın olmadan ve 75 feet'ten uzak olmadan","10 feet'ten yakın olmadan ve 40 feet'ten uzak olmadan","5 feet'ten yakın olmadan ve 30 feet'ten uzak olmadan"],"explanation":"New Jersey CDL Kılavuzu (Bölüm 9, Tehlikeli Maddeler), plaketli bir aracın, herhangi bir miktarda klor taşıyan bir aracın veya tehlikeli madde için kullanılan kargo tankları olan bir aracın en yakın raydan 15 ile 50 feet önce durması gerektiğini belirtir. Kaynak: NJ MVC CDL Manual, Sec. 9.6.12."},"62":{"q":"İki şeritli, bölünmemiş bir New Jersey karayolunda, bir okul otobüsü çocukları almak için kırmızı ışıkları yanıp sönerek durmuştur. Otobüse yaklaşan veya onu geçen bir araç en az ne kadar uzakta durmalıdır?","options":["25 feet","10 feet","20 feet","50 feet"],"explanation":"N.J.S.A. 39:4-128.1, bölünmemiş bir yolda yanıp sönen kırmızı ışıkları olan bir okul otobüsüne yaklaşan veya onu geçen bir sürücünün en az 25 feet uzakta durmasını ve ışıklar yanıp sönmeyi durdurana kadar durmuş halde kalmasını gerektirir. Kaynak: N.J.S.A. 39:4-128.1."},"63":{"q":"New Jersey yasasına göre, çift veya bölünmüş bir karayolunun AYRI bir yolunda giden ve diğer yolda yanıp sönen kırmızı ışıklarla durmuş bir okul otobüsüne yaklaşan bir sürücü ne yapmalıdır?","options":["Hızı 10 mph'den fazla olmayacak şekilde düşürmek ve otobüsü dikkatle geçmek","Otobüsten en az 25 feet uzakta durmak ve ışıklar yanıp sönmeyi durdurana kadar beklemek","Tamamen durmak ve otobüs şoförünün trafiği geçirmesini beklemek","Hiçbir işlem gerekmediği için belirlenen hızda devam etmek"],"explanation":"N.J.S.A. 39:4-128.1, bölünmüş karayolu istisnası sağlar: çift veya bölünmüş bir karayolunun başka bir yolundaki bir sürücünün durması gerekmez ancak otobüsü ve çocukları geçene kadar hızını 10 mph'den fazla olmayacak şekilde düşürmelidir. Kaynak: N.J.S.A. 39:4-128.1."},"64":{"q":"Bir New Jersey CMV aracı tek yönlü veya bölünmüş bir karayolunda durduğunda, sürücü üç uyarı cihazını (üçgeni) yaklaşan trafiğe doğru hangi mesafelere yerleştirmelidir?","options":["10 feet, 100 feet ve 200 feet","10 feet, 50 feet ve 100 feet","25 feet, 100 feet ve 150 feet","10 feet, 200 feet ve 300 feet"],"explanation":"New Jersey CDL Kılavuzu, tek yönlü veya bölünmüş bir karayolunda uyarı cihazlarının yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e yerleştirilmesini yönlendirir. Kaynak: NJ MVC CDL Manual, Sec. 2 (Güvenli Sürüş)."},"65":{"q":"Bir CMV aracını bir New Jersey yolunun banketinde durdurduktan sonra, sürücü acil durum uyarı cihazlarını kaç dakika içinde yerleştirmelidir?","options":["10 dakika","5 dakika","15 dakika","30 dakika"],"explanation":"New Jersey CDL Kılavuzu, bir yolda veya bankette durmanız gerekirse acil durum uyarı cihazlarını 10 dakika içinde yerleştirmenizi gerektirir. Kaynak: NJ MVC CDL Manual, Sec. 2 (Güvenli Sürüş)."},"66":{"q":"New Jersey'de her iki yöndeki trafiği taşıyan iki şeritli bir yolda, durmuş bir CMV'nin uyarı üçgenleri nereye yerleştirilmelidir?","options":["Aracın 10 feet yakınına ve arkasına ve önüne 100 feet'e","Yalnızca aracın arkasına 100 feet ve 200 feet'e","Aracın 25 feet yakınına ve arkasına 200 feet'e","Yalnızca aracın arkasına 10 feet, 100 feet ve 200 feet'e"],"explanation":"New Jersey CDL Kılavuzu, her iki yöndeki trafiği taşıyan iki şeritli bir yolda, ön veya arka köşelerin 10 feet yakınına bir üçgen ve aracın arkasına ve önüne 100 feet'e diğerlerini yerleştirmeyi yönlendirir. Kaynak: NJ MVC CDL Manual, Sec. 2 (Güvenli Sürüş)."},"67":{"q":"Kayıtlı brüt ağırlığı 10,000 pound'un üzerindeki ticari araçların, Garden State Parkway'in hangi kavşağın kuzeyinde kullanılması yasaktır?","options":["Interchange 105","Interchange 80","Interchange 142","Interchange 9"],"explanation":"10,000 lbs'nin üzerinde kayıtlı ticari araçlar, Garden State Parkway'in Interchange 105'in kuzeyinde yasaklanmıştır (otobüsler, izinli ve idare araçları için sınırlı istisnalarla). Kaynak: NJ Turnpike Authority Parkway düzenlemeleri; N.J.A.C. 19:9-1.9."},"68":{"q":"New Jersey Turnpike'ın 'çift-çift' (dual-dual) bölümünde, güney ayrımı ile kuzey birleşimi arasındaki iç yol için hangisi doğrudur?","options":["Yalnızca otomobillerle sınırlıdır, dış yol ise otomobil ve kamyon taşır","Yalnızca kamyonlarla sınırlıdır, dış yol ise yalnızca otomobil taşır","Yalnızca otobüsler ve acil durum araçları için ayrılmıştır","Araç türü ne olursa olsun yalnızca kuzeye giden trafiği taşır"],"explanation":"New Jersey Turnpike'ın çift-çift yapılandırmasında, iç yol yalnızca otomobil olarak belirlenmiştir; dış yol ise hem otomobil hem de kamyon taşır; kamyonlar ve otobüsler dış şeritlere yönlendirilir. Kaynak: NJ Turnpike Authority; NJ MVC."},"69":{"q":"New Jersey'nin sağda kalma yasası uyarınca, çok şeritli bir karayolunda, geçiş yapmayan veya sola dönmeye hazırlanmayan bir sürücü ne yapmalıdır?","options":["Trafik için mevcut olan en sağdaki şeritte kalmak","Her zaman orta şeridi kullanmak","Hangi şeritte en az trafik varsa onu kullanmak","Sağ tarafı kamyonlar için açık tutmak amacıyla en soldaki şeritte kalmak"],"explanation":"N.J.S.A. 39:4-82, sürücülerin sağda kalmasını ve geçiş yaparken veya sola dönüşe hazırlanırken hariç en sağdaki şeritte sürmesini gerektirir; cezalar N.J.S.A. 39:4-88.1 kapsamında belirlenir. Kaynak: N.J.S.A. 39:4-82, 39:4-88.1."},"70":{"q":"New Jersey düzenlemeleri uyarınca, beş tonun üzerindeki bir kamyon, çok şeritli bölünmüş bir karayolunun sol şeridinde ne zaman çalışabilir?","options":["Yalnızca yola girip çıkmak için, acil bir durumda veya bir sol dönüşe bir mil mesafe içindeyken","Daha yavaş bir aracı geçtiği her an","Yalnızca gece yarısı ile sabah 6 arasında","Sağ şeritteki trafik yoğun olduğu her an"],"explanation":"New Jersey, bölünmüş karayollarında beş tonun üzerindeki kamyonları sağ şeritlerle sınırlandırır; sol şeride yalnızca yola girmek/çıkmak için, acil bir durumda veya bir sol dönüşe bir mil mesafe içindeyken izin verir. Kaynak: NJ sağda kalma kuralları; N.J.S.A. 39:4-82 ve ilgili Title 39 hükümleri."},"71":{"q":"N.J.S.A. 39:4-98.1 uyarınca, Ulaştırma Komiseri, uygun çok şeritli eyalet karayollarında 10,000 pound veya daha fazla kayıtlı ağırlıktaki kamyonlar için belirlenen sınırın ne kadar altında bir farkla daha düşük bir azami hız sınırı belirleyebilir?","options":["5 mph","10 mph","15 mph","20 mph"],"explanation":"N.J.S.A. 39:4-98.1, sınırın 50 mph veya daha fazla olduğu dört veya daha fazla şeritli eyalet karayollarında 10,000 lbs veya daha fazla kamyonlar için 5 mph farkla belirlenmiş daha düşük bir kamyon hız sınırına izin verir. Kaynak: N.J.S.A. 39:4-98.1."},"72":{"q":"New Jersey'nin genel hız yasası uyarınca, belirlenmiş bir sınır yoksa, 'diğer tüm konumlar' (ticari, yerleşim veya okul bölgeleri dışında) için yasal hız sınırı nedir?","options":["50 mph","55 mph","65 mph","45 mph"],"explanation":"N.J.S.A. 39:4-98, farklı bir sınır belirtilmedikçe, ticari/yerleşim bölgelerinde 25 mph, belirli banliyö bölgelerinde 35 mph ve diğer tüm konumlarda 50 mph'lik karine niteliğindeki sınırları belirler. Kaynak: N.J.S.A. 39:4-98."},"73":{"q":"Bir New Jersey CMV'sinde gerekli bir duruşun ardından demiryolu raylarını geçerken, sürücü ne YAPMAMALIDIR?","options":["Aracın herhangi bir kısmı raylar üzerindeyken vites değiştirmek","Yaklaşırken dörtlü acil durum flaşörlerini kullanmak","Bir tren için her iki yöne de bakıp dinlemek","Geçmeden önce camı açmak"],"explanation":"New Jersey CDL Kılavuzu, aracın geçit üzerinde stop etmemesi için sürücülere demiryolu raylarını geçerken vites değiştirmemelerini talimatlandırır. Kaynak: NJ MVC CDL Manual, Secs. 2.15 ve 9.6.12."},"74":{"q":"Bir New Jersey otobüs şoförünün aşağıdaki durumların hangisinde bir demiryolu geçidinde durması GEREKMEZ?","options":["Geçit 'muaf' (exempt) veya 'terk edilmiş' (abandoned) olarak işaretlenmiştir","Geçitte çapraz levha (crossbuck) vardır ancak bariyer yoktur","Geçitte iki set ray vardır","Geçit, sinyalizasyonu olmayan kırsal bir alandadır"],"explanation":"New Jersey CDL Kılavuzu, otobüs durma gerekliliğine istisnaları listeler; bunlar arasında bir polis memuru veya işaretçinin trafiği yönlendirdiği yerler, bir trafik sinyalinin yeşil olduğu yerler ve 'muaf' veya 'terk edilmiş' olarak işaretlenmiş geçitler yer alır. Kaynak: NJ MVC CDL Manual, Sec. 4.3.5."},"75":{"q":"New Jersey'de, çapraz levhalı (crossbuck) ancak yol yüzeyine boyanmış beyaz dur çizgisi olmayan bir demiryolu geçidinde, durması gereken araçlar en yakın raydan hangi aralık içinde durmalıdır?","options":["15 feet'ten yakın olmadan ve 50 feet'ten uzak olmadan","10 feet'ten yakın olmadan ve 30 feet'ten uzak olmadan","20 feet'ten yakın olmadan ve 60 feet'ten uzak olmadan","25 feet'ten yakın olmadan ve 100 feet'ten uzak olmadan"],"explanation":"New Jersey CDL Kılavuzu, beyaz dur çizgisinin boyanmadığı yerlerde durması gereken araçların en yakın raydan 15 feet'ten yakın olmadan ve 50 feet'ten fazla olmadan durması gerektiğini belirtir. Kaynak: NJ MVC CDL Manual, Sec. 2.15."},"76":{"q":"Bir gabari (oversize) izni olmadan, New Jersey karayollarında yasal azami araç genişliği nedir?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"New Jersey'nin yasal azami genişliği 8 feet 6 inches'tir (102 inches); bunu aşan yükler NJDOT'tan bir gabari izni gerektirir. Standart yasal yükseklik 13 feet 6 inches ve brüt ağırlık 80,000 lbs'dir. Kaynak: NJDOT Ticari Araç boyut/ağırlık düzenlemeleri; Title 39."},"77":{"q":"New Jersey'de bir okul otobüsü bir demiryolu-karayolu geçidinde stop etmiştir (mahsur kalmıştır). New Jersey CDL Kılavuzu'na göre, sürücü önce ne yapmalıdır?","options":["Öğrencileri tahliye etmek ve onları yaklaşan herhangi bir trene doğru açılı olarak raylardan en az 100 feet uzağa yönlendirmek","Öğrencileri oturmuş halde tutmak ve geçit üzerindeyken motoru yeniden çalıştırmaya çalışmak","Yardım gelene kadar öğrencileri otobüsün zemininde yatırmak","Otobüsü terk etmek ve treni durdurmak için raylar boyunca koşmak"],"explanation":"New Jersey CDL Kılavuzu (Okul Otobüsü bölümü), sürücüyü derhal tahliye etmeye ve öğrencileri raylardan en az 100 feet uzakta güvenli bir yere yönlendirmeye, yaklaşan bir trene doğru ve ondan uzağa açılı olarak hareket ederek enkaz parçalarından zarar görmemelerini sağlamaya yönlendirir. Kaynak: NJ MVC CDL Manual, Sec. 10 (Okul Otobüsleri)."},"78":{"q":"New Jersey'de Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["New Jersey Motor Vehicle Commission (MVC)","New Jersey Department of Transportation (NJDOT)","New Jersey State Police Commercial Bureau","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"New Jersey'de CDL'ler New Jersey Motor Vehicle Commission (MVC) tarafından verilir. NJDOT yolları ve gabari/aşırı ağırlık izinlerini yönetir, FMCSA ise federal standartları belirler ancak belgeyi vermez. Kaynak: NJ MVC, Getting your Commercial Driver License (nj.gov/mvc/drivertopics/gettingcdl.htm)."},"79":{"q":"İlk kez başvuran bir New Jersey adayı bir CDL için sınava girebilmeden önce, MVC'ye kaç puanlık kimlik (point of identification) ibraz etmelidir?","options":["6 puanlık kimlik","4 puanlık kimlik","8 puanlık kimlik","2 puanlık kimlik"],"explanation":"New Jersey, 6 Points of ID doğrulama programını kullanır; CDL adayları altı puanlık kimlik (Sosyal Güvenlik numarası kanıtı, adres ve yasal mevcudiyet dahil) tesis etmelidir. Kaynak: NJ MVC, Getting your Commercial Driver License ve NJ MVC 6 Points of ID Program."},"80":{"q":"EYALET İÇİ (yalnızca New Jersey içinde) operasyon için bir New Jersey CDL'si almanın asgari yaşı nedir?","options":["18 yaşında","21 yaşında","19 yaşında","20 yaşında"],"explanation":"Bir kişinin eyalet içi sürüş için bir NJ CDL'si almak için en az 18 yaşında olması gerekir; 21 yaşın altındaki sürücüler eyalet içi operasyonla sınırlıdır ve ticaret kategorisi 3 veya 4 olarak kendi beyanlarını (self-certify) yapmalıdır. Eyaletler arası operasyon 21 yaşını gerektirir. Kaynak: NJ MVC, Getting your Commercial Driver License ve Commercial Learner Permits (CLP)."},"81":{"q":"20 yaşında bir New Jersey CDL sahibi hangi tür operasyonla sınırlıdır?","options":["Yalnızca eyalet içi (New Jersey içinde)","Yalnızca eyaletler arası (eyalet sınırları boyunca)","Hem eyaletler arası hem de eyalet içi","Yalnızca tehlikeli madde taşımacılığı"],"explanation":"21 yaşın altındaki sürücüler yalnızca eyalet içi ticarette (New Jersey içinde) çalışabilir ve kendi beyan (self-certification) ticaret kategorisi 3 veya 4'ü seçmelidir. Eyaletler arası operasyona 21 yaşına kadar izin verilmez. Kaynak: NJ MVC, Commercial Learner Permits (CLP)."},"82":{"q":"Bir New Jersey adayı ilk kez CDL beceri (skills) testine girmeden önce hangi eğitimi tamamlamalıdır?","options":["Bir FMCSA Training Provider Registry sağlayıcısından Entry-Level Driver Training (ELDT)","Bir MVC kurumunda eyalet tarafından yürütülen bir savunmacı sürüş kursu","40 saatlik bir OSHA ticari güvenlik sertifikası","NJDOT onaylı bir gabari yük taşıma sınıfı"],"explanation":"7 Şubat 2022'den itibaren geçerli olmak üzere, adaylar CDL beceri testine girmeden (ve HAZMAT bilgi testinden önce) FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan Entry-Level Driver Training (ELDT) tamamlamalıdır. Kaynak: NJ MVC, Getting your Commercial Driver License; FMCSA ELDT kuralı (49 CFR Part 380)."},"83":{"q":"New Jersey CDL kendi beyanında (self-certification) bir adayın seçmesi gereken kaç ticaret kategorisi vardır?","options":["4 kategori","2 kategori","3 kategori","5 kategori"],"explanation":"Dört kendi beyan ticaret kategorisi vardır: (1) muaf olmayan eyaletler arası, (2) muaf eyaletler arası, (3) muaf olmayan eyalet içi ve (4) muaf eyalet içi. Aday birini seçmelidir. Kaynak: NJ MVC, CDL Self-Certification and Medical Examiner Certificate (cdlmedcert.htm)."},"84":{"q":"New Jersey'de hangi kendi beyan (self-certification) kategorileri, bir CDL sahibinin dosyada geçerli bir Medical Examiner's Certificate (Sağlık Muayenecisi Sertifikası) bulundurmasını GEREKTİRİR?","options":["Muaf olmayan eyaletler arası (1) ve muaf olmayan eyalet içi (3)","Muaf eyaletler arası (2) ve muaf eyalet içi (4)","Muaf olmayan eyaletler arası (1) ve muaf eyaletler arası (2)","Yalnızca muaf olmayan eyaletler arası (1)"],"explanation":"'Muaf olmayan' kategoriler (1 ve 3) geçerli bir Medical Examiner's Certificate gerektirir. 'Muaf' kategoriler (2 ve 4), sürücü bir yolcu (P) veya okul otobüsü (S) onayına (endorsement) sahip olmadıkça bir tane gerektirmez. Kaynak: NJ MVC, CDL Self-Certification and Medical Examiner Certificate."},"85":{"q":"Mevcut kurallar uyarınca, bir sürücünün sağlık muayenecisi sertifikası normalde New Jersey MVC'ye nasıl ulaşır?","options":["Elektronik olarak, FMCSA'nın National Registry'sinden eyalet belge verme kurumuna iletilir","Sürücü, noter onaylı bir kağıt kopyasını NJDOT merkezine postalar","Sürücünün işvereni bunu New Jersey State Police'e sunar","Nakliye şirketi tarafından yerel MVC kurumuna faksla gönderilir"],"explanation":"Sağlık muayenecileri muayene sonuçlarını elektronik olarak FMCSA'nın National Registry'sine sunar ve sertifikasyon elektronik olarak State Driver Licensing Agency'ye (NJ MVC) iletilir; kanıt olarak hiçbir kağıt sertifika (Form MCSA-5876) gerekmez. Kaynak: NJ MVC, CDL Self-Certification and Medical Examiner Certificate."},"86":{"q":"Bir CDL sahibinin Medical Examiner's Certificate'ı için fiziksel muayeneyi yapmaya kim yetkilidir?","options":["FMCSA'nın National Registry of Certified Medical Examiners'ında listelenen bir sağlık muayenecisi","Sicil durumu ne olursa olsun, ruhsatlı herhangi bir New Jersey hekimi","Bir MVC belge verme kurumundaki bir hemşire","NJDOT istihdamında bir iş sağlığı görevlisi"],"explanation":"Muayene, FMCSA'nın National Registry of Certified Medical Examiners'ında listelenen, federal olarak sertifikalı bir sağlık muayenecisi tarafından yapılmalıdır; bu muayeneci sonuçları elektronik olarak sunar. Kaynak: NJ MVC, CDL Self-Certification and Medical Examiner Certificate."},"87":{"q":"Bir New Jersey adayı CDL bilgi test(ler)ini geçtikten sonra ne alır?","options":["Bir Commercial Learner's Permit (CLP)","Tam bir Commercial Driver License (CDL)","Geçici bir HAZMAT onay (endorsement) kartı","Bir beceri testi muafiyet (waiver) sertifikası"],"explanation":"Gerekli bilgi test(ler)ini geçmek, adayı beceri testinden önce denetimli pratik yapmaya olanak tanıyan bir Commercial Learner's Permit (CLP) için nitelikli kılar. CDL yalnızca beceri testi geçildikten sonra verilir. Kaynak: NJ MVC, Getting your Commercial Driver License ve Commercial Learner Permits (CLP)."},"88":{"q":"Bir New Jersey CDL bilgi testini geçmek için bir adayın alması gereken asgari yüzde nedir?","options":["80%","70%","75%","90%"],"explanation":"Her aday, New Jersey'de bir CDL bilgi testini geçmek için soruların en az 80%'ini doğru yanıtlamalıdır. Kaynak: NJ MVC, CDL Tests (cdltest.htm)."},"89":{"q":"New Jersey'deki genel bilgi CDL testi kaç sorudan oluşur?","options":["50 soru","30 soru","100 soru","25 soru"],"explanation":"CDL bilgi sınavı, 50 soruluk bir genel testin yanı sıra, istenen her onay (endorsement) için ayrı ek testler içerir. Kaynak: NJ MVC, CDL Tests (cdltest.htm)."},"90":{"q":"Bir New Jersey Commercial Learner's Permit (CLP), verildikten sonra ne kadar süre geçerlidir?","options":["180 gün","90 gün","1 yıl","60 gün"],"explanation":"Bir New Jersey CLP'si veriliş tarihinden itibaren 180 gün geçerlidir. Kaynak: NJ MVC, Commercial Learner Permits (CLP) (cdlclp.htm)."},"91":{"q":"Bir New Jersey Commercial Learner's Permit (CLP) kaç kez yenilenebilir?","options":["Bir kez","Yenilenemez","İki kez","Sınırsız sayıda"],"explanation":"Bir NJ CLP'si 180 gün geçerlidir ve bilgi testlerini yeniden almadan yalnızca bir kez (ek bir süre için) yenilenebilir. Kaynak: NJ MVC, Commercial Learner Permits (CLP)."},"92":{"q":"Bir New Jersey CLP'si verildikten sonra, bir sürücünün CDL beceri testine girmeden önce onu elinde bulundurması gereken asgari süre nedir?","options":["14 gün","30 gün","7 gün","10 gün"],"explanation":"Bir CLP sahibi, CDL beceri (yol) testine girmeden önce izin verildikten sonra en az 14 gün beklemelidir. Kaynak: NJ MVC, Getting your Commercial Driver License; federal CLP kuralı (49 CFR 383.25)."},"93":{"q":"New Jersey CDL beceri testi, sırasıyla hangi üç bölümden oluşur?","options":["Sefer öncesi muayene, temel araç kontrolü ve yolda sürüş","Yazılı bilgi, görme taraması ve yolda sürüş","Hava freni kontrolü, paralel park ve karayolu birleşmesi","Bağlantı (coupling) testi, geri gitme testi ve HAZMAT taşıma"],"explanation":"CDL beceri (yol) testi, sırayla yapılan üç bölümden oluşur: sefer öncesi muayene, temel araç kontrol beceri testi ve yolda sürüş testi. Kaynak: NJ MVC, CDL Tests (cdltest.htm)."},"94":{"q":"New Jersey beceri testinin sefer öncesi muayene bölümünde, adayın ne yapma becerisini göstermesi gerekir?","options":["Muayene edilmesi gereken bileşenleri ve nedenini tanımlamak ve açıklamak","Arızalı bir hava freni haznesini beş dakikadan kısa sürede onarmak","Tüm CDL kılavuzunu ezbere okumak","Beşinci tekerleği (fifth wheel) söküp yeniden monte etmek"],"explanation":"Sefer öncesi muayene testinde, aday muayene edilecek her bileşeni tanımlayabildiğini ve neden kontrol edildiğini açıklayabildiğini göstererek aracın sürmek için güvenli olduğunu kanıtlamalıdır. Kaynak: NJ MVC, CDL Tests (cdltest.htm)."},"95":{"q":"Beceri testi için, adayın hangi koşulu karşılayan temsili bir ticari motorlu araç sağlaması gerekir?","options":["Güncel muayene, geçerli kayıt ve sigorta ve kargo veya tehlikeli madde bulunmaması","Azami brüt ağırlık derecesine kadar yüklenmiş bir araç","İki yaşından büyük olmayan bir araç","Yalnızca ruhsatlı bir nakliyeci tarafından sahip olunan bir araç"],"explanation":"Adaylar, güncel muayeneye, geçerli kayıt ve sigortaya, uygun GVWR/plaketlemeye sahip ve içinde kargo veya tehlikeli madde bulunmayan, istenen sınıfı temsil eden uygun bir CMV sağlamalıdır. Kaynak: NJ MVC, CDL Tests (cdltest.htm)."},"96":{"q":"Bir New Jersey CDL'si ne sıklıkla yenilenmelidir?","options":["Her 4 yılda bir","Her 2 yılda bir","Her 5 yılda bir","Her 8 yılda bir"],"explanation":"Standart bir New Jersey CDL'si dört yıllık bir süre için verilir ve her 4 yılda bir yenilenmelidir (ilk bir CDL, temel belgenin sona erme tarihiyle eşleşecek şekilde orantılanabilir). Kaynak: NJ MVC, Getting your Commercial Driver License (gettingcdl.htm)."},"97":{"q":"Bir New Jersey CDL'sinin yenilenmesiyle ilgili hangi ifade doğrudur?","options":["Çevrimiçi veya postayla değil, bir MVC kurumunda bizzat yenilenmelidir","Temel bir Class D belgesi gibi tamamen çevrimiçi yenilenebilir","Yalnızca hiçbir onay (endorsement) tutulmuyorsa postayla yenilenebilir","Hiçbir sürücü işlemi gerekmeden otomatik olarak yenilenir"],"explanation":"Temel bir sürücü belgesinin aksine, bir New Jersey CDL'si çevrimiçi veya postayla yenilenemez; sahibi bir MVC kurumunda bizzat yenilemeli ve gerekli belgeleri ve güncel sağlık sertifikası durumunu sunmalıdır. Not: kesin ücretler değişebilir, bu nedenle güncel tutarları MVC ile teyit edin. Kaynak: NJ MVC CDL yenileme kılavuzu."}},"es":{"0":{"q":"En las carreteras de Nueva Jersey, ¿cuál es la altura máxima de un vehículo o combinación de vehículos, incluida su carga?","options":["13 pies 6 pulgadas","13 pies 0 pulgadas","14 pies 0 pulgadas","14 pies 6 pulgadas"],"explanation":"La ley de Nueva Jersey (N.J.S.A. 39:3-84) establece la altura máxima de cualquier vehículo o combinación, incluida la carga o el contenido, en 13 pies 6 pulgadas en todas las carreteras. (Fuente: N.J.S.A. 39:3-84; NJDOT Commercial Vehicle Size and Weight Guidebook.)"},"1":{"q":"¿Cuál es el peso bruto total máximo de un vehículo permitido en las carreteras de Nueva Jersey sin un permiso por exceso de peso?","options":["80,000 libras","73,280 libras","88,000 libras","76,000 libras"],"explanation":"Nueva Jersey limita el peso bruto vehicular total máximo a 80,000 libras, coincidiendo con el límite federal (N.J.S.A. 39:3-84). Cualquier valor superior a este en una carga no divisible requiere un permiso por exceso de peso. (Fuente: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"2":{"q":"En la mayoría de las carreteras de Nueva Jersey que NO forman parte de la red designada de 102 pulgadas o de la Red Nacional, ¿cuál es el ancho legal máximo del vehículo?","options":["96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)","108 pulgadas (9 pies)","90 pulgadas (7 pies 6 pulgadas)"],"explanation":"Si bien la Red Nacional designada y la red de camiones de 102 pulgadas de Nueva Jersey permiten 102 pulgadas (8'6\"), otras carreteras públicas están limitadas a 96 pulgadas (8 pies). (Fuente: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)"},"3":{"q":"¿Cuál es el ancho máximo, incluida la carga, permitido para los camiones en la Red Nacional designada y la red de rutas de camiones de 102 pulgadas de Nueva Jersey?","options":["102 pulgadas (8 pies 6 pulgadas)","96 pulgadas (8 pies)","120 pulgadas (10 pies)","114 pulgadas (9 pies 6 pulgadas)"],"explanation":"En la Red Nacional designada y la red de rutas de camiones de 102 pulgadas de Nueva Jersey, el ancho exterior máximo es de 102 pulgadas (8 pies 6 pulgadas), según N.J.S.A. 39:3-84. (Fuente: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"4":{"q":"Según la ley de Nueva Jersey, ¿cuál es el peso bruto máximo que se puede transportar en un solo eje?","options":["22,400 libras","20,000 libras","34,000 libras","24,000 libras"],"explanation":"Nueva Jersey permite hasta 22,400 libras en un solo eje, lo cual es mayor que la cifra federal básica de 20,000 libras para un solo eje (N.J.S.A. 39:3-84). (Fuente: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)"},"5":{"q":"¿Cuál es el peso bruto máximo permitido en un grupo de ejes en tándem en las carreteras de Nueva Jersey?","options":["34,000 libras","22,400 libras","40,000 libras","36,000 libras"],"explanation":"Nueva Jersey limita un grupo de ejes en tándem a 34,000 libras, igual que el estándar federal (N.J.S.A. 39:3-84). (Fuente: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"6":{"q":"¿Cuál es la longitud total máxima de un camión simple (recto) en las carreteras de Nueva Jersey cuando no transporta una carga indivisible?","options":["40 pies","35 pies","45 pies","53 pies"],"explanation":"N.J.S.A. 39:3-84 limita la longitud total de un vehículo simple a 40 pies (extendida a 50 pies solo cuando transporta postes, pilotes u otros artículos que no se pueden dividir). (Fuente: N.J.S.A. 39:3-84.)"},"7":{"q":"Según el estatuto de Nueva Jersey, ¿cuál es la longitud total máxima de una COMBINACIÓN de tractocamión y semirremolque (la unidad motriz más su carga) en carreteras generales?","options":["62 pies","53 pies","65 pies","75 pies"],"explanation":"N.J.S.A. 39:3-84 establece la longitud total de una combinación de vehículos, incluida la carga, en 62 pies. Tenga en cuenta que en la Red Nacional un tractocamión con semirremolque no tiene límite de longitud total, con el semirremolque en sí limitado a 53 pies. (Fuente: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"8":{"q":"En la Red Nacional de Nueva Jersey y en las rutas designadas de 102 pulgadas, ¿cuál es la longitud máxima de un SEMIRREMOLQUE que opera en una combinación de tractocamión y semirremolque?","options":["53 pies","48 pies","57 pies","45 pies"],"explanation":"Un semirremolque puede tener hasta 53 pies en la Red Nacional y en la red de 102 pulgadas de NJ (48 pies en otras carreteras), según las reglas del NJDOT y N.J.S.A. 39:3-84. (Fuente: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)"},"9":{"q":"Para un semirremolque de 48 a 53 pies que opera en la red designada de Nueva Jersey, ¿cuál es la distancia máxima permitida desde el pivote de enganche (kingpin) hasta el centro del eje trasero?","options":["41 pies","37 pies","46 pies","53 pies"],"explanation":"Para remolques de más de 48 pies hasta 53 pies, la distancia desde el pivote de enganche (kingpin) hasta el centro del eje trasero no puede exceder los 41 pies en la red interestatal/designada. (Fuente: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)"},"10":{"q":"En una combinación de remolques gemelos (dobles) que opera en la red designada de Nueva Jersey, ¿cuál es la longitud máxima de CADA unidad de arrastre?","options":["28 pies","33 pies","40 pies","53 pies"],"explanation":"Cada remolque en una combinación de remolques gemelos de Nueva Jersey está limitado a 28 pies, en consonancia con el estándar federal de dobles STAA reconocido en virtud de N.J.S.A. 39:3-84. (Fuente: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)"},"11":{"q":"¿Cuál es la carga bruta máxima que permite Nueva Jersey por pulgada de ancho de neumático?","options":["800 libras","650 libras","500 libras","1,000 libras"],"explanation":"Nueva Jersey limita la carga a 800 libras por pulgada de ancho de neumático (N.J.S.A. 39:3-84). (Fuente: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)"},"12":{"q":"La fórmula federal del puente utilizada en Nueva Jersey, W = 500[LN/(N-1) + 12N + 36], ¿qué valor determina?","options":["El peso bruto máximo permitido en un grupo de ejes consecutivos según su espaciamiento y número","La altura máxima de un vehículo según su distancia entre ejes","El ancho máximo según el número de neumáticos","La distancia mínima de frenado requerida para una combinación cargada"],"explanation":"La Fórmula Federal del Puente, aplicada en Nueva Jersey, calcula el peso bruto máximo permitido (W) en cualquier grupo de dos o más ejes consecutivos, donde L es el espaciamiento entre los ejes exteriores y N es el número de ejes. (Fuente: 23 CFR 658 / Fórmula Federal del Puente aplicada por el NJDOT; NJDOT Size and Weight Guidebook.)"},"13":{"q":"En la fórmula federal del puente tal como se usa en Nueva Jersey, ¿qué representa la variable 'L'?","options":["La distancia en pies entre los ejes exteriores del grupo de ejes","La longitud total del remolque","El límite de carga legal en libras","La tolerancia de peso del eje elevable"],"explanation":"En W = 500[LN/(N-1) + 12N + 36], 'L' es la distancia en pies entre los ejes más exteriores del grupo en consideración, y 'N' es el número de ejes en ese grupo. (Fuente: Fórmula Federal del Puente, 23 CFR 658, aplicada por el NJDOT.)"},"14":{"q":"¿Cuándo se emite en Nueva Jersey un permiso por sobredimensión/exceso de peso (OS/OW) para una carga que excede los límites legales de tamaño o peso?","options":["Solo cuando la carga es no divisible (no se puede desmontar ni dividir para cumplir con los límites legales)","Para cualquier carga, divisible o no, siempre que se pague una tarifa","Solo para cargas de productos agrícolas","Solo los fines de semana y días feriados"],"explanation":"El NJDOT emite permisos OS/OW solo para cargas no divisibles, definidas como cargas que no se pueden desmembrar, desmontar ni dividir para cumplir con los límites de peso y dimensionales. (Fuente: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)"},"15":{"q":"¿Cómo solicita un transportista en Nueva Jersey un permiso de transporte por sobredimensión/exceso de peso?","options":["En línea las 24/7 a través del sitio web de permisos OS/OW del NJDOT (nj.gotpermits.com)","Solo en persona en la oficina del secretario del condado durante el horario laboral","Enviando por correo un formulario notariado a la Policía Estatal","Automáticamente con la emisión de una CDL"],"explanation":"Los transportistas pueden solicitar permisos OS/OW del NJDOT en línea las 24 horas del día, los 7 días de la semana en el sitio web de permisos OS/OW del NJDOT (nj.gotpermits.com), ya sea directamente o a través de un servicio de permisos registrado. (Fuente: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)"},"16":{"q":"¿A partir de qué ancho de carga (incluida la carga) Nueva Jersey requiere al menos un vehículo escolta para un traslado con sobredimensión autorizado?","options":["Cuando el ancho excede los 14 pies","Cuando el ancho excede los 10 pies","Cuando el ancho excede los 8 pies 6 pulgadas","Cuando el ancho excede los 16 pies"],"explanation":"Según las reglas de permisos del NJDOT, se requiere un vehículo escolta cuando el ancho, incluida la carga, excede los 14 pies; se requieren dos escoltas cuando el ancho excede los 16 pies. (Fuente: NJDOT OS/OW Permit Reference Guide; oversize.io NJ regulations.)"},"17":{"q":"Un transportista quiere trasladar una sola pieza de maquinaria no divisible en un tractocamión con semirremolque que tendrá un peso bruto de 110,000 libras y 12 pies de ancho en una carretera estatal de Nueva Jersey. ¿Qué debe hacer el transportista?","options":["Obtener un permiso de sobredimensión/exceso de peso del NJDOT antes del traslado, ya que tanto el peso como el ancho exceden los límites legales","Nada, porque las cargas no divisibles están automáticamente exentas de todos los límites","Solo registrar el vehículo como agrícola para quedar exento","Viajar únicamente de noche sin ningún permiso"],"explanation":"La carga excede el límite de peso bruto de 80,000 libras y el límite de ancho de 102 pulgadas (8'6\"), por lo que se requiere un permiso OS/OW del NJDOT para esta carga no divisible antes de viajar, obtenido a través de nj.gotpermits.com. Un ancho de 12 pies está por debajo del umbral de 14 pies para escolta. (Fuente: N.J.S.A. 39:3-84; NJDOT OS/OW Permit Reference Guide.)"},"18":{"q":"En Nueva Jersey, ¿qué clase de CDL se requiere para operar un vehículo combinado con una clasificación de peso bruto combinado (GCWR) de 26,001 libras o más, donde la unidad remolcada tiene un GVWR de más de 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"El Manual de CDL de NJ define la Clase A como cualquier combinación de vehículos con un GCWR de 26,001 libras o más, siempre que el GVWR de la(s) unidad(es) remolcada(s) sea de más de 10,000 libras. Fuente: NJ MVC Commercial Driver License Manual (definiciones de clases)."},"19":{"q":"Según las reglas de Nueva Jersey, un vehículo simple con un GVWR de 26,001 libras o más, o tal vehículo remolcando una unidad que no supere las 10,000 libras de GVWR, ¿requiere qué clase de CDL?","options":["Clase A","Clase B","Clase C","Clase E"],"explanation":"El Manual de CDL de NJ define la Clase B como cualquier vehículo simple con un GVWR de 26,001 libras o más, o ese vehículo remolcando una unidad cuyo GVWR sea de 10,000 libras o menos. Fuente: NJ MVC Commercial Driver License Manual."},"20":{"q":"En Nueva Jersey, un vehículo diseñado para transportar 16 o más pasajeros (incluido el conductor), o un vehículo más pequeño que transporta materiales peligrosos con rótulos, ¿requiere como mínimo qué clase de CDL?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"El Manual de CDL de NJ define la Clase C como un vehículo que no cumple con los criterios de la Clase A o B pero que está diseñado para transportar 16 o más pasajeros incluido el operador, o que se utiliza para transportar materiales peligrosos que requieren rótulos. Fuente: NJ MVC Commercial Driver License Manual."},"21":{"q":"Un vehículo de Nueva Jersey está diseñado para llevar 16 o más pasajeros incluido el conductor, pero pesa menos de 26,001 libras. ¿Cuál es la clase mínima de CDL necesaria?","options":["No se requiere CDL","Clase A","Clase B","Clase C"],"explanation":"Incluso cuando está por debajo de los umbrales de peso para la Clase A o B, un vehículo diseñado para llevar 16 o más personas incluido el operador se clasifica como Clase C en Nueva Jersey. Fuente: NJ MVC Commercial Driver License Manual (definición de Clase C)."},"22":{"q":"¿Qué endoso necesita un titular de CDL de Nueva Jersey para conducir un vehículo que transporta líquidos o gases a granel en un tanque montado permanentemente?","options":["N (Vehículo Cisterna)","T (Dobles/Triples)","H (Materiales Peligrosos)","P (Pasajeros)"],"explanation":"El endoso N (Vehículo Cisterna) se requiere en Nueva Jersey para operar vehículos que transportan líquidos o gases a granel. Fuente: NJ MVC Endorsements page."},"23":{"q":"En Nueva Jersey, ¿qué endoso se requiere para arrastrar dos o tres remolques, y qué clase de CDL debe tener el conductor?","options":["Endoso T, con una CDL Clase A","Endoso N, con una CDL Clase B","Endoso T, con una CDL Clase C","Endoso P, con una CDL Clase A"],"explanation":"El endoso T (Dobles/Triples) se necesita para arrastrar dos o tres remolques, y se requiere una CDL Clase A para tenerlo. Fuente: NJ MVC Endorsements page."},"24":{"q":"Antes de que Nueva Jersey emita un endoso de HazMat (H), el solicitante debe aprobar una verificación de antecedentes realizada por ¿qué agencia?","options":["La Administración de Seguridad en el Transporte (TSA)","La unidad antifraude de la New Jersey MVC","La Administración Federal de Seguridad de Autotransportes (FMCSA)","Únicamente la Policía Estatal de Nueva Jersey"],"explanation":"Nueva Jersey requiere que los solicitantes del endoso de HazMat (H) sean registrados con huellas dactilares y aprueben una evaluación de amenazas de la Administración de Seguridad en el Transporte (TSA) antes de que se emita el endoso. Fuente: NJ MVC Hazardous Material Endorsements (HME) page; programa TSA HME."},"25":{"q":"Para conducir un autobús escolar en Nueva Jersey, ¿qué combinación de endosos de CDL se requiere?","options":["Tanto P (Pasajeros) como S (Autobús Escolar)","Solo S (Autobús Escolar)","Solo P (Pasajeros)","S y H"],"explanation":"Nueva Jersey requiere que los conductores de autobús escolar tengan tanto el endoso P (Pasajeros) como el endoso S (Autobús Escolar), además de aprobar un examen de conocimientos y un examen de manejo y una verificación de antecedentes. Fuente: NJ MVC Endorsements page."},"26":{"q":"¿Cuál es la edad mínima para obtener una CDL de Nueva Jersey restringida a operación intraestatal (solo dentro de Nueva Jersey)?","options":["18 años","21 años","19 años","17 años"],"explanation":"Un conductor puede obtener una CDL de Nueva Jersey a los 18 años, pero la operación está limitada al comercio intraestatal (dentro de Nueva Jersey) hasta los 21 años. Fuente: NJ MVC Getting Your CDL page."},"27":{"q":"¿Cuál es la edad mínima requerida para operar un vehículo comercial motorizado en comercio interestatal con una CDL de Nueva Jersey?","options":["21 años","18 años","23 años","19 años"],"explanation":"Los conductores menores de 21 años con una CDL de Nueva Jersey solo pueden operar de forma intraestatal; el comercio interestatal (y materiales peligrosos) requiere que el conductor tenga al menos 21 años. Fuente: NJ MVC Getting Your CDL page."},"28":{"q":"Según las reglas federales aplicadas en Nueva Jersey, ¿cuánto tiempo debe esperar el titular de un Permiso de Aprendiz Comercial (CLP) después de que se emite el CLP antes de tomar el examen de habilidades de la CDL?","options":["Un mínimo de 14 días","Un mínimo de 30 días","Un mínimo de 7 días","Un mínimo de 60 días"],"explanation":"Nueva Jersey aplica el requisito federal de que el titular de un CLP debe esperar un mínimo de 14 días antes de tomar el examen de habilidades. Fuente: NJ MVC Getting Your CDL / CLP pages."},"29":{"q":"Una vez emitido, ¿por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Nueva Jersey?","options":["180 días","1 año","90 días","60 días"],"explanation":"Un CLP de Nueva Jersey es válido por 180 días cuando se emite. Fuente: NJ MVC Commercial Learner Permits (CLP) page."},"30":{"q":"Al operar un vehículo comercial motorizado con un Permiso de Aprendiz Comercial de Nueva Jersey, el conductor también debe tener en su posesión ¿qué?","options":["Una licencia de conducir válida de Nueva Jersey","Un pasaporte","Un segundo CLP","Nada adicional"],"explanation":"Un CLP de Nueva Jersey debe ir acompañado de una licencia de conducir válida de Nueva Jersey cuando el titular opera un CMV. Fuente: NJ MVC Commercial Learner Permits (CLP) page."},"31":{"q":"Nueva Jersey requiere que los solicitantes de CDL cumplan con su estándar de verificación de identidad presentando ¿cuántos puntos de identificación?","options":["6 Puntos de ID","4 Puntos de ID","8 Puntos de ID","2 Puntos de ID"],"explanation":"Nueva Jersey utiliza el sistema de 6 Puntos de ID, que requiere documentos que establezcan la identidad, el número de Seguro Social, comprobante de domicilio y comprobante de presencia legal en los EE. UU. Fuente: NJ MVC Getting Your CDL / 6 Points of ID."},"32":{"q":"¿Cuál de los siguientes documentos se requiere específicamente como parte de la verificación de identidad de la CDL de Nueva Jersey?","options":["Tarjeta del Seguro Social y comprobante de presencia legal en los EE. UU.","Únicamente un certificado de nacimiento de cualquier país","Una tarjeta de membresía sindical","Únicamente una carta del empleador"],"explanation":"Los 6 Puntos de ID de Nueva Jersey para una CDL incluyen la tarjeta del Seguro Social, comprobante de domicilio y comprobante de presencia legal en los Estados Unidos. Fuente: NJ MVC Getting Your CDL page."},"33":{"q":"La Capacitación para Conductores de Nivel Inicial (ELDT) requerida antes del primer examen de habilidades de la CDL de Nueva Jersey debe obtenerse de un proveedor que esté:","options":["Incluido en el Registro de Proveedores de Capacitación de la FMCSA","Aprobado únicamente por la NJ MVC","Cualquier escuela de manejo comercial","Certificado por la TSA"],"explanation":"Desde el 7 de febrero de 2022, la ELDT debe completarse a través de un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA antes de tomar el examen de habilidades (o el examen de conocimientos para HazMat). Fuente: NJ MVC Getting Your CDL; FMCSA TPR."},"34":{"q":"¿Para qué endoso debe completarse la ELDT de Nueva Jersey ANTES del examen de conocimientos (escrito), en lugar de antes del examen de habilidades?","options":["H (Materiales Peligrosos)","P (Pasajeros)","S (Autobús Escolar)","N (Vehículo Cisterna)"],"explanation":"Para el endoso de HazMat (H), la ELDT debe completarse antes del examen de conocimientos; para la primera vez de Clase A/B y los endosos P y S, la ELDT se requiere antes del examen de habilidades. Fuente: NJ MVC CLP/CDL pages; FMCSA ELDT rule."},"35":{"q":"Un conductor con CDL de Nueva Jersey que opera únicamente dentro de Nueva Jersey y debe cumplir con el requisito de un certificado de examinador médico estatal debe autocertificarse bajo ¿qué categoría?","options":["Intraestatal No Exento","Interestatal No Exento","Interestatal Exento","Intraestatal Exento"],"explanation":"Intraestatal No Exento (NA) aplica a los conductores que operan únicamente dentro de Nueva Jersey y que deben cumplir con los requisitos de certificado médico. Fuente: NJ MVC CDL Holder Self-Certification; categorías de certificación médica de la FMCSA."},"36":{"q":"¿Qué categoría de autocertificación médica aplica a un titular de CDL de Nueva Jersey que conduce a través de líneas estatales y debe tener un certificado válido de examinador médico del DOT?","options":["Interestatal No Exento","Interestatal Exento","Intraestatal No Exento","Intraestatal Exento"],"explanation":"Los conductores Interestatales No Exentos (NI) operan en comercio interestatal y deben cumplir con los requisitos federales de tarjeta médica del DOT, manteniendo en archivo un certificado de un examinador del Registro Nacional. Fuente: NJ MVC CDL Self-Certification; categorías de la FMCSA."},"37":{"q":"Un conductor de Nueva Jersey que se autocertifica como Interestatal No Exento debe obtener un certificado de examinador médico de un proveedor que esté:","options":["Incluido en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA","Cualquier médico con licencia de Nueva Jersey","Aprobado por el secretario del condado local","Certificado por la TSA"],"explanation":"Los conductores no exentos deben ser examinados por un examinador médico incluido en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA y mantener el certificado en archivo. Fuente: NJ MVC CDL Self-Certification; FMCSA National Registry."},"38":{"q":"En Nueva Jersey, ¿cuál es la concentración máxima legal de alcohol en sangre (BAC) para una persona que opera un vehículo comercial motorizado (CMV)?","options":["0.02","0.04","0.08","0.10"],"explanation":"Nueva Jersey sigue el estándar federal para CMV: es ilegal operar un CMV con un BAC de 0.04 por ciento o superior. Esto es más estricto que el límite de 0.08 para un vehículo personal. Fuente: NJ MVC CDL Manual, Sección 1 (Descalificaciones); 49 CFR 383.51."},"39":{"q":"Según las reglas de consentimiento implícito de Nueva Jersey para titulares de CDL, ¿qué sucede si un conductor se niega a someterse a una prueba de concentración de alcohol al operar un CMV?","options":["Solo se impone una multa, sin descalificación","Se trata como una infracción mayor, descalificando al conductor igual que lo haría una condena por DUI","El conductor recibe una advertencia por una primera negativa","La CDL se suspende solo por 30 días"],"explanation":"Al tener una CDL y conducir en Nueva Jersey, el conductor otorga su consentimiento implícito para las pruebas de alcohol. Negarse a la prueba se trata como una infracción mayor y conlleva la misma descalificación que una condena por DUI (1 año para una primera infracción). Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 1."},"40":{"q":"En Nueva Jersey, ¿cuál es el período mínimo de descalificación de la CDL para una primera infracción mayor, como una primera condena por DUI mientras se opera un CMV sin rótulos?","options":["60 días","120 días","1 año","3 años"],"explanation":"Una primera infracción mayor (incluida DUI, un BAC de 0.04 o superior, o la negativa a la prueba) resulta en una descalificación de la CDL de al menos 1 año. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 1."},"41":{"q":"Si un conductor con CDL de Nueva Jersey comete una primera infracción mayor (como DUI) mientras opera un vehículo con rótulos de materiales peligrosos, ¿cuál es el período de descalificación?","options":["1 año","18 meses","3 años","5 años"],"explanation":"Una primera infracción mayor cometida mientras se transportan materiales peligrosos con rótulos eleva la descalificación de 1 año a 3 años. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 1."},"42":{"q":"¿Cuál es el período de descalificación de la CDL en Nueva Jersey para una segunda infracción mayor (por ejemplo, una segunda condena por DUI en cualquier momento)?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Una segunda infracción mayor resulta en una descalificación de la CDL de por vida. Nueva Jersey sigue la regla federal de que dos infracciones mayores separadas significan que el conductor pierde la CDL de por vida. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 1."},"43":{"q":"En Nueva Jersey, ¿cuántas infracciones de tránsito graves dentro de un período de 3 años (en incidentes separados) provocan una descalificación de la CDL de 60 días?","options":["1","2","3","4"],"explanation":"Una segunda infracción de tránsito grave dentro de 3 años (en un incidente separado) resulta en una descalificación de 60 días. La primera infracción grave por sí sola no causa descalificación. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 2."},"44":{"q":"¿Cuál es el período de descalificación de la CDL en Nueva Jersey para una tercera infracción de tránsito grave dentro de un período de 3 años (en incidentes separados)?","options":["60 días","90 días","120 días","1 año"],"explanation":"Una tercera infracción de tránsito grave dentro de 3 años resulta en una descalificación de 120 días. La segunda dentro de 3 años es de 60 días. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 2."},"45":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito grave para un titular de CDL de Nueva Jersey?","options":["Estacionar un CMV en una zona de no estacionar","Exceder el límite de velocidad señalizado por 15 mph o más","Una luz de gálibo fundida","No mantener ordenado un registro de bitácora"],"explanation":"El exceso de velocidad, definido como 15 mph o más por encima del límite señalizado, es una infracción de tránsito grave. Otras incluyen conducción imprudente, cambios de carril indebidos, seguir demasiado de cerca y enviar mensajes de texto mientras se conduce. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 2."},"46":{"q":"En Nueva Jersey, ¿cuál es la descalificación mínima de la CDL para una primera condena por una infracción en un cruce a nivel de ferrocarril y carretera mientras se opera un CMV?","options":["30 días","60 días","120 días","1 año"],"explanation":"Una primera infracción en un cruce a nivel de ferrocarril y carretera resulta en una descalificación mínima de 60 días. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 3."},"47":{"q":"¿Cuál es la descalificación mínima de la CDL en Nueva Jersey para una segunda infracción en un cruce a nivel de ferrocarril y carretera dentro de un período de 3 años?","options":["60 días","90 días","120 días","1 año"],"explanation":"Una segunda infracción en un cruce a nivel de ferrocarril y carretera dentro de 3 años resulta en una descalificación mínima de 120 días. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 3."},"48":{"q":"¿Cuál es la descalificación mínima de la CDL en Nueva Jersey para una tercera infracción en un cruce a nivel de ferrocarril y carretera dentro de un período de 3 años?","options":["120 días","180 días","1 año","3 años"],"explanation":"Una tercera infracción en un cruce a nivel de ferrocarril y carretera dentro de 3 años resulta en una descalificación mínima de 1 año. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 3."},"49":{"q":"En Nueva Jersey, ¿cuál es la descalificación mínima para una primera condena de un conductor con CDL por violar una orden de fuera de servicio (OOS) mientras no transporta materiales peligrosos ni pasajeros?","options":["90 días","120 días","180 días","1 año"],"explanation":"Una primera condena por violar una orden de fuera de servicio conlleva una descalificación de al menos 180 días (hasta 1 año). Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 4."},"50":{"q":"¿Cuál es el rango de descalificación en Nueva Jersey para una segunda violación de una orden de fuera de servicio dentro de un período de 10 años (sin materiales peligrosos, sin pasajeros)?","options":["180 días a 1 año","1 a 2 años","2 a 5 años","3 a 5 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 años resulta en una descalificación de 2 a 5 años. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 4."},"51":{"q":"¿Cuál es el rango de descalificación en Nueva Jersey para una tercera o subsiguiente violación de una orden de fuera de servicio dentro de un período de 10 años (sin materiales peligrosos, sin pasajeros)?","options":["180 días a 1 año","2 a 5 años","3 a 5 años","De por vida"],"explanation":"Una tercera o subsiguiente violación de una orden de fuera de servicio dentro de 10 años resulta en una descalificación de 3 a 5 años. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 4."},"52":{"q":"En Nueva Jersey, además de la descalificación, ¿qué multa de penalidad civil enfrenta un conductor con CDL por una primera condena por violar una orden de fuera de servicio?","options":["Al menos $1,000","Al menos $2,500","Al menos $5,000","Al menos $10,000"],"explanation":"Además de la descalificación, un conductor que viola una orden de fuera de servicio está sujeto a una penalidad civil de al menos $2,500 por una primera infracción, y de al menos $5,000 por una infracción subsiguiente. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.53."},"53":{"q":"Un conductor con CDL de Nueva Jersey que viola una orden de fuera de servicio mientras transporta materiales peligrosos con rótulos enfrenta ¿qué descalificación mínima para una primera infracción?","options":["120 días","180 días","1 año","2 años"],"explanation":"Una primera violación de una orden de fuera de servicio mientras se transportan materiales peligrosos que requieren rótulos (o mientras se opera un vehículo diseñado para llevar 16 o más pasajeros) conlleva una descalificación de al menos 180 días, hasta 2 años. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 4."},"54":{"q":"Según las reglas de Nueva Jersey y federales, enviar mensajes de texto mientras se conduce un CMV se clasifica como ¿qué tipo de infracción para un titular de CDL?","options":["Una infracción no imputable","Una infracción de tránsito grave","Una infracción mayor","Una violación de orden de fuera de servicio"],"explanation":"Enviar mensajes de texto y usar un teléfono móvil de mano mientras se conduce un CMV son infracciones de tránsito graves. Dos de estas infracciones dentro de 3 años conducen a una descalificación de 60 días; tres conducen a 120 días. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 2 y 392.80/392.82."},"55":{"q":"¿Cuál es la multa máxima para el conductor por usar un teléfono móvil de mano o enviar mensajes de texto mientras opera un CMV que aplica a los conductores con CDL de Nueva Jersey?","options":["Hasta $500","Hasta $1,000","Hasta $2,750","Hasta $5,000"],"explanation":"Un conductor con CDL que usa un teléfono de mano o envía mensajes de texto mientras conduce un CMV puede ser multado con hasta $2,750, y la infracción cuenta como una infracción de tránsito grave. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 392.82."},"56":{"q":"Usar un CMV en la comisión de un delito grave que involucra la fabricación, distribución o dispensación de una sustancia controlada conlleva ¿qué descalificación de la CDL de Nueva Jersey?","options":["1 año","3 años","10 años","De por vida sin posibilidad de reinstauración"],"explanation":"Usar un CMV para cometer un delito grave que involucra sustancias controladas es una infracción mayor que resulta en una descalificación de por vida sin posibilidad de reinstauración. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 1."},"57":{"q":"Un titular de CDL de Nueva Jersey acumula una primera condena por DUI y luego una condena separada por darse a la fuga del lugar de un accidente en un CMV. ¿Cuál es el resultado de esta segunda infracción mayor?","options":["Una descalificación de 120 días","Una descalificación de 1 año","Una descalificación de 3 años","Una descalificación de por vida"],"explanation":"El DUI y darse a la fuga del lugar de un accidente en un CMV son ambas infracciones mayores. Dos infracciones mayores cualesquiera (en incidentes separados) resultan en una descalificación de la CDL de por vida, incluso si son tipos diferentes de infracción mayor. Fuente: NJ MVC CDL Manual, Sección 1; 49 CFR 383.51 Tabla 1."},"58":{"q":"Según la ley \"Move Over\" (Cámbiate de carril) de Nueva Jersey, ¿qué debe hacer el conductor de un vehículo comercial al acercarse a un vehículo de emergencia detenido, una grúa o un vehículo de mantenimiento de carreteras con luces intermitentes encendidas en una autopista de varios carriles?","options":["Cambiarse a un carril que no esté contiguo al vehículo detenido, si se puede hacer de manera segura","Detenerse por completo hasta que el vehículo detenido se aleje","Continuar a la velocidad indicada, pero tocar la bocina al pasar","Orillarse al acotamiento y esperar a que un oficial indique con la mano que el tránsito puede pasar"],"explanation":"La ley \"Move Over\" de Nueva Jersey (N.J.S.A. 39:4-92.2) exige que el conductor que se aproxima en una vía de varios carriles se cambie a un carril que no esté contiguo al vehículo detenido cuando sea seguro hacerlo. Fuente: N.J.S.A. 39:4-92.2; New Jersey MVC."},"59":{"q":"Según la ley \"Move Over\" de Nueva Jersey, si un conductor no puede cambiarse de carril de manera segura para alejarse de un vehículo de emergencia o de servicio detenido con luces intermitentes, ¿qué se requiere?","options":["Reducir la velocidad a una velocidad razonable y adecuada por debajo del límite indicado y avanzar con precaución","Mantener el límite de velocidad indicado para evitar obstruir el tránsito","Detenerse por completo en el carril actual hasta que se apaguen las luces","Pasarse al camellón central sin importar las condiciones"],"explanation":"N.J.S.A. 39:4-92.2 establece que, cuando no se puede cambiar de carril de manera segura, el conductor debe reducir la velocidad a una velocidad razonable y adecuada por debajo del límite indicado y estar preparado para detenerse. Fuente: N.J.S.A. 39:4-92.2; New Jersey MVC."},"60":{"q":"En Nueva Jersey, ¿a qué distancia del riel más cercano de un cruce a nivel entre vía férrea y carretera debe detenerse un autobús antes de continuar?","options":["Entre 15 y 50 pies","Entre 5 y 15 pies","Entre 50 y 100 pies","Entre 10 y 25 pies"],"explanation":"El Manual de CDL de Nueva Jersey (Sección 4, Transporte de Pasajeros) exige que un autobús se detenga entre 15 y 50 pies antes de un cruce ferroviario y, luego, mire y escuche para detectar trenes. Fuente: New Jersey MVC Commercial Driver License Manual, Sec. 4.3.5."},"61":{"q":"Un vehículo de materiales peligrosos con placas (placarded) en Nueva Jersey debe detenerse a qué distancia del riel más cercano antes de cruzar las vías del tren?","options":["No más cerca de 15 pies y no más lejos de 50 pies","No más cerca de 25 pies y no más lejos de 75 pies","No más cerca de 10 pies y no más lejos de 40 pies","No más cerca de 5 pies y no más lejos de 30 pies"],"explanation":"El Manual de CDL de Nueva Jersey (Sección 9, Materiales Peligrosos) indica que un vehículo con placas, uno que transporte cualquier cantidad de cloro, o uno con tanques de carga usados para HazMat debe detenerse de 15 a 50 pies antes del riel más cercano. Fuente: New Jersey MVC CDL Manual, Sec. 9.6.12."},"62":{"q":"En una carretera de Nueva Jersey de dos carriles y sin división, un autobús escolar está detenido con las luces rojas intermitentes encendidas para recoger niños. Un vehículo que se acerca al autobús o lo rebasa debe detenerse al menos a qué distancia?","options":["25 pies","10 pies","20 pies","50 pies"],"explanation":"N.J.S.A. 39:4-128.1 exige que un conductor que se acerca a un autobús escolar o lo rebasa, cuando este tiene las luces rojas intermitentes encendidas en una calzada sin división, se detenga al menos a 25 pies de distancia y permanezca detenido hasta que las luces dejen de parpadear. Fuente: N.J.S.A. 39:4-128.1."},"63":{"q":"Según la ley de Nueva Jersey, un conductor que circula por una calzada SEPARADA de una autopista doble o dividida y que se acerca a un autobús escolar detenido con las luces rojas intermitentes encendidas en la otra calzada, ¿qué debe hacer?","options":["Reducir la velocidad a no más de 10 mph y pasar junto al autobús con precaución","Detenerse al menos a 25 pies del autobús y esperar a que las luces dejen de parpadear","Detenerse por completo y esperar a que el conductor del autobús indique con la mano que el tránsito puede continuar","Continuar a la velocidad indicada porque no se requiere ninguna acción"],"explanation":"N.J.S.A. 39:4-128.1 prevé una excepción para autopistas divididas: un conductor que circula por otra calzada de una autopista doble o dividida no tiene que detenerse, pero debe reducir la velocidad a no más de 10 mph hasta haber pasado el autobús y a cualquier niño. Fuente: N.J.S.A. 39:4-128.1."},"64":{"q":"Cuando un CMV de Nueva Jersey está detenido en una autopista de un solo sentido o dividida, el conductor debe colocar los tres dispositivos de advertencia (triángulos) a qué distancias en dirección al tránsito que se aproxima?","options":["10 pies, 100 pies y 200 pies","10 pies, 50 pies y 100 pies","25 pies, 100 pies y 150 pies","10 pies, 200 pies y 300 pies"],"explanation":"El Manual de CDL de Nueva Jersey indica que, en una autopista de un solo sentido o dividida, los dispositivos de advertencia se coloquen a 10 pies, 100 pies y 200 pies en dirección al tránsito que se aproxima. Fuente: New Jersey MVC CDL Manual, Sec. 2 (Conducir con Seguridad)."},"65":{"q":"Después de detener un CMV en el acotamiento de una carretera de Nueva Jersey, ¿dentro de cuántos minutos debe el conductor colocar los dispositivos de advertencia de emergencia?","options":["10 minutos","5 minutos","15 minutos","30 minutos"],"explanation":"El Manual de CDL de Nueva Jersey exige que, si debe detenerse en una carretera o acotamiento, coloque los dispositivos de advertencia de emergencia dentro de los 10 minutos. Fuente: New Jersey MVC CDL Manual, Sec. 2 (Conducir con Seguridad)."},"66":{"q":"En una carretera de Nueva Jersey de dos carriles con tránsito en ambos sentidos, ¿dónde deben colocarse los triángulos de advertencia de un CMV detenido?","options":["A no más de 10 pies del vehículo, y a 100 pies por detrás y por delante de él","A 100 pies y 200 pies por detrás del vehículo únicamente","A no más de 25 pies del vehículo, y a 200 pies por detrás de él","A 10 pies, 100 pies y 200 pies por detrás del vehículo únicamente"],"explanation":"El Manual de CDL de Nueva Jersey indica que, en una carretera de dos carriles con tránsito en ambos sentidos, se coloque un triángulo a no más de 10 pies de las esquinas delanteras o traseras y otros a 100 pies por detrás y por delante del vehículo. Fuente: New Jersey MVC CDL Manual, Sec. 2 (Conducir con Seguridad)."},"67":{"q":"A los vehículos comerciales con un peso bruto registrado superior a 10,000 libras se les prohíbe usar la Garden State Parkway al norte de qué intercambiador (interchange)?","options":["Intercambiador 105","Intercambiador 80","Intercambiador 142","Intercambiador 9"],"explanation":"A los vehículos comerciales registrados con más de 10,000 lbs se les prohíbe circular por la Garden State Parkway al norte del Intercambiador 105 (con excepciones limitadas para autobuses, vehículos con permiso y vehículos de la autoridad). Fuente: reglamentos de la Parkway de la NJ Turnpike Authority; N.J.A.C. 19:9-1.9."},"68":{"q":"En la sección \"dual-dual\" (doble-doble) de la New Jersey Turnpike, ¿qué es cierto sobre la calzada interior entre la bifurcación sur y la incorporación norte?","options":["Está restringida solo a automóviles, mientras que la calzada exterior admite automóviles y camiones","Está restringida solo a camiones, mientras que la calzada exterior admite solo automóviles","Está reservada exclusivamente para autobuses y vehículos de emergencia","Lleva tránsito únicamente en dirección norte, sin importar el tipo de vehículo"],"explanation":"En la configuración dual-dual de la New Jersey Turnpike, la calzada interior está designada solo para automóviles, mientras que la calzada exterior admite tanto automóviles como camiones; los camiones y autobuses son dirigidos a los carriles exteriores. Fuente: NJ Turnpike Authority; New Jersey MVC."},"69":{"q":"Según el estatuto de Nueva Jersey que obliga a mantenerse a la derecha, en una autopista de varios carriles, un conductor que no esté rebasando ni preparándose para dar vuelta a la izquierda, ¿qué debe hacer?","options":["Permanecer en el carril de la extrema derecha disponible para el tránsito","Usar el carril central en todo momento","Usar el carril que tenga menos tránsito","Permanecer en el carril de la extrema izquierda para dejar la derecha libre para los camiones"],"explanation":"N.J.S.A. 39:4-82 exige que los conductores se mantengan a la derecha y conduzcan por el carril de la extrema derecha, excepto cuando rebasen o se preparen para dar vuelta a la izquierda; las sanciones se establecen en N.J.S.A. 39:4-88.1. Fuente: N.J.S.A. 39:4-82, 39:4-88.1."},"70":{"q":"Según los reglamentos de Nueva Jersey, ¿cuándo puede un camión de más de cinco toneladas circular por el carril izquierdo de una autopista dividida de varios carriles?","options":["Solo para entrar o salir de la calzada, en una emergencia, o cuando se encuentre dentro de una milla de una vuelta a la izquierda","En cualquier momento que esté rebasando a un vehículo más lento","Solo entre la medianoche y las 6 a.m.","En cualquier momento que el tránsito en el carril derecho sea intenso"],"explanation":"Nueva Jersey restringe a los camiones de más de cinco toneladas en autopistas divididas a los carriles de la derecha, permitiéndoles el carril izquierdo solo para entrar o salir de la calzada, en una emergencia, o cuando se encuentren dentro de una milla de una vuelta a la izquierda. Fuente: reglas de mantenerse a la derecha de NJ; N.J.S.A. 39:4-82 y disposiciones relacionadas del Título 39."},"71":{"q":"Según N.J.S.A. 39:4-98.1, el Comisionado de Transporte puede establecer un límite máximo de velocidad más bajo para camiones de 10,000 libras o más de peso registrado, con un diferencial de cuánto por debajo del límite indicado en las carreteras estatales de varios carriles que califiquen?","options":["5 mph","10 mph","15 mph","20 mph"],"explanation":"N.J.S.A. 39:4-98.1 autoriza un límite de velocidad más bajo señalizado para camiones con un diferencial de 5 mph, para camiones de 10,000 lbs o más, en carreteras estatales de cuatro o más carriles donde el límite sea de 50 mph o más. Fuente: N.J.S.A. 39:4-98.1."},"72":{"q":"Según el estatuto general de velocidad de Nueva Jersey, en ausencia de un límite señalizado, ¿cuál es el límite de velocidad legal para \"todos los demás lugares\" (que no sean zonas comerciales, residenciales o escolares)?","options":["50 mph","55 mph","65 mph","45 mph"],"explanation":"N.J.S.A. 39:4-98 establece límites prima facie de 25 mph en distritos comerciales/residenciales, 35 mph en ciertos distritos suburbanos y 50 mph en todos los demás lugares, a menos que se señalice un límite distinto. Fuente: N.J.S.A. 39:4-98."},"73":{"q":"Al cruzar las vías del tren en un CMV de Nueva Jersey después de una parada obligatoria, ¿qué NO debe hacer el conductor?","options":["Cambiar de velocidad (marcha) mientras cualquier parte del vehículo esté sobre las vías","Usar las luces intermitentes de emergencia de cuatro direcciones mientras se aproxima","Mirar y escuchar en ambas direcciones para detectar un tren","Bajar la ventanilla antes de cruzar"],"explanation":"El Manual de CDL de Nueva Jersey indica a los conductores que no cambien de velocidad (marcha) mientras cruzan las vías del tren, para que el vehículo no se quede sin avanzar sobre el cruce. Fuente: New Jersey MVC CDL Manual, Secs. 2.15 y 9.6.12."},"74":{"q":"Un conductor de autobús de Nueva Jersey NO está obligado a detenerse en un cruce ferroviario en cuál de las siguientes situaciones?","options":["El cruce está señalizado como \"exento\" (exempt) o \"abandonado\" (abandoned)","El cruce tiene una cruz de San Andrés (crossbuck) pero no barrera","El cruce tiene dos juegos de vías","El cruce está en una zona rural sin señales"],"explanation":"El Manual de CDL de Nueva Jersey enumera excepciones al requisito de parada del autobús, incluyendo cuando un oficial de policía o señalero dirige el tránsito, cuando un semáforo está en verde, y en cruces señalizados como \"exento\" (exempt) o \"abandonado\" (abandoned). Fuente: New Jersey MVC CDL Manual, Sec. 4.3.5."},"75":{"q":"En Nueva Jersey, en un cruce ferroviario con una cruz de San Andrés (crossbuck) pero sin una línea de alto blanca pintada en el pavimento, los vehículos obligados a detenerse deben hacerlo dentro de qué rango del riel más cercano?","options":["No más cerca de 15 pies y no más lejos de 50 pies","No más cerca de 10 pies y no más lejos de 30 pies","No más cerca de 20 pies y no más lejos de 60 pies","No más cerca de 25 pies y no más lejos de 100 pies"],"explanation":"El Manual de CDL de Nueva Jersey indica que, donde no haya una línea de alto blanca pintada, los vehículos obligados a detenerse deben hacerlo no más cerca de 15 pies y no más de 50 pies del riel más cercano. Fuente: New Jersey MVC CDL Manual, Sec. 2.15."},"76":{"q":"Sin un permiso de sobredimensión, ¿cuál es el ancho máximo legal de un vehículo en las carreteras de Nueva Jersey?","options":["8 pies 6 pulgadas","8 pies 0 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"El ancho máximo legal de Nueva Jersey es de 8 pies 6 pulgadas (102 inches); las cargas que excedan esto requieren un permiso de sobredimensión del NJDOT. La altura legal estándar es de 13 pies 6 pulgadas y el peso bruto es de 80,000 lbs. Fuente: reglamentos de tamaño/peso de Vehículos Comerciales del NJDOT; Título 39."},"77":{"q":"Un autobús escolar se queda inmovilizado sobre un cruce a nivel entre vía férrea y carretera en Nueva Jersey. Según el Manual de CDL de Nueva Jersey, ¿qué debe hacer primero el conductor?","options":["Evacuar a los estudiantes y guiarlos al menos a 100 pies de las vías, en ángulo hacia cualquier tren que se aproxime","Mantener a los estudiantes sentados e intentar volver a arrancar el motor mientras está sobre el cruce","Hacer que los estudiantes se acuesten en el piso del autobús hasta que llegue ayuda","Bajar del autobús y correr por las vías para hacer señales al tren"],"explanation":"El Manual de CDL de Nueva Jersey (sección de Autobuses Escolares) indica al conductor que evacúe de inmediato y guíe a los estudiantes a un lugar seguro al menos a 100 pies de las vías, alejándose hacia y en ángulo respecto a un tren que se aproxime, para que no sean golpeados por escombros. Fuente: New Jersey MVC CDL Manual, Sec. 10 (Autobuses Escolares)."},"78":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Nueva Jersey?","options":["La New Jersey Motor Vehicle Commission (MVC)","El New Jersey Department of Transportation (NJDOT)","La Oficina Comercial de la Policía Estatal de Nueva Jersey","La Motor Carrier Safety Administration (FMCSA) federal"],"explanation":"En Nueva Jersey, las CDL son emitidas por la New Jersey Motor Vehicle Commission (MVC). El NJDOT se encarga de las carreteras y de los permisos de sobredimensión/sobrepeso, y la FMCSA establece las normas federales pero no emite la licencia. Fuente: New Jersey MVC, Getting your Commercial Driver License (nj.gov/mvc/drivertopics/gettingcdl.htm)."},"79":{"q":"Antes de que un solicitante primerizo de Nueva Jersey pueda presentar el examen para una CDL, ¿cuántos puntos de identificación debe presentar a la MVC?","options":["6 puntos de identificación","4 puntos de identificación","8 puntos de identificación","2 puntos de identificación"],"explanation":"Nueva Jersey utiliza un programa de verificación de 6 Puntos de Identificación; los solicitantes de CDL deben acreditar seis puntos de identificación (incluyendo comprobante del número de Seguro Social, domicilio y presencia legal). Fuente: New Jersey MVC, Getting your Commercial Driver License y el programa 6 Points of ID de la New Jersey MVC."},"80":{"q":"¿Cuál es la edad mínima para obtener una CDL de Nueva Jersey para operación INTRAESTATAL (únicamente dentro de Nueva Jersey)?","options":["18 años","21 años","19 años","20 años"],"explanation":"Una persona debe tener al menos 18 años para obtener una CDL de NJ para conducción intraestatal; los conductores menores de 21 años están restringidos a la operación intraestatal y deben autocertificarse en la categoría de comercio 3 o 4. La operación interestatal requiere tener 21 años. Fuente: New Jersey MVC, Getting your Commercial Driver License y Commercial Learner Permits (CLP)."},"81":{"q":"Un titular de CDL de Nueva Jersey de 20 años está limitado a qué tipo de operación?","options":["Solo intraestatal (dentro de Nueva Jersey)","Solo interestatal (a través de las fronteras estatales)","Tanto interestatal como intraestatal","Solo transporte de materiales peligrosos"],"explanation":"Los conductores menores de 21 años solo pueden operar en el comercio intraestatal (dentro de Nueva Jersey) y deben seleccionar la categoría de comercio de autocertificación 3 o 4. La operación interestatal no se permite hasta los 21 años. Fuente: New Jersey MVC, Commercial Learner Permits (CLP)."},"82":{"q":"¿Qué capacitación debe completar un solicitante de Nueva Jersey antes de presentar por primera vez el examen de habilidades (skills test) de la CDL?","options":["Capacitación para Conductores Principiantes (ELDT) de un proveedor del Training Provider Registry de la FMCSA","Un curso estatal de manejo defensivo en una agencia de la MVC","Una certificación de seguridad comercial de OSHA de 40 horas","Una clase de manejo de cargas de sobredimensión aprobada por el NJDOT"],"explanation":"A partir del 7 de febrero de 2022, los solicitantes deben completar la Capacitación para Conductores Principiantes (ELDT) de un proveedor incluido en el Training Provider Registry de la FMCSA antes de presentar el examen de habilidades de la CDL (y antes del examen de conocimientos de HazMat). Fuente: New Jersey MVC, Getting your Commercial Driver License; regla ELDT de la FMCSA (49 CFR Part 380)."},"83":{"q":"La autocertificación de la CDL de Nueva Jersey tiene cuántas categorías de comercio entre las que debe elegir un solicitante?","options":["4 categorías","2 categorías","3 categorías","5 categorías"],"explanation":"Hay cuatro categorías de comercio de autocertificación: (1) interestatal no exento, (2) interestatal exento, (3) intraestatal no exento e (4) intraestatal exento. El solicitante debe seleccionar una. Fuente: New Jersey MVC, CDL Self-Certification and Medical Examiner Certificate (cdlmedcert.htm)."},"84":{"q":"¿Cuáles categorías de autocertificación EXIGEN que un titular de CDL tenga un Certificado del Examinador Médico (Medical Examiner's Certificate) vigente en sus registros en Nueva Jersey?","options":["Interestatal no exento (1) e intraestatal no exento (3)","Interestatal exento (2) e intraestatal exento (4)","Interestatal no exento (1) e interestatal exento (2)","Solo interestatal no exento (1)"],"explanation":"Las categorías \"no exentas\" (1 y 3) exigen un Certificado del Examinador Médico vigente. Las categorías \"exentas\" (2 y 4) no requieren uno, a menos que el conductor tenga un endoso de pasajeros (P) o de autobús escolar (S). Fuente: New Jersey MVC, CDL Self-Certification and Medical Examiner Certificate."},"85":{"q":"¿Cómo llega normalmente a la New Jersey MVC el certificado del examinador médico de un conductor según las reglas actuales?","options":["De forma electrónica, transmitido desde el National Registry de la FMCSA a la agencia estatal de licencias","El conductor envía por correo una copia en papel notariada a la sede del NJDOT","El empleador del conductor lo presenta ante la Policía Estatal de Nueva Jersey","La empresa de transporte lo envía por fax a la agencia local de la MVC"],"explanation":"Los examinadores médicos envían electrónicamente los resultados del examen al National Registry de la FMCSA, y la certificación se transmite electrónicamente a la State Driver Licensing Agency (New Jersey MVC); no se requiere un certificado en papel (Formulario MCSA-5876) como comprobante. Fuente: New Jersey MVC, CDL Self-Certification and Medical Examiner Certificate."},"86":{"q":"¿Quién está autorizado para realizar el examen físico para el Certificado del Examinador Médico de un titular de CDL?","options":["Un examinador médico incluido en el National Registry of Certified Medical Examiners de la FMCSA","Cualquier médico con licencia de Nueva Jersey, sin importar su estatus en el registro","Un enfermero en una agencia de licencias de la MVC","Un oficial de salud ocupacional empleado por el NJDOT"],"explanation":"El examen debe ser realizado por un examinador médico certificado a nivel federal e incluido en el National Registry of Certified Medical Examiners de la FMCSA; ese examinador envía los resultados de forma electrónica. Fuente: New Jersey MVC, CDL Self-Certification and Medical Examiner Certificate."},"87":{"q":"¿Qué recibe un solicitante de Nueva Jersey después de aprobar el o los exámenes de conocimientos de la CDL?","options":["Un Permiso de Aprendiz Comercial (CLP)","Una Licencia de Conducir Comercial (CDL) completa","Una tarjeta temporal de endoso de HazMat","Un certificado de exención del examen de habilidades"],"explanation":"Aprobar el o los exámenes de conocimientos requeridos califica al solicitante para un Permiso de Aprendiz Comercial (CLP), que permite practicar bajo supervisión antes del examen de habilidades. La CDL se emite únicamente después de aprobar el examen de habilidades. Fuente: New Jersey MVC, Getting your Commercial Driver License y Commercial Learner Permits (CLP)."},"88":{"q":"¿Qué porcentaje mínimo debe obtener un solicitante para aprobar un examen de conocimientos de la CDL de Nueva Jersey?","options":["80%","70%","75%","90%"],"explanation":"Cada solicitante debe responder correctamente al menos el 80% de las preguntas para aprobar un examen de conocimientos de la CDL en Nueva Jersey. Fuente: New Jersey MVC, CDL Tests (cdltest.htm)."},"89":{"q":"El examen general de conocimientos de la CDL en Nueva Jersey consta de cuántas preguntas?","options":["50 preguntas","30 preguntas","100 preguntas","25 preguntas"],"explanation":"El examen de conocimientos de la CDL incluye un examen general de 50 preguntas, además de exámenes adicionales por separado para cada endoso que se solicite. Fuente: New Jersey MVC, CDL Tests (cdltest.htm)."},"90":{"q":"¿Cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Nueva Jersey después de emitido?","options":["180 días","90 días","1 año","60 días"],"explanation":"Un CLP de Nueva Jersey es válido por 180 días a partir de su emisión. Fuente: New Jersey MVC, Commercial Learner Permits (CLP) (cdlclp.htm)."},"91":{"q":"¿Cuántas veces se puede renovar un Permiso de Aprendiz Comercial (CLP) de Nueva Jersey?","options":["Una vez","No se puede renovar","Dos veces","Un número ilimitado de veces"],"explanation":"Un CLP de NJ es válido por 180 días y solo se puede renovar una vez (por un período adicional) sin volver a presentar los exámenes de conocimientos. Fuente: New Jersey MVC, Commercial Learner Permits (CLP)."},"92":{"q":"Después de que se emite un CLP de Nueva Jersey, ¿cuál es el tiempo mínimo que un conductor debe tenerlo antes de presentar el examen de habilidades de la CDL?","options":["14 días","30 días","7 días","10 días"],"explanation":"El titular de un CLP debe esperar un mínimo de 14 días después de que se emite el permiso antes de presentar el examen de habilidades (de manejo en carretera) de la CDL. Fuente: New Jersey MVC, Getting your Commercial Driver License; regla federal de CLP (49 CFR 383.25)."},"93":{"q":"El examen de habilidades de la CDL de Nueva Jersey se compone de cuáles tres partes, en orden?","options":["Inspección previa al viaje, control básico del vehículo y conducción en carretera","Conocimientos por escrito, examen de la vista y conducción en carretera","Verificación de frenos de aire, estacionamiento en paralelo e incorporación a la autopista","Examen de acoplamiento, examen de reversa y manejo de HazMat"],"explanation":"El examen de habilidades (de manejo en carretera) de la CDL tiene tres partes que se realizan en secuencia: la inspección previa al viaje, el examen de habilidades de control básico del vehículo y el examen de conducción en carretera. Fuente: New Jersey MVC, CDL Tests (cdltest.htm)."},"94":{"q":"Durante la parte de inspección previa al viaje del examen de habilidades de Nueva Jersey, ¿qué debe demostrar que es capaz de hacer el solicitante?","options":["Identificar y explicar los componentes que deben inspeccionarse y por qué","Reparar una cámara de freno de aire averiada en menos de cinco minutos","Recitar todo el manual de la CDL de memoria","Desarmar y volver a armar la quinta rueda"],"explanation":"En el examen de inspección previa al viaje, el solicitante debe demostrar que puede identificar cada componente que debe inspeccionarse y explicar por qué se revisa, comprobando que el vehículo es seguro para conducir. Fuente: New Jersey MVC, CDL Tests (cdltest.htm)."},"95":{"q":"Para el examen de habilidades, el solicitante debe proporcionar un vehículo motorizado comercial representativo que cumpla con cuál condición?","options":["Inspección vigente, registro y seguro válidos, y sin carga ni materiales peligrosos","Un vehículo cargado hasta su capacidad máxima de peso bruto","Un vehículo de no más de dos años de antigüedad","Un vehículo propiedad únicamente de un transportista (motor carrier) con licencia"],"explanation":"Los solicitantes deben proporcionar un CMV apropiado y representativo de la clase solicitada, con inspección vigente, registro y seguro válidos, GVWR/placas adecuadas, y sin carga ni materiales peligrosos a bordo. Fuente: New Jersey MVC, CDL Tests (cdltest.htm)."},"96":{"q":"¿Con qué frecuencia debe renovarse una CDL de Nueva Jersey?","options":["Cada 4 años","Cada 2 años","Cada 5 años","Cada 8 años"],"explanation":"Una CDL estándar de Nueva Jersey se emite por un período de cuatro años y debe renovarse cada 4 años (una primera CDL puede prorratearse para coincidir con el vencimiento de la licencia básica). Fuente: New Jersey MVC, Getting your Commercial Driver License (gettingcdl.htm)."},"97":{"q":"¿Cuál afirmación sobre la renovación de una CDL de Nueva Jersey es correcta?","options":["Debe renovarse en persona en una agencia de la MVC, no en línea ni por correo","Se puede renovar por completo en línea, igual que una licencia básica Clase D","Se puede renovar por correo solo si no se tienen endosos","Se renueva automáticamente sin que el conductor tenga que hacer nada"],"explanation":"A diferencia de una licencia de conducir básica, una CDL de Nueva Jersey no se puede renovar en línea ni por correo; el titular debe renovarla en persona en una agencia de la MVC y presentar los documentos requeridos y el estatus vigente de su certificación médica. Nota: las tarifas exactas pueden cambiar, así que confirme los montos actuales con la MVC. Fuente: orientación de renovación de CDL de la New Jersey MVC."}},"hi":{"0":{"q":"न्यू जर्सी के राजमार्गों पर, किसी वाहन या वाहनों के संयोजन की, उसके भार सहित, अधिकतम ऊँचाई कितनी होती है?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","14 feet 6 inches"],"explanation":"न्यू जर्सी कानून (N.J.S.A. 39:3-84) के अनुसार, किसी भी वाहन या संयोजन की, भार या सामग्री सहित, अधिकतम ऊँचाई सभी राजमार्गों पर 13 feet 6 inches निर्धारित है। (स्रोत: N.J.S.A. 39:3-84; NJDOT Commercial Vehicle Size and Weight Guidebook.)"},"1":{"q":"बिना ओवरवेट परमिट के न्यू जर्सी के राजमार्गों पर किसी वाहन का अधिकतम कुल सकल वजन कितना अनुमत है?","options":["80,000 pounds","73,280 pounds","88,000 pounds","76,000 pounds"],"explanation":"न्यू जर्सी अधिकतम कुल सकल वाहन वजन को 80,000 pounds पर सीमित करता है, जो संघीय सीमा के अनुरूप है (N.J.S.A. 39:3-84)। किसी अविभाज्य (non-divisible) भार पर इससे अधिक कुछ भी होने पर ओवरवेट परमिट आवश्यक होता है। (स्रोत: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"2":{"q":"न्यू जर्सी की अधिकांश सड़कों पर जो निर्धारित 102-inch या National Network का हिस्सा नहीं हैं, अधिकतम कानूनी वाहन चौड़ाई कितनी है?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","90 inches (7 feet 6 inches)"],"explanation":"जबकि निर्धारित National Network और न्यू जर्सी का 102-inch ट्रक नेटवर्क 102 inches (8'6\") की अनुमति देते हैं, अन्य सार्वजनिक सड़कें 96 inches (8 feet) तक सीमित हैं। (स्रोत: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)"},"3":{"q":"न्यू जर्सी के निर्धारित National Network और 102-inch ट्रक रूट नेटवर्क पर ट्रकों के लिए, भार सहित, अधिकतम अनुमत चौड़ाई कितनी है?","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","120 inches (10 feet)","114 inches (9 feet 6 inches)"],"explanation":"निर्धारित National Network और न्यू जर्सी के 102-inch ट्रक रूट नेटवर्क पर, N.J.S.A. 39:3-84 के अनुसार अधिकतम बाहरी चौड़ाई 102 inches (8 feet 6 inches) है। (स्रोत: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"4":{"q":"न्यू जर्सी कानून के तहत, किसी भी एकल धुरी (single axle) पर ले जाया जा सकने वाला अधिकतम सकल वजन कितना है?","options":["22,400 pounds","20,000 pounds","34,000 pounds","24,000 pounds"],"explanation":"न्यू जर्सी एकल धुरी पर 22,400 pounds तक की अनुमति देता है, जो बुनियादी संघीय 20,000-pound एकल-धुरी आँकड़े से अधिक है (N.J.S.A. 39:3-84)। (स्रोत: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)"},"5":{"q":"न्यू जर्सी के राजमार्गों पर एक टैंडम धुरी समूह (tandem axle group) पर अनुमत अधिकतम सकल वजन कितना है?","options":["34,000 pounds","22,400 pounds","40,000 pounds","36,000 pounds"],"explanation":"न्यू जर्सी एक टैंडम धुरी समूह को 34,000 pounds तक सीमित करता है, जो संघीय मानक के समान है (N.J.S.A. 39:3-84)। (स्रोत: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"6":{"q":"किसी अविभाज्य भार को न ले जाते समय न्यू जर्सी के राजमार्गों पर एकल (सीधे) ट्रक की अधिकतम कुल लंबाई कितनी होती है?","options":["40 feet","35 feet","45 feet","53 feet"],"explanation":"N.J.S.A. 39:3-84 एकल वाहन की कुल लंबाई को 40 feet तक सीमित करता है (केवल तभी 50 feet तक बढ़ाया जाता है जब खंभे, पाइलिंग, या अन्य ऐसी वस्तुएँ ले जाई जा रही हों जिन्हें विभाजित नहीं किया जा सकता)। (स्रोत: N.J.S.A. 39:3-84.)"},"7":{"q":"न्यू जर्सी कानून के तहत, सामान्य राजमार्गों पर एक ट्रक-ट्रैक्टर और सेमीट्रेलर संयोजन (पावर यूनिट और उसका भार) की अधिकतम कुल लंबाई कितनी होती है?","options":["62 feet","53 feet","65 feet","75 feet"],"explanation":"N.J.S.A. 39:3-84 वाहनों के संयोजन की कुल लंबाई, भार सहित, 62 feet निर्धारित करता है। ध्यान दें कि National Network पर ट्रैक्टर-सेमीट्रेलर पर इसके बजाय कोई कुल लंबाई सीमा नहीं होती, जबकि सेमीट्रेलर स्वयं 53 feet पर सीमित होता है। (स्रोत: N.J.S.A. 39:3-84; NJDOT Size and Weight Guidebook.)"},"8":{"q":"न्यू जर्सी के National Network और निर्धारित 102-inch रूटों पर, ट्रैक्टर-सेमीट्रेलर संयोजन में संचालित होने वाले सेमीट्रेलर की अधिकतम लंबाई कितनी होती है?","options":["53 feet","48 feet","57 feet","45 feet"],"explanation":"NJDOT नियमों और N.J.S.A. 39:3-84 के अनुसार, एक सेमीट्रेलर National Network और NJ 102-inch नेटवर्क पर 53 feet तक हो सकता है (अन्य राजमार्गों पर 48 feet)। (स्रोत: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)"},"9":{"q":"न्यू जर्सी के निर्धारित नेटवर्क पर संचालित होने वाले 48-से-53-feet सेमीट्रेलर के लिए, किंगपिन से पिछली धुरी के केंद्र तक की अधिकतम अनुमत दूरी कितनी होती है?","options":["41 feet","37 feet","46 feet","53 feet"],"explanation":"48 feet से अधिक और 53 feet तक के ट्रेलरों के लिए, इंटरस्टेट/निर्धारित नेटवर्क पर किंगपिन-से-पिछली-धुरी-के-केंद्र की दूरी 41 feet से अधिक नहीं हो सकती। (स्रोत: NJDOT Commercial Vehicle Size and Weight Guidebook; J.J. Keller Compliance Network.)"},"10":{"q":"न्यू जर्सी के निर्धारित नेटवर्क पर संचालित होने वाले ट्विन-ट्रेलर (डबल) संयोजन में, प्रत्येक ट्रेलिंग यूनिट की अधिकतम लंबाई कितनी होती है?","options":["28 feet","33 feet","40 feet","53 feet"],"explanation":"न्यू जर्सी के ट्विन-ट्रेलर संयोजन में प्रत्येक ट्रेलर 28 feet तक सीमित है, जो N.J.S.A. 39:3-84 के तहत मान्यता प्राप्त संघीय STAA डबल मानक के अनुरूप है। (स्रोत: N.J.S.A. 39:3-84; J.J. Keller Compliance Network.)"},"11":{"q":"न्यू जर्सी टायर की चौड़ाई के प्रति इंच कितना अधिकतम सकल भार अनुमत करता है?","options":["800 pounds","650 pounds","500 pounds","1,000 pounds"],"explanation":"न्यू जर्सी भार को टायर की चौड़ाई के प्रति इंच 800 pounds तक सीमित करता है (N.J.S.A. 39:3-84)। (स्रोत: N.J.S.A. 39:3-84; J.J. Keller Compliance Network, NJ Size/Weight Limits.)"},"12":{"q":"न्यू जर्सी में उपयोग किया जाने वाला संघीय ब्रिज फॉर्मूला, W = 500[LN/(N-1) + 12N + 36], किस मान को निर्धारित करता है?","options":["लगातार धुरियों के समूह पर उनके अंतराल और संख्या के आधार पर अनुमत अधिकतम सकल वजन","वाहन की उसके व्हीलबेस के आधार पर अधिकतम ऊँचाई","टायरों की संख्या के आधार पर अधिकतम चौड़ाई","लदे हुए संयोजन के लिए आवश्यक न्यूनतम रुकने की दूरी"],"explanation":"न्यू जर्सी में लागू Federal Bridge Formula किसी भी दो या अधिक लगातार धुरियों के समूह पर अनुमत अधिकतम सकल वजन (W) की गणना करता है, जहाँ L बाहरी धुरियों के बीच का अंतराल है और N धुरियों की संख्या है। (स्रोत: 23 CFR 658 / NJDOT द्वारा लागू Federal Bridge Formula; NJDOT Size and Weight Guidebook.)"},"13":{"q":"न्यू जर्सी में उपयोग किए जाने वाले संघीय ब्रिज फॉर्मूले में, चर 'L' किसका प्रतिनिधित्व करता है?","options":["धुरी समूह की बाहरी धुरियों के बीच की दूरी feet में","ट्रेलर की कुल लंबाई","कानूनी भार सीमा pounds में","लिफ्ट-धुरी वजन भत्ता"],"explanation":"W = 500[LN/(N-1) + 12N + 36] में, 'L' विचाराधीन समूह की सबसे बाहरी धुरियों के बीच की दूरी feet में है, और 'N' उस समूह में धुरियों की संख्या है। (स्रोत: Federal Bridge Formula, 23 CFR 658, NJDOT द्वारा लागू।)"},"14":{"q":"कानूनी आकार या वजन सीमाओं से अधिक भार के लिए न्यू जर्सी oversize/overweight (OS/OW) परमिट कब जारी किया जाता है?","options":["केवल तब जब भार अविभाज्य (non-divisible) हो (कानूनी सीमाओं को पूरा करने के लिए जिसे अलग या विभाजित नहीं किया जा सकता)","किसी भी भार के लिए, चाहे विभाज्य हो या न हो, बशर्ते शुल्क का भुगतान किया जाए","केवल कृषि उपज के भार के लिए","केवल सप्ताहांत और छुट्टियों पर"],"explanation":"NJDOT OS/OW परमिट केवल अविभाज्य भार के लिए जारी करता है, जिसे ऐसे भार के रूप में परिभाषित किया गया है जिसे वजन और आयाम सीमाओं को पूरा करने के लिए विभाजित, अलग, या तोड़ा नहीं जा सकता। (स्रोत: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)"},"15":{"q":"न्यू जर्सी में एक कैरियर oversize/overweight ढुलाई परमिट के लिए कैसे आवेदन करता है?","options":["NJDOT की OS/OW परमिट वेबसाइट (nj.gotpermits.com) के माध्यम से 24/7 ऑनलाइन","केवल व्यावसायिक घंटों के दौरान काउंटी क्लर्क के कार्यालय में व्यक्तिगत रूप से","State Police को एक नोटरीकृत फॉर्म डाक से भेजकर","CDL जारी होने के साथ स्वचालित रूप से"],"explanation":"कैरियर NJDOT OS/OW परमिट के लिए NJDOT OS/OW परमिट वेबसाइट (nj.gotpermits.com) पर दिन में 24 घंटे, सप्ताह में 7 दिन, सीधे या किसी पंजीकृत परमिट सेवा के माध्यम से ऑनलाइन आवेदन कर सकते हैं। (स्रोत: NJDOT OS/OW Permit Reference Guide; nj.gotpermits.com.)"},"16":{"q":"किसी परमिटेड ओवरसाइज़ मूव के लिए न्यू जर्सी किस भार चौड़ाई (भार सहित) पर कम से कम एक एस्कॉर्ट वाहन की आवश्यकता रखता है?","options":["जब चौड़ाई 14 feet से अधिक हो","जब चौड़ाई 10 feet से अधिक हो","जब चौड़ाई 8 feet 6 inches से अधिक हो","जब चौड़ाई 16 feet से अधिक हो"],"explanation":"NJDOT परमिट नियमों के तहत, जब भार सहित चौड़ाई 14 feet से अधिक हो तो एक एस्कॉर्ट वाहन आवश्यक है; जब चौड़ाई 16 feet से अधिक हो तो दो एस्कॉर्ट आवश्यक हैं। (स्रोत: NJDOT OS/OW Permit Reference Guide; oversize.io NJ regulations.)"},"17":{"q":"एक कैरियर न्यू जर्सी राज्य राजमार्ग पर एक ट्रैक्टर-सेमीट्रेलर पर मशीनरी का एकल, अविभाज्य टुकड़ा ले जाना चाहता है जो 110,000 pounds सकल और 12 feet चौड़ा होगा। कैरियर को क्या करना चाहिए?","options":["मूव से पहले NJDOT oversize/overweight परमिट प्राप्त करना, क्योंकि वजन और चौड़ाई दोनों कानूनी सीमाओं से अधिक हैं","कुछ नहीं, क्योंकि अविभाज्य भार स्वचालित रूप से सभी सीमाओं से छूट प्राप्त हैं","छूट पाने के लिए केवल वाहन को कृषि के रूप में पंजीकृत करना","बिना किसी परमिट के केवल रात में यात्रा करना"],"explanation":"भार 80,000-pound सकल सीमा और 102-inch (8'6\") चौड़ाई सीमा से अधिक है, इसलिए यात्रा से पहले इस अविभाज्य भार के लिए NJDOT OS/OW परमिट आवश्यक है, जो nj.gotpermits.com के माध्यम से प्राप्त किया जाता है। 12-foot चौड़ाई 14-foot एस्कॉर्ट सीमा से नीचे है। (स्रोत: N.J.S.A. 39:3-84; NJDOT OS/OW Permit Reference Guide.)"},"18":{"q":"न्यू जर्सी में, 26,001 या अधिक pounds की सकल संयोजन वजन रेटिंग (GCWR) वाले संयोजन वाहन को चलाने के लिए कौन सी CDL श्रेणी आवश्यक है, जहाँ खींची जाने वाली यूनिट का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"NJ CDL Manual Class A को वाहनों के किसी भी ऐसे संयोजन के रूप में परिभाषित करता है जिसका GCWR 26,001 या अधिक pounds हो, बशर्ते खींची जाने वाली यूनिट(यों) का GVWR 10,000 pounds से अधिक हो। स्रोत: NJ MVC Commercial Driver License Manual (Class definitions)।"},"19":{"q":"न्यू जर्सी नियमों के तहत, 26,001 या अधिक pounds GVWR वाला एकल वाहन, या ऐसा वाहन जो 10,000 pounds GVWR से अधिक नहीं वाली यूनिट को खींच रहा हो, किस CDL श्रेणी की आवश्यकता रखता है?","options":["Class A","Class B","Class C","Class E"],"explanation":"NJ CDL Manual Class B को किसी भी ऐसे एकल वाहन के रूप में परिभाषित करता है जिसका GVWR 26,001 या अधिक pounds हो, या ऐसा वाहन जो ऐसी यूनिट को खींच रहा हो जिसका GVWR 10,000 pounds या उससे कम हो। स्रोत: NJ MVC Commercial Driver License Manual।"},"20":{"q":"न्यू जर्सी में, 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया वाहन, या प्लेकार्डेड खतरनाक सामग्री ले जाने वाला छोटा वाहन, कम से कम किस CDL श्रेणी की आवश्यकता रखता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"NJ CDL Manual Class C को ऐसे वाहन के रूप में परिभाषित करता है जो Class A या B के मानदंडों को पूरा नहीं करता लेकिन चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है, या प्लेकार्डिंग की आवश्यकता वाली खतरनाक सामग्री ले जाने के लिए उपयोग किया जाता है। स्रोत: NJ MVC Commercial Driver License Manual।"},"21":{"q":"एक न्यू जर्सी वाहन चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है लेकिन उसका वजन 26,001 pounds से कम है। आवश्यक न्यूनतम CDL श्रेणी क्या है?","options":["कोई CDL आवश्यक नहीं","Class A","Class B","Class C"],"explanation":"Class A या B के लिए वजन सीमाओं से कम होने पर भी, चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किया गया वाहन न्यू जर्सी में Class C में आता है। स्रोत: NJ MVC Commercial Driver License Manual (Class C definition)।"},"22":{"q":"स्थायी रूप से लगे टैंक में थोक में तरल पदार्थ या गैसों का परिवहन करने वाले वाहन को चलाने के लिए न्यू जर्सी CDL धारक को किस एंडोर्समेंट की आवश्यकता होती है?","options":["N (Tank Vehicle)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"explanation":"थोक में तरल पदार्थ या गैसों का परिवहन करने वाले वाहनों को चलाने के लिए न्यू जर्सी में N (Tank Vehicle) एंडोर्समेंट आवश्यक है। स्रोत: NJ MVC Endorsements page।"},"23":{"q":"न्यू जर्सी में, दो या तीन ट्रेलरों को खींचने के लिए कौन सा एंडोर्समेंट आवश्यक है, और चालक को कौन सी श्रेणी का CDL धारण करना चाहिए?","options":["T एंडोर्समेंट, Class A CDL के साथ","N एंडोर्समेंट, Class B CDL के साथ","T एंडोर्समेंट, Class C CDL के साथ","P एंडोर्समेंट, Class A CDL के साथ"],"explanation":"दो या तीन ट्रेलरों को खींचने के लिए T (Doubles/Triples) एंडोर्समेंट आवश्यक है, और इसे धारण करने के लिए Class A CDL की आवश्यकता होती है। स्रोत: NJ MVC Endorsements page।"},"24":{"q":"न्यू जर्सी द्वारा HazMat (H) एंडोर्समेंट जारी करने से पहले, आवेदक को किस एजेंसी द्वारा संचालित पृष्ठभूमि जाँच पास करनी होती है?","options":["The Transportation Security Administration (TSA)","The New Jersey MVC fraud unit","The Federal Motor Carrier Safety Administration (FMCSA)","केवल The New Jersey State Police"],"explanation":"न्यू जर्सी HazMat (H) एंडोर्समेंट के आवेदकों से एंडोर्समेंट जारी होने से पहले फिंगरप्रिंट लेने और Transportation Security Administration (TSA) के खतरा मूल्यांकन को पास करने की आवश्यकता रखता है। स्रोत: NJ MVC Hazardous Material Endorsements (HME) page; TSA HME program।"},"25":{"q":"न्यू जर्सी में स्कूल बस चलाने के लिए, CDL एंडोर्समेंट का कौन सा संयोजन आवश्यक है?","options":["P (Passenger) और S (School Bus) दोनों","केवल S (School Bus)","केवल P (Passenger)","S और H"],"explanation":"न्यू जर्सी स्कूल बस चालकों से P (Passenger) और S (School Bus) दोनों एंडोर्समेंट धारण करने, साथ ही एक ज्ञान और रोड टेस्ट तथा पृष्ठभूमि जाँच पास करने की आवश्यकता रखता है। स्रोत: NJ MVC Endorsements page।"},"26":{"q":"अंतरराज्यीय (intrastate, केवल न्यू जर्सी के भीतर) संचालन तक सीमित न्यू जर्सी CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 years old","21 years old","19 years old","17 years old"],"explanation":"एक चालक 18 वर्ष की आयु में न्यू जर्सी CDL प्राप्त कर सकता है, लेकिन 21 वर्ष की आयु तक संचालन अंतरराज्यीय वाणिज्य (न्यू जर्सी के भीतर) तक सीमित है। स्रोत: NJ MVC Getting Your CDL page।"},"27":{"q":"न्यू जर्सी CDL के साथ अंतरराज्यीय वाणिज्य (interstate commerce) में एक वाणिज्यिक मोटर वाहन चलाने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["21 years old","18 years old","23 years old","19 years old"],"explanation":"न्यू जर्सी CDL के साथ 21 वर्ष से कम आयु के चालक केवल अंतरराज्यीय (intrastate) संचालन कर सकते हैं; इंटरस्टेट वाणिज्य (और हैज़मैट) के लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: NJ MVC Getting Your CDL page।"},"28":{"q":"न्यू जर्सी में लागू संघीय नियमों के तहत, Commercial Learner Permit (CLP) धारक को CLP जारी होने के बाद CDL कौशल परीक्षण देने से पहले कितने समय तक प्रतीक्षा करनी होती है?","options":["A minimum of 14 days","A minimum of 30 days","A minimum of 7 days","A minimum of 60 days"],"explanation":"न्यू जर्सी संघीय आवश्यकता लागू करता है कि CLP धारक को कौशल परीक्षण देने से पहले कम से कम 14 days प्रतीक्षा करनी होती है। स्रोत: NJ MVC Getting Your CDL / CLP pages।"},"29":{"q":"जारी होने के बाद, एक न्यू जर्सी Commercial Learner Permit (CLP) कितने समय तक वैध रहता है?","options":["180 days","1 year","90 days","60 days"],"explanation":"जारी होने पर एक न्यू जर्सी CLP 180 days के लिए वैध होता है। स्रोत: NJ MVC Commercial Learner Permits (CLP) page।"},"30":{"q":"न्यू जर्सी Commercial Learner Permit पर एक वाणिज्यिक मोटर वाहन चलाते समय, चालक के पास और क्या होना चाहिए?","options":["एक वैध New Jersey driver's license","एक पासपोर्ट","एक दूसरा CLP","अतिरिक्त कुछ नहीं"],"explanation":"जब धारक एक CMV चलाता है तो एक न्यू जर्सी CLP के साथ एक वैध New Jersey driver's license होनी चाहिए। स्रोत: NJ MVC Commercial Learner Permits (CLP) page।"},"31":{"q":"न्यू जर्सी CDL आवेदकों से अपने पहचान सत्यापन मानक को पूरा करने के लिए कितने पहचान बिंदु प्रस्तुत करने की आवश्यकता रखता है?","options":["6 Points of ID","4 Points of ID","8 Points of ID","2 Points of ID"],"explanation":"न्यू जर्सी 6 Points of ID प्रणाली का उपयोग करता है, जिसमें ऐसे दस्तावेज़ आवश्यक होते हैं जो पहचान, Social Security नंबर, पते का प्रमाण, और अमेरिका में कानूनी उपस्थिति का प्रमाण स्थापित करें। स्रोत: NJ MVC Getting Your CDL / 6 Points of ID।"},"32":{"q":"निम्नलिखित में से कौन सा दस्तावेज़ न्यू जर्सी के CDL पहचान सत्यापन के हिस्से के रूप में विशेष रूप से आवश्यक है?","options":["Social Security card और अमेरिका में कानूनी उपस्थिति का प्रमाण","केवल किसी भी देश का जन्म प्रमाणपत्र","एक यूनियन सदस्यता कार्ड","केवल एक नियोक्ता पत्र"],"explanation":"CDL के लिए न्यू जर्सी के 6 Points of ID में Social Security card, पते का प्रमाण, और संयुक्त राज्य अमेरिका में कानूनी उपस्थिति का प्रमाण शामिल हैं। स्रोत: NJ MVC Getting Your CDL page।"},"33":{"q":"पहली बार न्यू जर्सी CDL कौशल परीक्षण से पहले आवश्यक Entry-Level Driver Training (ELDT) ऐसे प्रदाता से प्राप्त की जानी चाहिए जो:","options":["FMCSA Training Provider Registry पर सूचीबद्ध हो","केवल NJ MVC द्वारा अनुमोदित हो","कोई भी वाणिज्यिक ड्राइविंग स्कूल हो","TSA द्वारा प्रमाणित हो"],"explanation":"7 फरवरी, 2022 से, कौशल परीक्षण (या HazMat के लिए ज्ञान परीक्षण) देने से पहले ELDT FMCSA Training Provider Registry पर सूचीबद्ध प्रदाता के माध्यम से पूरी की जानी चाहिए। स्रोत: NJ MVC Getting Your CDL; FMCSA TPR।"},"34":{"q":"किस एंडोर्समेंट के लिए न्यू जर्सी ELDT कौशल परीक्षण से पहले के बजाय ज्ञान (लिखित) परीक्षण से पहले पूरी की जानी चाहिए?","options":["H (Hazardous Materials)","P (Passenger)","S (School Bus)","N (Tank Vehicle)"],"explanation":"HazMat (H) एंडोर्समेंट के लिए, ELDT ज्ञान परीक्षण से पहले पूरी की जानी चाहिए; पहली बार Class A/B और P तथा S एंडोर्समेंट के लिए, ELDT कौशल परीक्षण से पहले आवश्यक है। स्रोत: NJ MVC CLP/CDL pages; FMCSA ELDT rule।"},"35":{"q":"एक न्यू जर्सी CDL चालक जो केवल न्यू जर्सी के भीतर संचालन करता है और जिसे एक राज्य चिकित्सा परीक्षक के प्रमाणपत्र की आवश्यकता को पूरा करना होता है, उसे किस श्रेणी के तहत स्व-प्रमाणित (self-certify) करना चाहिए?","options":["Non-Excepted Intrastate","Non-Excepted Interstate","Excepted Interstate","Excepted Intrastate"],"explanation":"Non-Excepted Intrastate (NA) उन चालकों पर लागू होता है जो केवल न्यू जर्सी के भीतर संचालन करते हैं और जिन्हें चिकित्सा प्रमाणपत्र आवश्यकताओं को पूरा करना होता है। स्रोत: NJ MVC CDL Holder Self-Certification; FMCSA medical certification categories।"},"36":{"q":"कौन सी चिकित्सा स्व-प्रमाणन श्रेणी एक न्यू जर्सी CDL धारक पर लागू होती है जो राज्य की सीमाओं के पार चलता है और जिसके पास एक वैध DOT चिकित्सा परीक्षक का प्रमाणपत्र होना आवश्यक है?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Non-Excepted Interstate (NI) चालक अंतरराज्यीय वाणिज्य में संचालन करते हैं और उन्हें संघीय DOT चिकित्सा कार्ड आवश्यकताओं को पूरा करना होता है, तथा National Registry परीक्षक का प्रमाणपत्र फ़ाइल में रखना होता है। स्रोत: NJ MVC CDL Self-Certification; FMCSA categories।"},"37":{"q":"एक न्यू जर्सी चालक जो Non-Excepted Interstate के रूप में स्व-प्रमाणित करता है, उसे ऐसे प्रदाता से चिकित्सा परीक्षक का प्रमाणपत्र प्राप्त करना होगा जो:","options":["FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध हो","कोई भी लाइसेंस प्राप्त New Jersey चिकित्सक हो","स्थानीय काउंटी क्लर्क द्वारा अनुमोदित हो","TSA द्वारा प्रमाणित हो"],"explanation":"Non-excepted चालकों की जाँच FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध चिकित्सा परीक्षक द्वारा की जानी चाहिए और प्रमाणपत्र को फ़ाइल में रखना होता है। स्रोत: NJ MVC CDL Self-Certification; FMCSA National Registry।"},"38":{"q":"न्यू जर्सी में, एक वाणिज्यिक मोटर वाहन (CMV) चलाने वाले व्यक्ति के लिए अधिकतम कानूनी रक्त अल्कोहल सांद्रता (BAC) कितनी होती है?","options":["0.02","0.04","0.08","0.10"],"explanation":"न्यू जर्सी संघीय CMV मानक का पालन करता है: 0.04 प्रतिशत या अधिक BAC के साथ CMV चलाना अवैध है। यह व्यक्तिगत वाहन के लिए 0.08 सीमा से अधिक सख्त है। स्रोत: NJ MVC CDL Manual, Section 1 (Disqualifications); 49 CFR 383.51।"},"39":{"q":"CDL धारकों के लिए न्यू जर्सी के निहित-सहमति (implied-consent) नियमों के तहत, यदि कोई चालक CMV चलाते समय अल्कोहल सांद्रता के परीक्षण के लिए सहमत होने से इनकार करता है तो क्या होता है?","options":["केवल जुर्माना लगाया जाता है, कोई अयोग्यता नहीं","इसे एक प्रमुख अपराध (major offense) के रूप में माना जाता है, जो चालक को ठीक उसी तरह अयोग्य करता है जैसे DUI दोषसिद्धि करती है","पहली बार इनकार करने पर चालक को चेतावनी मिलती है","CDL केवल 30 दिनों के लिए निलंबित किया जाता है"],"explanation":"CDL धारण करके और न्यू जर्सी में गाड़ी चलाकर, एक चालक अल्कोहल परीक्षण के लिए निहित सहमति देता है। परीक्षण से इनकार करना एक प्रमुख अपराध माना जाता है और इसमें DUI दोषसिद्धि के समान अयोग्यता होती है (पहले अपराध के लिए 1 year)। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1।"},"40":{"q":"न्यू जर्सी में, पहले प्रमुख अपराध के लिए न्यूनतम CDL अयोग्यता अवधि क्या है, जैसे कि एक गैर-प्लेकार्डेड CMV चलाते समय पहली DUI दोषसिद्धि?","options":["60 days","120 days","1 year","3 years"],"explanation":"एक पहला प्रमुख अपराध (DUI, 0.04 या अधिक BAC, या परीक्षण से इनकार सहित) कम से कम 1-year CDL अयोग्यता में परिणत होता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1।"},"41":{"q":"यदि कोई न्यू जर्सी CDL चालक खतरनाक सामग्री के लिए प्लेकार्डेड वाहन चलाते समय पहला प्रमुख अपराध (जैसे DUI) करता है, तो अयोग्यता अवधि क्या होती है?","options":["1 year","18 months","3 years","5 years"],"explanation":"प्लेकार्डेड खतरनाक सामग्री का परिवहन करते समय किया गया पहला प्रमुख अपराध अयोग्यता को 1 year से बढ़ाकर 3 years कर देता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1।"},"42":{"q":"दूसरे प्रमुख अपराध (उदाहरण के लिए, किसी भी समय दूसरी DUI दोषसिद्धि) के लिए न्यू जर्सी में CDL अयोग्यता अवधि क्या है?","options":["3 years","5 years","10 years","आजीवन"],"explanation":"एक दूसरा प्रमुख अपराध आजीवन CDL अयोग्यता में परिणत होता है। न्यू जर्सी संघीय नियम का पालन करता है कि दो अलग-अलग प्रमुख अपराधों का अर्थ है कि चालक जीवन भर के लिए CDL खो देता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1।"},"43":{"q":"न्यू जर्सी में, 3-year अवधि के भीतर (अलग-अलग घटनाओं में) कितने गंभीर यातायात उल्लंघन 60-दिन की CDL अयोग्यता को ट्रिगर करते हैं?","options":["1","2","3","4"],"explanation":"3 years के भीतर (एक अलग घटना में) दूसरा गंभीर यातायात उल्लंघन 60-दिन की अयोग्यता में परिणत होता है। केवल पहला गंभीर उल्लंघन अयोग्यता का कारण नहीं बनता। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2।"},"44":{"q":"3-year अवधि के भीतर (अलग-अलग घटनाओं में) तीसरे गंभीर यातायात उल्लंघन के लिए न्यू जर्सी में CDL अयोग्यता अवधि क्या है?","options":["60 days","90 days","120 days","1 year"],"explanation":"3 years के भीतर तीसरा गंभीर यातायात उल्लंघन 120-दिन की अयोग्यता में परिणत होता है। 3 years के भीतर दूसरा 60 दिन का होता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2।"},"45":{"q":"निम्नलिखित में से किसे न्यू जर्सी CDL धारक के लिए एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["नो-पार्किंग ज़ोन में CMV पार्क करना","निर्धारित गति सीमा से 15 mph या अधिक तेज़ गाड़ी चलाना","एक जली हुई क्लीयरेंस लैंप","लॉगबुक को साफ़-सुथरा न रखना"],"explanation":"अत्यधिक गति, जिसे निर्धारित सीमा से 15 mph या अधिक के रूप में परिभाषित किया गया है, एक गंभीर यातायात उल्लंघन है। अन्य में लापरवाह ड्राइविंग, अनुचित लेन परिवर्तन, बहुत करीब से पीछा करना, और गाड़ी चलाते समय टेक्स्टिंग शामिल हैं। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2।"},"46":{"q":"न्यू जर्सी में, CMV चलाते समय रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["30 days","60 days","120 days","1 year"],"explanation":"पहला रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 60-दिन की अयोग्यता में परिणत होता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3।"},"47":{"q":"3-year अवधि के भीतर दूसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यू जर्सी में न्यूनतम CDL अयोग्यता क्या है?","options":["60 days","90 days","120 days","1 year"],"explanation":"3 years के भीतर दूसरा रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 120-दिन की अयोग्यता में परिणत होता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3।"},"48":{"q":"3-year अवधि के भीतर तीसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यू जर्सी में न्यूनतम CDL अयोग्यता क्या है?","options":["120 days","180 days","1 year","3 years"],"explanation":"3 years के भीतर तीसरा रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 1-year अयोग्यता में परिणत होता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 3।"},"49":{"q":"न्यू जर्सी में, खतरनाक सामग्री या यात्रियों को न ले जाते समय एक out-of-service (OOS) आदेश के उल्लंघन की किसी CDL चालक की पहली दोषसिद्धि के लिए न्यूनतम अयोग्यता क्या है?","options":["90 days","120 days","180 days","1 year"],"explanation":"out-of-service आदेश के उल्लंघन की पहली दोषसिद्धि कम से कम 180 days (1 year तक) की अयोग्यता में परिणत होती है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4।"},"50":{"q":"10-year अवधि के भीतर दूसरे out-of-service आदेश उल्लंघन (गैर-हैज़मैट, गैर-यात्री) के लिए न्यू जर्सी में अयोग्यता सीमा क्या है?","options":["180 days to 1 year","1 to 2 years","2 to 5 years","3 to 5 years"],"explanation":"10 years के भीतर दूसरा out-of-service आदेश उल्लंघन 2 to 5 years की अयोग्यता में परिणत होता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4।"},"51":{"q":"10-year अवधि के भीतर तीसरे या उसके बाद के out-of-service आदेश उल्लंघन (गैर-हैज़मैट, गैर-यात्री) के लिए न्यू जर्सी में अयोग्यता सीमा क्या है?","options":["180 days to 1 year","2 to 5 years","3 to 5 years","आजीवन"],"explanation":"10 years के भीतर तीसरा या उसके बाद का out-of-service आदेश उल्लंघन 3 to 5 years की अयोग्यता में परिणत होता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4।"},"52":{"q":"न्यू जर्सी में, अयोग्यता के अलावा, एक out-of-service आदेश के उल्लंघन की पहली दोषसिद्धि के लिए एक CDL चालक को किस सिविल पेनल्टी जुर्माने का सामना करना पड़ता है?","options":["At least $1,000","At least $2,500","At least $5,000","At least $10,000"],"explanation":"अयोग्यता के अलावा, एक out-of-service आदेश का उल्लंघन करने वाला चालक पहले अपराध के लिए At least $2,500, और उसके बाद के अपराध के लिए At least $5,000 की सिविल पेनल्टी के अधीन होता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.53।"},"53":{"q":"प्लेकार्डेड खतरनाक सामग्री का परिवहन करते समय एक out-of-service आदेश का उल्लंघन करने वाले न्यू जर्सी CDL चालक को पहले अपराध के लिए किस न्यूनतम अयोग्यता का सामना करना पड़ता है?","options":["120 days","180 days","1 year","2 years"],"explanation":"प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री का परिवहन करते समय (या 16+ यात्रियों को ले जाने के लिए डिज़ाइन किया गया वाहन चलाते समय) पहला out-of-service आदेश उल्लंघन कम से कम 180 days, 2 years तक की अयोग्यता वहन करता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 4।"},"54":{"q":"न्यू जर्सी और संघीय नियमों के तहत, CMV चलाते समय टेक्स्टिंग को CDL धारक के लिए किस प्रकार के उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["एक गैर-चार्जेबल उल्लंघन (infraction)","एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक out-of-service आदेश उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग करना और हाथ में पकड़े मोबाइल फोन का उपयोग करना गंभीर यातायात उल्लंघन हैं। 3 years के भीतर ऐसे दो उल्लंघन 60-दिन की अयोग्यता की ओर ले जाते हैं; तीन 120 दिनों की ओर ले जाते हैं। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 2 and 392.80/392.82।"},"55":{"q":"न्यू जर्सी CDL चालकों पर लागू होने वाले, CMV चलाते समय हाथ में पकड़े मोबाइल फोन का उपयोग करने या टेक्स्टिंग करने के लिए अधिकतम चालक जुर्माना क्या है?","options":["Up to $500","Up to $1,000","Up to $2,750","Up to $5,000"],"explanation":"एक CDL चालक जो CMV चलाते समय हाथ में पकड़े फोन का उपयोग करता है या टेक्स्टिंग करता है, उस पर Up to $2,750 का जुर्माना लगाया जा सकता है, और यह अपराध एक गंभीर यातायात उल्लंघन के रूप में गिना जाता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 392.82।"},"56":{"q":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े एक अपराध (felony) के संचालन में CMV का उपयोग करने पर न्यू जर्सी की कौन सी CDL अयोग्यता वहन होती है?","options":["1 year","3 years","10 years","बहाली की किसी संभावना के बिना आजीवन"],"explanation":"नियंत्रित पदार्थों से जुड़े एक अपराध को करने के लिए CMV का उपयोग करना एक प्रमुख अपराध है जो बहाली की किसी संभावना के बिना आजीवन अयोग्यता में परिणत होता है। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1।"},"57":{"q":"एक न्यू जर्सी CDL धारक पहली DUI दोषसिद्धि जमा करता है, फिर बाद में एक CMV में दुर्घटनास्थल से भागने के लिए एक अलग दोषसिद्धि। इस दूसरे प्रमुख अपराध का परिणाम क्या होता है?","options":["A 120-day disqualification","A 1-year disqualification","A 3-year disqualification","एक आजीवन अयोग्यता"],"explanation":"DUI और एक CMV में दुर्घटनास्थल से भागना दोनों प्रमुख अपराध हैं। किन्हीं भी दो प्रमुख अपराधों (अलग-अलग घटनाओं में) का परिणाम एक आजीवन CDL अयोग्यता होता है, भले ही वे विभिन्न प्रकार के प्रमुख अपराध हों। स्रोत: NJ MVC CDL Manual, Section 1; 49 CFR 383.51 Table 1।"},"58":{"q":"न्यू जर्सी के मूव ओवर कानून के तहत, बहु-लेन वाले राजमार्ग पर चमकती रोशनी (फ्लैशिंग लाइट्स) दिखा रहे रुके हुए आपातकालीन वाहन, टो ट्रक, या राजमार्ग रखरखाव वाहन के पास पहुँचते समय किसी वाणिज्यिक वाहन के चालक को क्या करना चाहिए?","options":["यदि सुरक्षित रूप से किया जा सके, तो रुके हुए वाहन से सटी हुई लेन के अलावा किसी अन्य लेन में लेन बदल लें","जब तक रुका हुआ वाहन हट न जाए, तब तक पूरी तरह रुक जाएँ","निर्धारित गति पर चलते रहें परन्तु गुजरते समय हॉर्न बजाएँ","किनारे (शोल्डर) पर गाड़ी खड़ी करें और किसी अधिकारी द्वारा यातायात को इशारा करके आगे बढ़ाने का इंतज़ार करें"],"explanation":"न्यू जर्सी का मूव ओवर कानून (N.J.S.A. 39:4-92.2) बहु-लेन वाली सड़क पर पास आ रहे चालक से यह अपेक्षा करता है कि जब ऐसा करना सुरक्षित हो, तो वह रुके हुए वाहन से सटी हुई लेन के अलावा किसी अन्य लेन में लेन बदल ले। स्रोत: N.J.S.A. 39:4-92.2; NJ MVC।"},"59":{"q":"न्यू जर्सी के मूव ओवर कानून के तहत, यदि कोई चालक चमकती रोशनी वाले रुके हुए आपातकालीन या सेवा वाहन से दूर सुरक्षित रूप से लेन नहीं बदल सकता, तो क्या आवश्यक है?","options":["गति को निर्धारित सीमा से कम एक उचित और सही गति तक घटाएँ और सावधानी से आगे बढ़ें","यातायात को बाधित होने से बचाने के लिए निर्धारित गति सीमा बनाए रखें","जब तक रोशनी बंद न हो जाए, तब तक मौजूदा लेन में पूरी तरह रुक जाएँ","परिस्थितियों की परवाह किए बिना मीडियन (बीच के हिस्से) पर चले जाएँ"],"explanation":"N.J.S.A. 39:4-92.2 यह प्रावधान करता है कि जब लेन सुरक्षित रूप से नहीं बदली जा सकती, तो चालक को गति घटाकर निर्धारित सीमा से कम एक उचित और सही गति तक लानी होगी और रुकने के लिए तैयार रहना होगा। स्रोत: N.J.S.A. 39:4-92.2; NJ MVC।"},"60":{"q":"न्यू जर्सी में, आगे बढ़ने से पहले एक बस को रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग की निकटतम रेल से कितनी दूरी पर रुकना चाहिए?","options":["15 और 50 फीट के बीच","5 और 15 फीट के बीच","50 और 100 फीट के बीच","10 और 25 फीट के बीच"],"explanation":"न्यू जर्सी CDL मैनुअल (सेक्शन 4, यात्रियों का परिवहन) में एक बस को रेलमार्ग क्रॉसिंग से 15 और 50 फीट के बीच रुकने, फिर ट्रेनों के लिए देखने और सुनने की आवश्यकता है। स्रोत: NJ MVC Commercial Driver License Manual, Sec. 4.3.5।"},"61":{"q":"न्यू जर्सी में प्लेकार्ड वाले खतरनाक-सामग्री वाहन को रेलमार्ग पटरियों को पार करने से पहले निकटतम रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["15 फीट से अधिक निकट नहीं और 50 फीट से अधिक दूर नहीं","25 फीट से अधिक निकट नहीं और 75 फीट से अधिक दूर नहीं","10 फीट से अधिक निकट नहीं और 40 फीट से अधिक दूर नहीं","5 फीट से अधिक निकट नहीं और 30 फीट से अधिक दूर नहीं"],"explanation":"न्यू जर्सी CDL मैनुअल (सेक्शन 9, खतरनाक सामग्री) में कहा गया है कि एक प्लेकार्ड वाला वाहन, कोई भी मात्रा में क्लोरीन ले जाने वाला वाहन, या हैज़मैट के लिए उपयोग किए जाने वाले कार्गो टैंक वाला वाहन निकटतम रेल से 15 से 50 फीट पहले रुकना चाहिए। स्रोत: NJ MVC CDL Manual, Sec. 9.6.12।"},"62":{"q":"न्यू जर्सी के दो-लेन वाले, अविभाजित राजमार्ग पर, एक स्कूल बस बच्चों को लेने के लिए लाल बत्तियाँ चमकाते हुए रुकी हुई है। बस के पास आ रहे या उससे आगे निकल रहे वाहन को कम से कम कितनी दूरी पर रुकना चाहिए?","options":["25 फीट","10 फीट","20 फीट","50 फीट"],"explanation":"N.J.S.A. 39:4-128.1 के अनुसार किसी अविभाजित सड़क पर चमकती लाल बत्तियों वाली स्कूल बस के पास आ रहे या उससे आगे निकल रहे चालक को कम से कम 25 फीट दूर रुकना होगा और बत्तियों के चमकना बंद होने तक रुके रहना होगा। स्रोत: N.J.S.A. 39:4-128.1।"},"63":{"q":"न्यू जर्सी कानून के तहत, किसी दोहरे या विभाजित राजमार्ग के अलग रोडवे पर चल रहे चालक को, जो दूसरे रोडवे पर चमकती लाल बत्तियों के साथ रुकी हुई स्कूल बस के पास पहुँचता है, क्या करना चाहिए?","options":["गति को 10 mph से अधिक नहीं तक घटाएँ और बस से आगे सावधानी से बढ़ें","बस से कम से कम 25 फीट दूर रुकें और बत्तियों के चमकना बंद होने तक इंतज़ार करें","पूरी तरह रुकें और बस चालक द्वारा यातायात को इशारा करके आगे बढ़ाने तक इंतज़ार करें","निर्धारित गति पर चलते रहें क्योंकि किसी कार्रवाई की आवश्यकता नहीं है"],"explanation":"N.J.S.A. 39:4-128.1 एक विभाजित-राजमार्ग अपवाद प्रदान करता है: किसी दोहरे या विभाजित राजमार्ग के दूसरे रोडवे पर चल रहे चालक को रुकने की आवश्यकता नहीं है परन्तु उसे बस और किसी भी बच्चे से आगे निकलने तक गति को 10 mph से अधिक नहीं तक घटाना होगा। स्रोत: N.J.S.A. 39:4-128.1।"},"64":{"q":"जब कोई न्यू जर्सी CMV किसी एक-तरफ़ा या विभाजित राजमार्ग पर रुका हुआ हो, तो चालक को तीन चेतावनी उपकरण (त्रिकोण) आ रहे यातायात की ओर किन दूरियों पर रखने चाहिए?","options":["10 फीट, 100 फीट, और 200 फीट","10 फीट, 50 फीट, और 100 फीट","25 फीट, 100 फीट, और 150 फीट","10 फीट, 200 फीट, और 300 फीट"],"explanation":"न्यू जर्सी CDL मैनुअल निर्देश देता है कि किसी एक-तरफ़ा या विभाजित राजमार्ग पर चेतावनी उपकरण आ रहे यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर रखे जाएँ। स्रोत: NJ MVC CDL Manual, Sec. 2 (Driving Safely)।"},"65":{"q":"न्यू जर्सी की किसी सड़क के किनारे (शोल्डर) पर CMV रोकने के बाद, चालक को कितने मिनट के भीतर आपातकालीन चेतावनी उपकरण लगाने चाहिए?","options":["10 मिनट","5 मिनट","15 मिनट","30 मिनट"],"explanation":"न्यू जर्सी CDL मैनुअल के अनुसार यदि आपको किसी सड़क या किनारे (शोल्डर) पर रुकना पड़े, तो आपको 10 मिनट के भीतर आपातकालीन चेतावनी उपकरण लगाने होंगे। स्रोत: NJ MVC CDL Manual, Sec. 2 (Driving Safely)।"},"66":{"q":"न्यू जर्सी में दोनों दिशाओं में यातायात ले जाने वाली दो-लेन वाली सड़क पर, रुके हुए CMV के चेतावनी त्रिकोण कहाँ रखे जाने चाहिए?","options":["वाहन के 10 फीट के भीतर और उसके पीछे व आगे 100 फीट पर","केवल वाहन के पीछे 100 फीट और 200 फीट पर","वाहन के 25 फीट के भीतर और उसके पीछे 200 फीट पर","केवल वाहन के पीछे 10 फीट, 100 फीट, और 200 फीट पर"],"explanation":"न्यू जर्सी CDL मैनुअल निर्देश देता है कि दोनों दिशाओं में यातायात ले जाने वाली दो-लेन वाली सड़क पर, एक त्रिकोण आगे या पीछे के कोनों के 10 फीट के भीतर रखें और अन्य वाहन के पीछे व आगे 100 फीट पर रखें। स्रोत: NJ MVC CDL Manual, Sec. 2 (Driving Safely)।"},"67":{"q":"10,000 पाउंड से अधिक पंजीकृत सकल वजन वाले वाणिज्यिक वाहनों को किस इंटरचेंज के उत्तर में Garden State Parkway का उपयोग करने से प्रतिबंधित किया गया है?","options":["Interchange 105","Interchange 80","Interchange 142","Interchange 9"],"explanation":"10,000 lbs से अधिक पंजीकृत वाणिज्यिक वाहनों को Interchange 105 के उत्तर में Garden State Parkway से प्रतिबंधित किया गया है (बसों, परमिट वाले, और प्राधिकरण वाहनों के लिए सीमित अपवादों के साथ)। स्रोत: NJ Turnpike Authority Parkway regulations; N.J.A.C. 19:9-1.9।"},"68":{"q":"New Jersey Turnpike के 'dual-dual' खंड पर, दक्षिणी विभाजन और उत्तरी विलय के बीच की भीतरी रोडवे के बारे में क्या सही है?","options":["यह केवल कारों तक सीमित है, जबकि बाहरी रोडवे कारें और ट्रक ले जाती है","यह केवल ट्रकों तक सीमित है, जबकि बाहरी रोडवे केवल कारें ले जाती है","यह विशेष रूप से बसों और आपातकालीन वाहनों के लिए आरक्षित है","यह वाहन के प्रकार की परवाह किए बिना केवल उत्तर की ओर जाने वाला यातायात ले जाती है"],"explanation":"New Jersey Turnpike के dual-dual विन्यास पर, भीतरी रोडवे केवल कारों के लिए निर्धारित है जबकि बाहरी रोडवे कारें और ट्रक दोनों ले जाती है; ट्रकों और बसों को बाहरी लेन की ओर निर्देशित किया जाता है। स्रोत: NJ Turnpike Authority; NJ MVC।"},"69":{"q":"न्यू जर्सी के दाएँ-चलने (keep-right) वाले कानून के तहत, बहु-लेन वाले राजमार्ग पर ऐसे चालक को, जो आगे नहीं निकल रहा या बाएँ मुड़ने की तैयारी नहीं कर रहा, क्या करना चाहिए?","options":["यातायात के लिए उपलब्ध दाहिनी ओर की लेन में रहें","हर समय बीच वाली लेन का उपयोग करें","जिस लेन में सबसे कम यातायात हो, उसका उपयोग करें","ट्रकों के लिए दाहिनी ओर खाली रखने हेतु बाईं ओर की लेन में रहें"],"explanation":"N.J.S.A. 39:4-82 के अनुसार चालकों को दाहिनी ओर रहना होगा और दाहिनी ओर की लेन में गाड़ी चलानी होगी, सिवाय आगे निकलते समय या बाएँ मुड़ने की तैयारी करते समय; दंड N.J.S.A. 39:4-88.1 के तहत निर्धारित हैं। स्रोत: N.J.S.A. 39:4-82, 39:4-88.1।"},"70":{"q":"न्यू जर्सी विनियमों के तहत, पाँच टन से अधिक का कोई ट्रक बहु-लेन वाले विभाजित राजमार्ग की बाईं लेन में कब चल सकता है?","options":["केवल रोडवे में प्रवेश करने या उससे निकलने, किसी आपातकाल में, या जब बाएँ मोड़ के एक मील के भीतर हो","जब भी वह किसी धीमे वाहन से आगे निकल रहा हो","केवल आधी रात और सुबह 6 बजे के बीच","जब भी दाहिनी लेन में यातायात भारी हो"],"explanation":"न्यू जर्सी विभाजित राजमार्गों पर पाँच टन से अधिक के ट्रकों को दाहिनी लेन तक सीमित करता है, और बाईं लेन की अनुमति केवल रोडवे में प्रवेश/निकास, किसी आपातकाल में, या जब बाएँ मोड़ के एक मील के भीतर हो, तब देता है। स्रोत: NJ keep-right rules; N.J.S.A. 39:4-82 और संबंधित Title 39 प्रावधान।"},"71":{"q":"N.J.S.A. 39:4-98.1 के तहत, परिवहन आयुक्त (Commissioner of Transportation) योग्य बहु-लेन वाले राज्य राजमार्गों पर 10,000 पाउंड या अधिक पंजीकृत वजन वाले ट्रकों के लिए निर्धारित सीमा से कितने अंतर पर एक कम अधिकतम गति सीमा निर्धारित कर सकते हैं?","options":["5 mph","10 mph","15 mph","20 mph"],"explanation":"N.J.S.A. 39:4-98.1, चार या अधिक लेन वाले राज्य राजमार्गों पर जहाँ सीमा 50 mph या अधिक है, वहाँ 10,000 lbs या अधिक के ट्रकों के लिए 5 mph अंतर पर एक निर्धारित कम ट्रक गति सीमा को अधिकृत करता है। स्रोत: N.J.S.A. 39:4-98.1।"},"72":{"q":"न्यू जर्सी के सामान्य गति कानून के तहत, किसी निर्धारित सीमा के अभाव में, 'अन्य सभी स्थानों' (व्यावसायिक, आवासीय, या स्कूल क्षेत्र नहीं) के लिए वैधानिक गति सीमा क्या है?","options":["50 mph","55 mph","65 mph","45 mph"],"explanation":"N.J.S.A. 39:4-98 व्यावसायिक/आवासीय जिलों में 25 mph, कुछ उपनगरीय जिलों में 35 mph, और अन्य सभी स्थानों में 50 mph की प्रथमदृष्ट्या (prima facie) सीमाएँ निर्धारित करता है, जब तक कि कोई भिन्न सीमा निर्धारित न की गई हो। स्रोत: N.J.S.A. 39:4-98।"},"73":{"q":"न्यू जर्सी CMV में आवश्यक रुकाव के बाद रेलमार्ग पटरियों को पार करते समय, चालक को क्या नहीं करना चाहिए?","options":["जब तक वाहन का कोई भी हिस्सा पटरियों पर हो, तब तक गियर बदलना","पास आते समय चार-तरफ़ा आपातकालीन फ्लैशर्स का उपयोग करना","ट्रेन के लिए दोनों दिशाओं में देखना और सुनना","पार करने से पहले खिड़की नीचे करना"],"explanation":"न्यू जर्सी CDL मैनुअल चालकों को रेलमार्ग पटरियों को पार करते समय गियर न बदलने का निर्देश देता है, ताकि वाहन क्रॉसिंग पर रुक (स्टॉल) न जाए। स्रोत: NJ MVC CDL Manual, Secs. 2.15 और 9.6.12।"},"74":{"q":"निम्नलिखित में से किस स्थिति में एक न्यू जर्सी बस चालक को रेलमार्ग क्रॉसिंग पर रुकने की आवश्यकता नहीं है?","options":["क्रॉसिंग 'exempt' (छूट प्राप्त) या 'abandoned' (परित्यक्त) के रूप में चिह्नित है","क्रॉसिंग पर क्रॉसबक है परन्तु कोई गेट नहीं है","क्रॉसिंग पर पटरियों के दो सेट हैं","क्रॉसिंग बिना किसी सिग्नल के ग्रामीण क्षेत्र में है"],"explanation":"न्यू जर्सी CDL मैनुअल बस के रुकने की आवश्यकता के अपवादों को सूचीबद्ध करता है, जिसमें वे जगहें शामिल हैं जहाँ कोई पुलिस अधिकारी या फ्लैगमैन यातायात को निर्देशित करता है, जहाँ ट्रैफ़िक सिग्नल हरा है, और 'exempt' या 'abandoned' के रूप में चिह्नित क्रॉसिंग पर। स्रोत: NJ MVC CDL Manual, Sec. 4.3.5।"},"75":{"q":"न्यू जर्सी में, ऐसे रेलमार्ग क्रॉसिंग पर जहाँ क्रॉसबक है परन्तु सड़क पर कोई सफ़ेद स्टॉप लाइन रंगी हुई नहीं है, वहाँ रुकने के लिए आवश्यक वाहनों को निकटतम रेल से किस सीमा के भीतर रुकना चाहिए?","options":["15 फीट से अधिक निकट नहीं और 50 फीट से अधिक दूर नहीं","10 फीट से अधिक निकट नहीं और 30 फीट से अधिक दूर नहीं","20 फीट से अधिक निकट नहीं और 60 फीट से अधिक दूर नहीं","25 फीट से अधिक निकट नहीं और 100 फीट से अधिक दूर नहीं"],"explanation":"न्यू जर्सी CDL मैनुअल में कहा गया है कि जहाँ कोई सफ़ेद स्टॉप लाइन रंगी हुई नहीं है, वहाँ रुकने के लिए आवश्यक वाहनों को निकटतम रेल से 15 फीट से अधिक निकट नहीं और 50 फीट से अधिक दूर नहीं रुकना चाहिए। स्रोत: NJ MVC CDL Manual, Sec. 2.15।"},"76":{"q":"ओवरसाइज़ परमिट के बिना, न्यू जर्सी राजमार्गों पर अधिकतम वैध वाहन चौड़ाई क्या है?","options":["8 फीट 6 इंच","8 फीट 0 इंच","9 फीट 0 इंच","10 फीट 0 इंच"],"explanation":"न्यू जर्सी की वैध अधिकतम चौड़ाई 8 फीट 6 इंच (102 inches) है; इससे अधिक भार के लिए NJDOT से एक ओवरसाइज़ परमिट की आवश्यकता होती है। मानक वैध ऊँचाई 13 फीट 6 इंच और सकल वजन 80,000 lbs है। स्रोत: NJDOT Commercial Vehicle size/weight regulations; Title 39।"},"77":{"q":"न्यू जर्सी में एक स्कूल बस रेलमार्ग-राजमार्ग क्रॉसिंग पर रुक (स्टॉल) गई है। न्यू जर्सी CDL मैनुअल के अनुसार, चालक को सबसे पहले क्या करना चाहिए?","options":["छात्रों को बाहर निकालें और उन्हें पटरियों से कम से कम 100 फीट दूर किसी भी आ रही ट्रेन की ओर एक कोण पर ले जाएँ","छात्रों को बैठाए रखें और क्रॉसिंग पर रहते हुए इंजन को फिर से चालू करने का प्रयास करें","मदद आने तक छात्रों को बस के फर्श पर लेटाए रखें","बस छोड़ दें और ट्रेन को संकेत देने के लिए पटरियों के साथ-साथ दौड़ें"],"explanation":"न्यू जर्सी CDL मैनुअल (स्कूल बस सेक्शन) चालक को तुरंत बाहर निकालने और छात्रों को पटरियों से कम से कम 100 फीट दूर किसी सुरक्षित स्थान पर ले जाने का निर्देश देता है, और आ रही ट्रेन की ओर तथा उससे दूर एक कोण पर बढ़ें ताकि वे मलबे से न टकराएँ। स्रोत: NJ MVC CDL Manual, Sec. 10 (School Buses)।"},"78":{"q":"न्यू जर्सी में वाणिज्यिक चालक लाइसेंस (CDLs) कौन सी एजेंसी जारी करती है?","options":["New Jersey Motor Vehicle Commission (MVC)","New Jersey Department of Transportation (NJDOT)","New Jersey State Police Commercial Bureau","संघीय Motor Carrier Safety Administration (FMCSA)"],"explanation":"न्यू जर्सी में, CDLs, New Jersey Motor Vehicle Commission (MVC) द्वारा जारी किए जाते हैं। NJDOT सड़कों और ओवरसाइज़/ओवरवेट परमिट को संभालता है, और FMCSA संघीय मानक निर्धारित करता है परन्तु लाइसेंस जारी नहीं करता। स्रोत: NJ MVC, Getting your Commercial Driver License (nj.gov/mvc/drivertopics/gettingcdl.htm)।"},"79":{"q":"किसी पहली बार के न्यू जर्सी आवेदक का CDL के लिए परीक्षण होने से पहले, उसे MVC को पहचान के कितने अंक (points) प्रस्तुत करने होंगे?","options":["पहचान के 6 अंक (points)","पहचान के 4 अंक (points)","पहचान के 8 अंक (points)","पहचान के 2 अंक (points)"],"explanation":"न्यू जर्सी एक 6 Points of ID सत्यापन कार्यक्रम का उपयोग करता है; CDL आवेदकों को पहचान के छह अंक (points) स्थापित करने होंगे (जिसमें सामाजिक सुरक्षा संख्या, पता, और कानूनी उपस्थिति का प्रमाण शामिल है)। स्रोत: NJ MVC, Getting your Commercial Driver License और the NJ MVC 6 Points of ID Program।"},"80":{"q":"INTRASTATE (केवल न्यू जर्सी के भीतर) संचालन के लिए न्यू जर्सी CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","19 वर्ष","20 वर्ष"],"explanation":"intrastate ड्राइविंग के लिए NJ CDL प्राप्त करने हेतु व्यक्ति की आयु कम से कम 18 वर्ष होनी चाहिए; 21 वर्ष से कम आयु के चालक intrastate संचालन तक सीमित हैं और उन्हें commerce category 3 या 4 के लिए स्व-प्रमाणन (self-certify) करना होगा। interstate संचालन के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: NJ MVC, Getting your Commercial Driver License और Commercial Learner Permits (CLP)।"},"81":{"q":"20 वर्षीय न्यू जर्सी CDL धारक किस प्रकार के संचालन तक सीमित है?","options":["केवल Intrastate (न्यू जर्सी के भीतर)","केवल Interstate (राज्य की सीमाओं के पार)","Interstate और Intrastate दोनों","केवल खतरनाक सामग्री परिवहन"],"explanation":"21 वर्ष से कम आयु के चालक केवल intrastate व्यापार (न्यू जर्सी के भीतर) में संचालन कर सकते हैं और उन्हें स्व-प्रमाणन commerce category 3 या 4 का चयन करना होगा। 21 वर्ष की आयु तक interstate संचालन की अनुमति नहीं है। स्रोत: NJ MVC, Commercial Learner Permits (CLP)।"},"82":{"q":"किसी न्यू जर्सी आवेदक को पहली बार CDL स्किल्स टेस्ट देने से पहले कौन सा प्रशिक्षण पूरा करना होगा?","options":["किसी FMCSA Training Provider Registry प्रदाता से Entry-Level Driver Training (ELDT)","किसी MVC एजेंसी में राज्य द्वारा संचालित एक रक्षात्मक ड्राइविंग पाठ्यक्रम","एक 40-घंटे का OSHA वाणिज्यिक सुरक्षा प्रमाणन","एक NJDOT-अनुमोदित ओवरसाइज़ लोड हैंडलिंग कक्षा"],"explanation":"7 फरवरी, 2022 से प्रभावी, आवेदकों को CDL स्किल्स टेस्ट देने से पहले (और HAZMAT नॉलेज टेस्ट से पहले) FMCSA Training Provider Registry में सूचीबद्ध किसी प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना होगा। स्रोत: NJ MVC, Getting your Commercial Driver License; FMCSA ELDT rule (49 CFR Part 380)।"},"83":{"q":"न्यू जर्सी CDL स्व-प्रमाणन (self-certification) में कितनी commerce categories होती हैं जिनमें से एक आवेदक को चुनना होता है?","options":["4 श्रेणियाँ","2 श्रेणियाँ","3 श्रेणियाँ","5 श्रेणियाँ"],"explanation":"चार स्व-प्रमाणन commerce categories होती हैं: (1) non-excepted interstate, (2) excepted interstate, (3) non-excepted intrastate, और (4) excepted intrastate। आवेदक को एक का चयन करना होगा। स्रोत: NJ MVC, CDL Self-Certification and Medical Examiner Certificate (cdlmedcert.htm)।"},"84":{"q":"न्यू जर्सी में किन स्व-प्रमाणन श्रेणियों के लिए CDL धारक को एक वैध Medical Examiner's Certificate फ़ाइल में रखना आवश्यक है?","options":["Non-excepted interstate (1) और non-excepted intrastate (3)","Excepted interstate (2) और excepted intrastate (4)","Non-excepted interstate (1) और excepted interstate (2)","केवल non-excepted interstate (1)"],"explanation":"'non-excepted' श्रेणियों (1 और 3) के लिए एक वैध Medical Examiner's Certificate आवश्यक है। 'excepted' श्रेणियों (2 और 4) के लिए इसकी आवश्यकता नहीं होती, जब तक कि चालक के पास यात्री (P) या स्कूल बस (S) एंडोर्समेंट न हो। स्रोत: NJ MVC, CDL Self-Certification and Medical Examiner Certificate।"},"85":{"q":"वर्तमान नियमों के तहत किसी चालक का medical examiner's certificate सामान्यतः न्यू जर्सी MVC तक कैसे पहुँचता है?","options":["इलेक्ट्रॉनिक रूप से, FMCSA के National Registry से राज्य लाइसेंसिंग एजेंसी को प्रेषित किया जाता है","चालक NJDOT मुख्यालय को एक नोटरीकृत कागज़ी प्रति डाक से भेजता है","चालक का नियोक्ता इसे New Jersey State Police के पास दाखिल करता है","इसे ट्रकिंग कंपनी द्वारा स्थानीय MVC एजेंसी को फ़ैक्स किया जाता है"],"explanation":"मेडिकल एग्ज़ामिनर इलेक्ट्रॉनिक रूप से परीक्षा परिणाम FMCSA के National Registry को प्रस्तुत करते हैं, और प्रमाणन इलेक्ट्रॉनिक रूप से State Driver Licensing Agency (NJ MVC) को प्रेषित किया जाता है; प्रमाण के रूप में किसी कागज़ी प्रमाणपत्र (Form MCSA-5876) की आवश्यकता नहीं है। स्रोत: NJ MVC, CDL Self-Certification and Medical Examiner Certificate।"},"86":{"q":"किसी CDL धारक के Medical Examiner's Certificate के लिए शारीरिक परीक्षण करने के लिए कौन अधिकृत है?","options":["FMCSA के National Registry of Certified Medical Examiners में सूचीबद्ध एक मेडिकल एग्ज़ामिनर","रजिस्ट्री स्थिति की परवाह किए बिना, कोई भी लाइसेंस प्राप्त न्यू जर्सी चिकित्सक","किसी MVC लाइसेंसिंग एजेंसी की एक नर्स","एक NJDOT-नियोजित व्यावसायिक स्वास्थ्य अधिकारी"],"explanation":"परीक्षा FMCSA के National Registry of Certified Medical Examiners में सूचीबद्ध एक संघीय रूप से प्रमाणित मेडिकल एग्ज़ामिनर द्वारा की जानी चाहिए; वह एग्ज़ामिनर परिणाम इलेक्ट्रॉनिक रूप से प्रस्तुत करता है। स्रोत: NJ MVC, CDL Self-Certification and Medical Examiner Certificate।"},"87":{"q":"CDL नॉलेज टेस्ट पास करने के बाद कोई न्यू जर्सी आवेदक क्या प्राप्त करता है?","options":["एक Commercial Learner's Permit (CLP)","एक पूर्ण Commercial Driver License (CDL)","एक अस्थायी HAZMAT एंडोर्समेंट कार्ड","एक स्किल्स-टेस्ट छूट (waiver) प्रमाणपत्र"],"explanation":"आवश्यक नॉलेज टेस्ट पास करना आवेदक को एक Commercial Learner's Permit (CLP) के लिए योग्य बनाता है, जो स्किल्स टेस्ट से पहले पर्यवेक्षित अभ्यास की अनुमति देता है। CDL केवल स्किल्स टेस्ट पास करने के बाद जारी किया जाता है। स्रोत: NJ MVC, Getting your Commercial Driver License और Commercial Learner Permits (CLP)।"},"88":{"q":"किसी न्यू जर्सी CDL नॉलेज टेस्ट को पास करने के लिए किसी आवेदक को न्यूनतम कितने प्रतिशत अंक प्राप्त करने होंगे?","options":["80%","70%","75%","90%"],"explanation":"न्यू जर्सी में CDL नॉलेज टेस्ट पास करने के लिए प्रत्येक आवेदक को कम से कम 80% प्रश्नों का सही उत्तर देना होगा। स्रोत: NJ MVC, CDL Tests (cdltest.htm)।"},"89":{"q":"न्यू जर्सी में सामान्य नॉलेज CDL टेस्ट में कितने प्रश्न होते हैं?","options":["50 प्रश्न","30 प्रश्न","100 प्रश्न","25 प्रश्न"],"explanation":"CDL नॉलेज परीक्षा में एक 50-प्रश्न वाला सामान्य टेस्ट शामिल होता है, साथ ही माँगे गए प्रत्येक एंडोर्समेंट के लिए अलग अतिरिक्त टेस्ट होते हैं। स्रोत: NJ MVC, CDL Tests (cdltest.htm)।"},"90":{"q":"किसी न्यू जर्सी Commercial Learner's Permit (CLP) जारी होने के बाद कितने समय तक वैध रहता है?","options":["180 दिन","90 दिन","1 वर्ष","60 दिन"],"explanation":"एक न्यू जर्सी CLP जारी होने की तारीख से 180 दिनों के लिए वैध है। स्रोत: NJ MVC, Commercial Learner Permits (CLP) (cdlclp.htm)।"},"91":{"q":"किसी न्यू जर्सी Commercial Learner's Permit (CLP) को कितनी बार नवीनीकृत (renew) किया जा सकता है?","options":["एक बार","इसे नवीनीकृत नहीं किया जा सकता","दो बार","असीमित बार"],"explanation":"एक NJ CLP 180 दिनों के लिए वैध है और नॉलेज टेस्ट दोबारा दिए बिना इसे केवल एक बार (एक अतिरिक्त अवधि के लिए) नवीनीकृत किया जा सकता है। स्रोत: NJ MVC, Commercial Learner Permits (CLP)।"},"92":{"q":"किसी न्यू जर्सी CLP के जारी होने के बाद, CDL स्किल्स टेस्ट देने से पहले किसी चालक को इसे कम से कम कितने समय तक रखना होगा?","options":["14 दिन","30 दिन","7 दिन","10 दिन"],"explanation":"किसी CLP धारक को CDL स्किल्स (रोड) टेस्ट देने से पहले परमिट जारी होने के बाद कम से कम 14 दिन प्रतीक्षा करनी होगी। स्रोत: NJ MVC, Getting your Commercial Driver License; federal CLP rule (49 CFR 383.25)।"},"93":{"q":"न्यू जर्सी CDL स्किल्स टेस्ट किन तीन भागों से, क्रम में, बना होता है?","options":["प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","लिखित नॉलेज, दृष्टि जाँच, और सड़क पर ड्राइविंग","एयर-ब्रेक जाँच, समानांतर पार्किंग, और राजमार्ग विलय (merging)","कपलिंग टेस्ट, बैकिंग टेस्ट, और HAZMAT हैंडलिंग"],"explanation":"CDL स्किल्स (रोड) टेस्ट के तीन भाग होते हैं जो क्रम में लिए जाते हैं: प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण स्किल्स टेस्ट, और सड़क पर ड्राइविंग टेस्ट। स्रोत: NJ MVC, CDL Tests (cdltest.htm)।"},"94":{"q":"स्किल्स टेस्ट के न्यू जर्सी प्री-ट्रिप निरीक्षण भाग के दौरान, आवेदक को क्या करने की क्षमता प्रदर्शित करनी होगी?","options":["उन घटकों की पहचान करना और समझाना जिनका निरीक्षण किया जाना चाहिए और क्यों","एक विफल एयर-ब्रेक चैंबर को पाँच मिनट से कम समय में ठीक करना","पूरे CDL मैनुअल को याद से सुनाना","फिफ्थ व्हील को अलग करना और फिर से जोड़ना"],"explanation":"प्री-ट्रिप निरीक्षण टेस्ट में, आवेदक को यह दिखाना होगा कि वह निरीक्षण किए जाने वाले प्रत्येक घटक की पहचान कर सकता है और समझा सकता है कि उसकी जाँच क्यों की जाती है, यह साबित करते हुए कि वाहन चलाने के लिए सुरक्षित है। स्रोत: NJ MVC, CDL Tests (cdltest.htm)।"},"95":{"q":"स्किल्स टेस्ट के लिए, आवेदक को एक प्रतिनिधि वाणिज्यिक मोटर वाहन उपलब्ध कराना होगा जो किस शर्त को पूरा करता हो?","options":["वर्तमान निरीक्षण, वैध पंजीकरण और बीमा, और कोई कार्गो या खतरनाक सामग्री नहीं","अपनी अधिकतम सकल वजन रेटिंग तक भरा हुआ एक वाहन","दो वर्ष से अधिक पुराना न होने वाला एक वाहन","केवल किसी लाइसेंस प्राप्त मोटर कैरियर के स्वामित्व वाला एक वाहन"],"explanation":"आवेदकों को माँगी गई श्रेणी के प्रतिनिधि एक उपयुक्त CMV उपलब्ध कराना होगा जिसमें वर्तमान निरीक्षण, वैध पंजीकरण और बीमा, उचित GVWR/प्लेकार्डिंग हो, और जिसमें कोई कार्गो या खतरनाक सामग्री न हो। स्रोत: NJ MVC, CDL Tests (cdltest.htm)।"},"96":{"q":"किसी न्यू जर्सी CDL को कितनी बार नवीनीकृत (renew) किया जाना चाहिए?","options":["हर 4 वर्ष में","हर 2 वर्ष में","हर 5 वर्ष में","हर 8 वर्ष में"],"explanation":"एक मानक न्यू जर्सी CDL चार-वर्ष की अवधि के लिए जारी किया जाता है और इसे हर 4 वर्ष में नवीनीकृत किया जाना चाहिए (पहले CDL को बेसिक लाइसेंस की समाप्ति से मेल खाने के लिए आनुपातिक किया जा सकता है)। स्रोत: NJ MVC, Getting your Commercial Driver License (gettingcdl.htm)।"},"97":{"q":"किसी न्यू जर्सी CDL को नवीनीकृत करने के बारे में कौन सा कथन सही है?","options":["इसे किसी MVC एजेंसी में व्यक्तिगत रूप से नवीनीकृत किया जाना चाहिए, ऑनलाइन या डाक से नहीं","इसे एक बेसिक Class D लाइसेंस की तरह पूरी तरह ऑनलाइन नवीनीकृत किया जा सकता है","इसे केवल तभी डाक से नवीनीकृत किया जा सकता है जब कोई एंडोर्समेंट न हो","इसे बिना किसी चालक कार्रवाई के स्वचालित रूप से नवीनीकृत किया जाता है"],"explanation":"एक बेसिक चालक लाइसेंस के विपरीत, एक न्यू जर्सी CDL को ऑनलाइन या डाक से नवीनीकृत नहीं किया जा सकता; धारक को किसी MVC एजेंसी में व्यक्तिगत रूप से नवीनीकरण कराना होगा और आवश्यक दस्तावेज़ तथा वर्तमान चिकित्सा प्रमाणन स्थिति प्रस्तुत करनी होगी। ध्यान दें: सटीक शुल्क बदल सकते हैं, इसलिए वर्तमान राशियों की पुष्टि MVC से करें। स्रोत: NJ MVC CDL renewal guidance।"}},"ar":{"0":{"q":"على طرق نيو جيرسي السريعة، ما هو الحد الأقصى لارتفاع المركبة أو مجموعة المركبات، بما في ذلك حمولتها؟","options":["13 قدماً و6 بوصات","13 قدماً و0 بوصة","14 قدماً و0 بوصة","14 قدماً و6 بوصات"],"explanation":"يحدد قانون نيو جيرسي (N.J.S.A. 39:3-84) الحد الأقصى لارتفاع أي مركبة أو مجموعة مركبات، بما في ذلك الحمولة أو المحتويات، بـ 13 قدماً و6 بوصات على جميع الطرق السريعة. (المصدر: N.J.S.A. 39:3-84؛ دليل NJDOT لأحجام وأوزان المركبات التجارية.)"},"1":{"q":"ما هو الحد الأقصى للوزن الإجمالي الكلي للمركبة المسموح به على طرق نيو جيرسي السريعة دون تصريح للوزن الزائد؟","options":["80,000 رطل","73,280 رطلاً","88,000 رطل","76,000 رطل"],"explanation":"تحدد نيو جيرسي سقف الوزن الإجمالي الكلي الأقصى للمركبة بـ 80,000 رطل، بما يطابق الحد الفيدرالي (N.J.S.A. 39:3-84). وأي شيء يتجاوز ذلك في حمولة غير قابلة للتجزئة يتطلب تصريحاً للوزن الزائد. (المصدر: N.J.S.A. 39:3-84؛ دليل NJDOT للأحجام والأوزان.)"},"2":{"q":"على معظم طرق نيو جيرسي التي ليست جزءاً من الشبكة المخصصة لعرض 102 بوصة أو الشبكة الوطنية، ما هو الحد الأقصى القانوني لعرض المركبة؟","options":["96 بوصة (8 أقدام)","102 بوصة (8 أقدام و6 بوصات)","108 بوصات (9 أقدام)","90 بوصة (7 أقدام و6 بوصات)"],"explanation":"في حين أن الشبكة الوطنية المخصصة وشبكة شاحنات نيو جيرسي بعرض 102 بوصة تسمحان بعرض 102 بوصة (8 أقدام و6 بوصات)، فإن الطرق العامة الأخرى محدودة بـ 96 بوصة (8 أقدام). (المصدر: N.J.S.A. 39:3-84؛ شبكة J.J. Keller للامتثال، حدود الأحجام/الأوزان في نيو جيرسي.)"},"3":{"q":"ما هو الحد الأقصى للعرض، بما في ذلك الحمولة، المسموح به للشاحنات على الشبكة الوطنية المخصصة في نيو جيرسي وشبكة مسارات الشاحنات بعرض 102 بوصة؟","options":["102 بوصة (8 أقدام و6 بوصات)","96 بوصة (8 أقدام)","120 بوصة (10 أقدام)","114 بوصة (9 أقدام و6 بوصات)"],"explanation":"على الشبكة الوطنية المخصصة وشبكة مسارات شاحنات نيو جيرسي بعرض 102 بوصة، يبلغ الحد الأقصى للعرض الخارجي 102 بوصة (8 أقدام و6 بوصات)، وفقاً لـ N.J.S.A. 39:3-84. (المصدر: N.J.S.A. 39:3-84؛ دليل NJDOT للأحجام والأوزان.)"},"4":{"q":"بموجب قانون نيو جيرسي، ما هو الحد الأقصى للوزن الإجمالي الذي يمكن حمله على أي محور مفرد؟","options":["22,400 رطل","20,000 رطل","34,000 رطل","24,000 رطل"],"explanation":"تسمح نيو جيرسي بما يصل إلى 22,400 رطل على المحور المفرد، وهو أعلى من الرقم الفيدرالي الأساسي البالغ 20,000 رطل للمحور المفرد (N.J.S.A. 39:3-84). (المصدر: N.J.S.A. 39:3-84؛ شبكة J.J. Keller للامتثال.)"},"5":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على مجموعة المحاور المزدوجة على طرق نيو جيرسي السريعة؟","options":["34,000 رطل","22,400 رطل","40,000 رطل","36,000 رطل"],"explanation":"تحدد نيو جيرسي مجموعة المحاور المزدوجة بـ 34,000 رطل، وهو نفس المعيار الفيدرالي (N.J.S.A. 39:3-84). (المصدر: N.J.S.A. 39:3-84؛ دليل NJDOT للأحجام والأوزان.)"},"6":{"q":"ما هو الحد الأقصى للطول الكلي لشاحنة مفردة (مستقيمة) على طرق نيو جيرسي السريعة عندما لا تحمل حمولة غير قابلة للتجزئة؟","options":["40 قدماً","35 قدماً","45 قدماً","53 قدماً"],"explanation":"يحدد N.J.S.A. 39:3-84 الطول الكلي للمركبة المفردة بـ 40 قدماً (ويمتد إلى 50 قدماً فقط عند حمل أعمدة أو ركائز أو غيرها من المواد التي لا يمكن تجزئتها). (المصدر: N.J.S.A. 39:3-84.)"},"7":{"q":"بموجب قانون نيو جيرسي، ما هو الحد الأقصى للطول الكلي لمجموعة الجرار-الشاحنة ونصف المقطورة (وحدة القوة بالإضافة إلى حمولتها) على الطرق السريعة العامة؟","options":["62 قدماً","53 قدماً","65 قدماً","75 قدماً"],"explanation":"يحدد N.J.S.A. 39:3-84 الطول الكلي لمجموعة المركبات، بما في ذلك الحمولة، بـ 62 قدماً. لاحظ أنه على الشبكة الوطنية لا يوجد حد للطول الكلي للجرار-نصف المقطورة، مع تحديد نصف المقطورة نفسها بحد أقصى 53 قدماً. (المصدر: N.J.S.A. 39:3-84؛ دليل NJDOT للأحجام والأوزان.)"},"8":{"q":"على الشبكة الوطنية لنيو جيرسي والمسارات المخصصة بعرض 102 بوصة، ما هو الحد الأقصى لطول نصف المقطورة العاملة في مجموعة جرار-نصف مقطورة؟","options":["53 قدماً","48 قدماً","57 قدماً","45 قدماً"],"explanation":"يمكن أن يصل طول نصف المقطورة إلى 53 قدماً على الشبكة الوطنية وشبكة نيو جيرسي بعرض 102 بوصة (48 قدماً على الطرق السريعة الأخرى)، وفقاً لقواعد NJDOT و N.J.S.A. 39:3-84. (المصدر: دليل NJDOT لأحجام وأوزان المركبات التجارية؛ شبكة J.J. Keller للامتثال.)"},"9":{"q":"بالنسبة لنصف مقطورة يتراوح طولها بين 48 و53 قدماً وتعمل على الشبكة المخصصة في نيو جيرسي، ما هو الحد الأقصى المسموح به للمسافة من المسمار الملكي (kingpin) إلى مركز المحور الخلفي؟","options":["41 قدماً","37 قدماً","46 قدماً","53 قدماً"],"explanation":"بالنسبة للمقطورات التي يزيد طولها عن 48 قدماً وحتى 53 قدماً، لا يمكن أن تتجاوز المسافة من المسمار الملكي إلى مركز المحور الخلفي 41 قدماً على الشبكة الوطنية السريعة/المخصصة. (المصدر: دليل NJDOT لأحجام وأوزان المركبات التجارية؛ شبكة J.J. Keller للامتثال.)"},"10":{"q":"في مجموعة المقطورتين (المزدوجة) التي تعمل على الشبكة المخصصة في نيو جيرسي، ما هو الحد الأقصى لطول كل وحدة مقطورة؟","options":["28 قدماً","33 قدماً","40 قدماً","53 قدماً"],"explanation":"تقتصر كل مقطورة في مجموعة المقطورتين في نيو جيرسي على 28 قدماً، بما يتفق مع المعيار الفيدرالي للمقطورة المزدوجة (STAA) المعترف به بموجب N.J.S.A. 39:3-84. (المصدر: N.J.S.A. 39:3-84؛ شبكة J.J. Keller للامتثال.)"},"11":{"q":"ما هو الحد الأقصى للحمولة الإجمالية التي تسمح بها نيو جيرسي لكل بوصة من عرض الإطار؟","options":["800 رطل","650 رطلاً","500 رطل","1,000 رطل"],"explanation":"تحدد نيو جيرسي الحمولة بـ 800 رطل لكل بوصة من عرض الإطار (N.J.S.A. 39:3-84). (المصدر: N.J.S.A. 39:3-84؛ شبكة J.J. Keller للامتثال، حدود الأحجام/الأوزان في نيو جيرسي.)"},"12":{"q":"صيغة الجسر الفيدرالية المستخدمة في نيو جيرسي، W = 500[LN/(N-1) + 12N + 36]، تحدد أي قيمة؟","options":["الحد الأقصى للوزن الإجمالي المسموح به على مجموعة من المحاور المتتالية بناءً على تباعدها وعددها","الحد الأقصى لارتفاع المركبة بناءً على قاعدة العجلات","الحد الأقصى للعرض بناءً على عدد الإطارات","الحد الأدنى المطلوب لمسافة التوقف لمجموعة محملة"],"explanation":"تحسب صيغة الجسر الفيدرالية، المطبقة في نيو جيرسي، الحد الأقصى المسموح به للوزن الإجمالي (W) على أي مجموعة من محورين متتاليين أو أكثر، حيث L هي المسافة بين المحاور الخارجية و N هي عدد المحاور. (المصدر: 23 CFR 658 / صيغة الجسر الفيدرالية كما تطبقها NJDOT؛ دليل NJDOT للأحجام والأوزان.)"},"13":{"q":"في صيغة الجسر الفيدرالية كما تُستخدم في نيو جيرسي، ماذا يمثل المتغير 'L'؟","options":["المسافة بالأقدام بين المحاور الخارجية لمجموعة المحاور","الطول الكلي للمقطورة","حد الحمولة القانوني بالأرطال","بدل وزن محور الرفع"],"explanation":"في W = 500[LN/(N-1) + 12N + 36]، 'L' هي المسافة بالأقدام بين المحاور الخارجية للمجموعة قيد الدراسة، و'N' هي عدد المحاور في تلك المجموعة. (المصدر: صيغة الجسر الفيدرالية، 23 CFR 658، كما تطبقها NJDOT.)"},"14":{"q":"متى يُصدَر تصريح الحجم الزائد/الوزن الزائد (OS/OW) في نيو جيرسي لحمولة تتجاوز حدود الحجم أو الوزن القانونية؟","options":["فقط عندما تكون الحمولة غير قابلة للتجزئة (لا يمكن تفكيكها أو تقسيمها لتلبية الحدود القانونية)","لأي حمولة، قابلة للتجزئة أم لا، طالما تم دفع رسم","فقط لحمولات المنتجات الزراعية","فقط في عطلات نهاية الأسبوع والعطلات الرسمية"],"explanation":"تُصدر NJDOT تصاريح OS/OW فقط للحمولات غير القابلة للتجزئة، المعرَّفة بأنها الحمولات التي لا يمكن تفكيكها أو تفكيك أجزائها أو تقسيمها بحيث تلبي حدود الوزن والأبعاد. (المصدر: دليل NJDOT المرجعي لتصاريح OS/OW؛ nj.gotpermits.com.)"},"15":{"q":"كيف يتقدم الناقل في نيو جيرسي بطلب للحصول على تصريح نقل الحجم الزائد/الوزن الزائد؟","options":["عبر الإنترنت على مدار الساعة طوال أيام الأسبوع من خلال موقع تصاريح OS/OW التابع لـ NJDOT (nj.gotpermits.com)","فقط شخصياً في مكتب كاتب المقاطعة خلال ساعات العمل","بإرسال نموذج موثَّق بالبريد إلى شرطة الولاية","تلقائياً مع إصدار رخصة CDL"],"explanation":"يجوز للناقلين التقدم بطلب للحصول على تصاريح OS/OW التابعة لـ NJDOT عبر الإنترنت على مدار 24 ساعة في اليوم، 7 أيام في الأسبوع على موقع تصاريح OS/OW التابع لـ NJDOT (nj.gotpermits.com)، إما مباشرة أو من خلال خدمة تصاريح مسجلة. (المصدر: دليل NJDOT المرجعي لتصاريح OS/OW؛ nj.gotpermits.com.)"},"16":{"q":"عند أي عرض للحمولة (بما في ذلك الحمولة) تتطلب نيو جيرسي مركبة مرافقة واحدة على الأقل لعملية نقل حجم زائد مرخَّصة؟","options":["عندما يتجاوز العرض 14 قدماً","عندما يتجاوز العرض 10 أقدام","عندما يتجاوز العرض 8 أقدام و6 بوصات","عندما يتجاوز العرض 16 قدماً"],"explanation":"بموجب قواعد تصاريح NJDOT، تُطلب مركبة مرافقة واحدة عندما يتجاوز العرض بما في ذلك الحمولة 14 قدماً؛ وتُطلب مركبتان مرافقتان عندما يتجاوز العرض 16 قدماً. (المصدر: دليل NJDOT المرجعي لتصاريح OS/OW؛ لوائح oversize.io لنيو جيرسي.)"},"17":{"q":"يريد ناقل نقل قطعة آلية واحدة غير قابلة للتجزئة على جرار-نصف مقطورة سيبلغ وزنها الإجمالي 110,000 رطل وعرضها 12 قدماً على طريق سريع تابع لولاية نيو جيرسي. ماذا يجب على الناقل أن يفعل؟","options":["الحصول على تصريح الحجم الزائد/الوزن الزائد من NJDOT قبل النقل، لأن كلاً من الوزن والعرض يتجاوزان الحدود القانونية","لا شيء، لأن الحمولات غير القابلة للتجزئة معفاة تلقائياً من جميع الحدود","فقط تسجيل المركبة كزراعية لتكون معفاة","السفر فقط ليلاً دون أي تصريح"],"explanation":"تتجاوز الحمولة حد الوزن الإجمالي البالغ 80,000 رطل وحد العرض البالغ 102 بوصة (8 أقدام و6 بوصات)، لذا يلزم تصريح OS/OW من NJDOT لهذه الحمولة غير القابلة للتجزئة قبل السفر، يُحصَل عليه عبر nj.gotpermits.com. وعرض 12 قدماً أقل من عتبة المرافقة البالغة 14 قدماً. (المصدر: N.J.S.A. 39:3-84؛ دليل NJDOT المرجعي لتصاريح OS/OW.)"},"18":{"q":"في نيو جيرسي، أي فئة من رخص CDL مطلوبة لتشغيل مركبة مركَّبة بتصنيف وزن مجموعة المركبات الإجمالي (GCWR) يبلغ 26,001 رطل أو أكثر، حيث تكون الوحدة المقطورة بتصنيف وزن المركبة الإجمالي (GVWR) أكثر من 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"يعرِّف دليل CDL لنيو جيرسي الفئة A بأنها أي مجموعة من المركبات بتصنيف GCWR يبلغ 26,001 رطل أو أكثر، شريطة أن يكون تصنيف GVWR للوحدة (الوحدات) المقطورة أكثر من 10,000 رطل. المصدر: دليل رخصة القيادة التجارية الصادر عن NJ MVC (تعريفات الفئات)."},"19":{"q":"بموجب قواعد نيو جيرسي، تتطلب مركبة مفردة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر، أو مثل هذه المركبة وهي تقطر وحدة لا يتجاوز تصنيف GVWR لها 10,000 رطل، أي فئة من رخص CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة E"],"explanation":"يعرِّف دليل CDL لنيو جيرسي الفئة B بأنها أي مركبة مفردة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر، أو تلك المركبة وهي تقطر وحدة يبلغ تصنيف GVWR لها 10,000 رطل أو أقل. المصدر: دليل رخصة القيادة التجارية الصادر عن NJ MVC."},"20":{"q":"في نيو جيرسي، تتطلب مركبة مصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق)، أو مركبة أصغر تنقل مواد خطرة تحمل لوحات تحذيرية، أي فئة من رخص CDL كحد أدنى؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"يعرِّف دليل CDL لنيو جيرسي الفئة C بأنها مركبة لا تستوفي معايير الفئة A أو B لكنها مصممة لنقل 16 راكباً أو أكثر بما في ذلك المشغِّل، أو تُستخدم لنقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: دليل رخصة القيادة التجارية الصادر عن NJ MVC."},"21":{"q":"مركبة في نيو جيرسي مصممة لحمل 16 راكباً أو أكثر بما في ذلك السائق لكن وزنها أقل من 26,001 رطل. ما هي الفئة الدنيا المطلوبة من رخص CDL؟","options":["لا حاجة لرخصة CDL","الفئة A","الفئة B","الفئة C"],"explanation":"حتى عند كونها دون عتبات الوزن للفئة A أو B، فإن المركبة المصممة لحمل 16 شخصاً أو أكثر بما في ذلك المشغِّل تندرج ضمن الفئة C في نيو جيرسي. المصدر: دليل رخصة القيادة التجارية الصادر عن NJ MVC (تعريف الفئة C)."},"22":{"q":"أي تصديق يحتاجه حامل رخصة CDL في نيو جيرسي لقيادة مركبة تنقل سوائل أو غازات بكميات كبيرة في خزان مثبَّت بشكل دائم؟","options":["N (مركبة صهريجية)","T (مزدوجة/ثلاثية)","H (المواد الخطرة)","P (الركاب)"],"explanation":"تصديق N (المركبة الصهريجية) مطلوب في نيو جيرسي لتشغيل المركبات التي تنقل سوائل أو غازات بكميات كبيرة. المصدر: صفحة التصديقات الخاصة بـ NJ MVC."},"23":{"q":"في نيو جيرسي، أي تصديق مطلوب لقطر مقطورتين أو ثلاث مقطورات، وأي فئة من رخص CDL يجب أن يحملها السائق؟","options":["تصديق T، مع رخصة CDL من الفئة A","تصديق N، مع رخصة CDL من الفئة B","تصديق T، مع رخصة CDL من الفئة C","تصديق P، مع رخصة CDL من الفئة A"],"explanation":"تصديق T (المزدوجة/الثلاثية) مطلوب لقطر مقطورتين أو ثلاث مقطورات، ويلزم حمل رخصة CDL من الفئة A للحصول عليه. المصدر: صفحة التصديقات الخاصة بـ NJ MVC."},"24":{"q":"قبل أن تصدر نيو جيرسي تصديق المواد الخطرة (H)، يجب على مقدم الطلب اجتياز فحص الخلفية الذي تجريه أي جهة؟","options":["إدارة أمن النقل (TSA)","وحدة الاحتيال في NJ MVC","الإدارة الفيدرالية لسلامة الناقلات بالمركبات (FMCSA)","شرطة ولاية نيو جيرسي فقط"],"explanation":"تشترط نيو جيرسي على المتقدمين للحصول على تصديق المواد الخطرة (H) أخذ بصماتهم واجتياز تقييم التهديد الذي تجريه إدارة أمن النقل (TSA) قبل إصدار التصديق. المصدر: صفحة تصديقات المواد الخطرة (HME) الخاصة بـ NJ MVC؛ برنامج HME التابع لـ TSA."},"25":{"q":"لقيادة حافلة مدرسية في نيو جيرسي، أي مزيج من تصديقات CDL مطلوب؟","options":["كلاً من P (الركاب) و S (الحافلة المدرسية)","S (الحافلة المدرسية) فقط","P (الركاب) فقط","S و H"],"explanation":"تشترط نيو جيرسي على سائقي الحافلات المدرسية حمل كلٍّ من تصديق P (الركاب) و S (الحافلة المدرسية)، بالإضافة إلى اجتياز اختبار المعرفة واختبار الطريق وفحص الخلفية. المصدر: صفحة التصديقات الخاصة بـ NJ MVC."},"26":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL من نيو جيرسي مقيَّدة بالتشغيل داخل الولاية (داخل نيو جيرسي فقط)؟","options":["18 عاماً","21 عاماً","19 عاماً","17 عاماً"],"explanation":"يجوز للسائق الحصول على رخصة CDL من نيو جيرسي في سن 18، لكن التشغيل يقتصر على التجارة داخل الولاية (داخل نيو جيرسي) حتى سن 21. المصدر: صفحة الحصول على رخصة CDL الخاصة بـ NJ MVC."},"27":{"q":"ما هو الحد الأدنى للعمر المطلوب لتشغيل مركبة تجارية محركة في التجارة بين الولايات برخصة CDL من نيو جيرسي؟","options":["21 عاماً","18 عاماً","23 عاماً","19 عاماً"],"explanation":"يجوز للسائقين دون سن 21 الحاملين لرخصة CDL من نيو جيرسي التشغيل داخل الولاية فقط؛ أما التجارة بين الولايات (والمواد الخطرة) فتتطلب أن يكون عمر السائق 21 عاماً على الأقل. المصدر: صفحة الحصول على رخصة CDL الخاصة بـ NJ MVC."},"28":{"q":"بموجب القواعد الفيدرالية المطبَّقة في نيو جيرسي، كم يجب أن ينتظر حامل تصريح المتعلم التجاري (CLP) بعد إصدار CLP قبل أداء اختبار مهارات CDL؟","options":["14 يوماً على الأقل","30 يوماً على الأقل","7 أيام على الأقل","60 يوماً على الأقل"],"explanation":"تطبق نيو جيرسي الاشتراط الفيدرالي بأن على حامل CLP الانتظار 14 يوماً على الأقل قبل أداء اختبار المهارات. المصدر: صفحات الحصول على CDL / CLP الخاصة بـ NJ MVC."},"29":{"q":"بمجرد إصداره، إلى متى يبقى تصريح المتعلم التجاري (CLP) في نيو جيرسي صالحاً؟","options":["180 يوماً","سنة واحدة","90 يوماً","60 يوماً"],"explanation":"يبقى تصريح CLP في نيو جيرسي صالحاً لمدة 180 يوماً عند إصداره. المصدر: صفحة تصاريح المتعلم التجاري (CLP) الخاصة بـ NJ MVC."},"30":{"q":"عند تشغيل مركبة تجارية محركة بتصريح المتعلم التجاري في نيو جيرسي، يجب أن يكون بحوزة السائق أيضاً ماذا؟","options":["رخصة قيادة سارية من نيو جيرسي","جواز سفر","تصريح CLP ثانٍ","لا شيء إضافي"],"explanation":"يجب أن يكون تصريح CLP في نيو جيرسي مصحوباً برخصة قيادة سارية من نيو جيرسي عندما يشغِّل حامله مركبة تجارية محركة. المصدر: صفحة تصاريح المتعلم التجاري (CLP) الخاصة بـ NJ MVC."},"31":{"q":"تشترط نيو جيرسي على المتقدمين للحصول على رخصة CDL استيفاء معيار التحقق من الهوية الخاص بها من خلال تقديم كم نقطة من نقاط إثبات الهوية؟","options":["6 نقاط لإثبات الهوية","4 نقاط لإثبات الهوية","8 نقاط لإثبات الهوية","نقطتان لإثبات الهوية"],"explanation":"تستخدم نيو جيرسي نظام 6 نقاط لإثبات الهوية، الذي يتطلب وثائق تثبت الهوية ورقم الضمان الاجتماعي وإثبات العنوان وإثبات التواجد القانوني في الولايات المتحدة. المصدر: صفحة الحصول على CDL / 6 نقاط لإثبات الهوية الخاصة بـ NJ MVC."},"32":{"q":"أي من الوثائق التالية مطلوبة تحديداً كجزء من التحقق من الهوية لرخصة CDL في نيو جيرسي؟","options":["بطاقة الضمان الاجتماعي وإثبات التواجد القانوني في الولايات المتحدة","شهادة ميلاد من أي بلد فقط","بطاقة عضوية نقابية","خطاب من صاحب العمل فقط"],"explanation":"تشمل نقاط الهوية الست لرخصة CDL في نيو جيرسي بطاقة الضمان الاجتماعي وإثبات العنوان وإثبات التواجد القانوني في الولايات المتحدة. المصدر: صفحة الحصول على رخصة CDL الخاصة بـ NJ MVC."},"33":{"q":"تدريب السائقين المبتدئين (ELDT) المطلوب قبل اختبار مهارات CDL لأول مرة في نيو جيرسي يجب الحصول عليه من مزوِّد:","options":["مُدرَج في سجل مزوِّدي التدريب التابع لـ FMCSA","معتمد من NJ MVC فقط","أي مدرسة قيادة تجارية","معتمد من TSA"],"explanation":"منذ 7 فبراير 2022، يجب إكمال تدريب ELDT من خلال مزوِّد مُدرَج في سجل مزوِّدي التدريب التابع لـ FMCSA قبل أداء اختبار المهارات (أو اختبار المعرفة للمواد الخطرة). المصدر: صفحة الحصول على CDL الخاصة بـ NJ MVC؛ سجل مزوِّدي التدريب التابع لـ FMCSA."},"34":{"q":"لأي تصديق يجب إكمال تدريب ELDT في نيو جيرسي قبل اختبار المعرفة (الكتابي)، بدلاً من قبل اختبار المهارات؟","options":["H (المواد الخطرة)","P (الركاب)","S (الحافلة المدرسية)","N (المركبة الصهريجية)"],"explanation":"بالنسبة لتصديق المواد الخطرة (H)، يجب إكمال تدريب ELDT قبل اختبار المعرفة؛ أما بالنسبة للفئة A/B لأول مرة وتصديقي P و S، فإن تدريب ELDT مطلوب قبل اختبار المهارات. المصدر: صفحات CLP/CDL الخاصة بـ NJ MVC؛ قاعدة ELDT التابعة لـ FMCSA."},"35":{"q":"سائق رخصة CDL في نيو جيرسي يعمل داخل نيو جيرسي فقط ويجب أن يستوفي اشتراط شهادة الفاحص الطبي للولاية ينبغي أن يصدِّق ذاتياً تحت أي فئة؟","options":["غير معفى داخل الولاية","غير معفى بين الولايات","معفى بين الولايات","معفى داخل الولاية"],"explanation":"تنطبق فئة غير معفى داخل الولاية (NA) على السائقين العاملين داخل نيو جيرسي فقط الذين يجب أن يستوفوا اشتراطات الشهادة الطبية. المصدر: التصديق الذاتي لحامل رخصة CDL الخاص بـ NJ MVC؛ فئات التصديق الطبي التابعة لـ FMCSA."},"36":{"q":"أي فئة من فئات التصديق الطبي الذاتي تنطبق على حامل رخصة CDL في نيو جيرسي يقود عبر حدود الولايات ويجب أن يحمل شهادة فاحص طبي سارية من DOT؟","options":["غير معفى بين الولايات","معفى بين الولايات","غير معفى داخل الولاية","معفى داخل الولاية"],"explanation":"السائقون غير المعفيين بين الولايات (NI) يعملون في التجارة بين الولايات ويجب أن يستوفوا اشتراطات البطاقة الطبية الفيدرالية من DOT، مع الاحتفاظ بشهادة من فاحص مدرَج في السجل الوطني في ملفهم. المصدر: التصديق الذاتي لرخصة CDL الخاص بـ NJ MVC؛ فئات FMCSA."},"37":{"q":"سائق في نيو جيرسي يصدِّق ذاتياً بأنه غير معفى بين الولايات يجب أن يحصل على شهادة فاحص طبي من مزوِّد:","options":["مدرَج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA","أي طبيب مرخَّص في نيو جيرسي","معتمد من كاتب المقاطعة المحلي","معتمد من TSA"],"explanation":"يجب فحص السائقين غير المعفيين من قبل فاحص طبي مدرَج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA والاحتفاظ بالشهادة في الملف. المصدر: التصديق الذاتي لرخصة CDL الخاص بـ NJ MVC؛ السجل الوطني التابع لـ FMCSA."},"38":{"q":"في نيو جيرسي، ما هو الحد الأقصى القانوني لتركيز الكحول في الدم (BAC) للشخص الذي يشغِّل مركبة تجارية محركة (CMV)؟","options":["0.02","0.04","0.08","0.10"],"explanation":"تتبع نيو جيرسي المعيار الفيدرالي للمركبات التجارية المحركة: من غير القانوني تشغيل مركبة تجارية محركة بتركيز كحول في الدم BAC يبلغ 0.04 بالمئة أو أعلى. وهذا أكثر صرامة من حد 0.08 للمركبة الشخصية. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1 (حالات سحب الأهلية)؛ 49 CFR 383.51."},"39":{"q":"بموجب قواعد الموافقة الضمنية في نيو جيرسي لحاملي رخص CDL، ماذا يحدث إذا رفض السائق الخضوع لاختبار تركيز الكحول عند تشغيل مركبة تجارية محركة؟","options":["تُفرض غرامة فقط، دون سحب للأهلية","يُعامَل ذلك كمخالفة كبرى، تسحب أهلية السائق تماماً كما تفعل إدانة بالقيادة تحت تأثير الكحول","يتلقى السائق تحذيراً عند الرفض الأول","تُعلَّق رخصة CDL لمدة 30 يوماً فقط"],"explanation":"بحمل رخصة CDL والقيادة في نيو جيرسي، يمنح السائق موافقة ضمنية على اختبار الكحول. ويُعامَل رفض الاختبار كمخالفة كبرى ويحمل نفس سحب الأهلية الذي تحمله إدانة بالقيادة تحت تأثير الكحول (سنة واحدة للمخالفة الأولى). المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 1."},"40":{"q":"في نيو جيرسي، ما هو الحد الأدنى لمدة سحب أهلية CDL لأول مخالفة كبرى، مثل أول إدانة بالقيادة تحت تأثير الكحول أثناء تشغيل مركبة تجارية محركة لا تحمل لوحات تحذيرية؟","options":["60 يوماً","120 يوماً","سنة واحدة","3 سنوات"],"explanation":"تؤدي أول مخالفة كبرى (بما في ذلك القيادة تحت تأثير الكحول، أو تركيز كحول في الدم يبلغ 0.04 أو أعلى، أو رفض الاختبار) إلى سحب أهلية CDL لمدة سنة واحدة على الأقل. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 1."},"41":{"q":"إذا ارتكب سائق رخصة CDL في نيو جيرسي أول مخالفة كبرى (مثل القيادة تحت تأثير الكحول) أثناء تشغيل مركبة تحمل لوحات تحذيرية للمواد الخطرة، فما هي مدة سحب الأهلية؟","options":["سنة واحدة","18 شهراً","3 سنوات","5 سنوات"],"explanation":"ترفع أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة تحمل لوحات تحذيرية مدة سحب الأهلية من سنة واحدة إلى 3 سنوات. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 1."},"42":{"q":"ما هي مدة سحب أهلية CDL في نيو جيرسي لثاني مخالفة كبرى (على سبيل المثال، ثاني إدانة بالقيادة تحت تأثير الكحول في أي وقت)؟","options":["3 سنوات","5 سنوات","10 سنوات","مدى الحياة"],"explanation":"تؤدي ثاني مخالفة كبرى إلى سحب أهلية CDL مدى الحياة. وتتبع نيو جيرسي القاعدة الفيدرالية التي تقضي بأن مخالفتين كبريين منفصلتين تعنيان فقدان السائق لرخصة CDL مدى الحياة. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 1."},"43":{"q":"في نيو جيرسي، كم عدد المخالفات المرورية الجسيمة خلال فترة 3 سنوات (في حوادث منفصلة) التي تؤدي إلى سحب أهلية CDL لمدة 60 يوماً؟","options":["1","2","3","4"],"explanation":"تؤدي ثاني مخالفة مرورية جسيمة خلال 3 سنوات (في حادث منفصل) إلى سحب الأهلية لمدة 60 يوماً. أما المخالفة الجسيمة الأولى وحدها فلا تسبب سحب الأهلية. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 2."},"44":{"q":"ما هي مدة سحب أهلية CDL في نيو جيرسي لثالث مخالفة مرورية جسيمة خلال فترة 3 سنوات (في حوادث منفصلة)؟","options":["60 يوماً","90 يوماً","120 يوماً","سنة واحدة"],"explanation":"تؤدي ثالث مخالفة مرورية جسيمة خلال 3 سنوات إلى سحب الأهلية لمدة 120 يوماً. أما الثانية خلال 3 سنوات فهي 60 يوماً. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 2."},"45":{"q":"أي مما يلي يُصنَّف كمخالفة مرورية جسيمة لحامل رخصة CDL في نيو جيرسي؟","options":["إيقاف مركبة تجارية محركة في منطقة ممنوع الوقوف فيها","تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فوق حد السرعة المعلن","مصباح إضاءة محترق","عدم الحفاظ على دفتر السجل مرتباً"],"explanation":"تُعَد السرعة المفرطة، المعرَّفة بأنها 15 ميلاً في الساعة أو أكثر فوق الحد المعلن، مخالفة مرورية جسيمة. وتشمل الأخرى القيادة المتهورة، وتغيير المسارات غير السليم، والاقتراب الشديد من المركبات الأخرى، والمراسلة النصية أثناء القيادة. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 2."},"46":{"q":"في نيو جيرسي، ما هو الحد الأدنى لسحب أهلية CDL لأول إدانة بمخالفة معبر السكة الحديدية-الطريق السريع أثناء تشغيل مركبة تجارية محركة؟","options":["30 يوماً","60 يوماً","120 يوماً","سنة واحدة"],"explanation":"تؤدي أول مخالفة لمعبر السكة الحديدية-الطريق السريع إلى سحب الأهلية لمدة 60 يوماً كحد أدنى. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 3."},"47":{"q":"ما هو الحد الأدنى لسحب أهلية CDL في نيو جيرسي لثاني مخالفة لمعبر السكة الحديدية-الطريق السريع خلال فترة 3 سنوات؟","options":["60 يوماً","90 يوماً","120 يوماً","سنة واحدة"],"explanation":"تؤدي ثاني مخالفة لمعبر السكة الحديدية-الطريق السريع خلال 3 سنوات إلى سحب الأهلية لمدة 120 يوماً كحد أدنى. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 3."},"48":{"q":"ما هو الحد الأدنى لسحب أهلية CDL في نيو جيرسي لثالث مخالفة لمعبر السكة الحديدية-الطريق السريع خلال فترة 3 سنوات؟","options":["120 يوماً","180 يوماً","سنة واحدة","3 سنوات"],"explanation":"تؤدي ثالث مخالفة لمعبر السكة الحديدية-الطريق السريع خلال 3 سنوات إلى سحب الأهلية لمدة سنة واحدة كحد أدنى. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 3."},"49":{"q":"في نيو جيرسي، ما هو الحد الأدنى لسحب الأهلية لأول إدانة لسائق رخصة CDL بانتهاك أمر إيقاف عن الخدمة (OOS) أثناء عدم نقل مواد خطرة أو ركاب؟","options":["90 يوماً","120 يوماً","180 يوماً","سنة واحدة"],"explanation":"تحمل أول إدانة بانتهاك أمر إيقاف عن الخدمة سحب الأهلية لمدة 180 يوماً على الأقل (حتى سنة واحدة). المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 4."},"50":{"q":"ما هو نطاق سحب الأهلية في نيو جيرسي لثاني انتهاك لأمر إيقاف عن الخدمة خلال فترة 10 سنوات (دون مواد خطرة، دون ركاب)؟","options":["180 يوماً إلى سنة واحدة","1 إلى 2 سنة","2 إلى 5 سنوات","3 إلى 5 سنوات"],"explanation":"يؤدي ثاني انتهاك لأمر إيقاف عن الخدمة خلال 10 سنوات إلى سحب الأهلية لمدة 2 إلى 5 سنوات. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 4."},"51":{"q":"ما هو نطاق سحب الأهلية في نيو جيرسي لثالث انتهاك أو ما يليه لأمر إيقاف عن الخدمة خلال فترة 10 سنوات (دون مواد خطرة، دون ركاب)؟","options":["180 يوماً إلى سنة واحدة","2 إلى 5 سنوات","3 إلى 5 سنوات","مدى الحياة"],"explanation":"يؤدي ثالث انتهاك أو ما يليه لأمر إيقاف عن الخدمة خلال 10 سنوات إلى سحب الأهلية لمدة 3 إلى 5 سنوات. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 4."},"52":{"q":"في نيو جيرسي، بالإضافة إلى سحب الأهلية، ما هي الغرامة المدنية التي يواجهها سائق رخصة CDL لأول إدانة بانتهاك أمر إيقاف عن الخدمة؟","options":["1,000 دولار على الأقل","2,500 دولار على الأقل","5,000 دولار على الأقل","10,000 دولار على الأقل"],"explanation":"إلى جانب سحب الأهلية، يخضع السائق الذي ينتهك أمر إيقاف عن الخدمة لغرامة مدنية لا تقل عن 2,500 دولار للمخالفة الأولى، ولا تقل عن 5,000 دولار للمخالفة اللاحقة. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.53."},"53":{"q":"سائق رخصة CDL في نيو جيرسي ينتهك أمر إيقاف عن الخدمة أثناء نقل مواد خطرة تحمل لوحات تحذيرية يواجه أي حد أدنى لسحب الأهلية للمخالفة الأولى؟","options":["120 يوماً","180 يوماً","سنة واحدة","سنتان"],"explanation":"تحمل أول مخالفة لانتهاك أمر إيقاف عن الخدمة أثناء نقل مواد خطرة تتطلب لوحات تحذيرية (أو أثناء تشغيل مركبة مصممة لحمل 16 راكباً أو أكثر) سحب الأهلية لمدة 180 يوماً على الأقل، حتى سنتين. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 4."},"54":{"q":"بموجب القواعد الفيدرالية وقواعد نيو جيرسي، تُصنَّف المراسلة النصية أثناء قيادة مركبة تجارية محركة كأي نوع من المخالفات لحامل رخصة CDL؟","options":["مخالفة غير قابلة للتجريم","مخالفة مرورية جسيمة","مخالفة كبرى","انتهاك لأمر إيقاف عن الخدمة"],"explanation":"المراسلة النصية واستخدام هاتف محمول باليد أثناء قيادة مركبة تجارية محركة من المخالفات المرورية الجسيمة. ويؤدي ارتكاب اثنتين من هذه المخالفات خلال 3 سنوات إلى سحب الأهلية لمدة 60 يوماً؛ وثلاث منها تؤدي إلى 120 يوماً. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 2 و392.80/392.82."},"55":{"q":"ما هو الحد الأقصى لغرامة السائق لاستخدام هاتف محمول باليد أو المراسلة النصية أثناء تشغيل مركبة تجارية محركة الذي ينطبق على سائقي رخص CDL في نيو جيرسي؟","options":["حتى 500 دولار","حتى 1,000 دولار","حتى 2,750 دولاراً","حتى 5,000 دولار"],"explanation":"قد يُغرَّم سائق رخصة CDL الذي يستخدم هاتفاً محمولاً باليد أو يراسل نصياً أثناء قيادة مركبة تجارية محركة بمبلغ يصل إلى 2,750 دولاراً، وتُحتسب المخالفة كمخالفة مرورية جسيمة. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 392.82."},"56":{"q":"استخدام مركبة تجارية محركة في ارتكاب جناية تنطوي على تصنيع أو توزيع أو صرف مادة خاضعة للرقابة يحمل أي سحب لأهلية CDL في نيو جيرسي؟","options":["سنة واحدة","3 سنوات","10 سنوات","مدى الحياة دون إمكانية إعادة الإصدار"],"explanation":"استخدام مركبة تجارية محركة لارتكاب جناية تنطوي على مواد خاضعة للرقابة هو مخالفة كبرى تؤدي إلى سحب الأهلية مدى الحياة دون إمكانية إعادة الإصدار. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 1."},"57":{"q":"حامل رخصة CDL في نيو جيرسي يجمع أول إدانة بالقيادة تحت تأثير الكحول، ثم لاحقاً إدانة منفصلة بمغادرة مكان الحادث في مركبة تجارية محركة. ما هي نتيجة هذه المخالفة الكبرى الثانية؟","options":["سحب الأهلية لمدة 120 يوماً","سحب الأهلية لمدة سنة واحدة","سحب الأهلية لمدة 3 سنوات","سحب الأهلية مدى الحياة"],"explanation":"القيادة تحت تأثير الكحول ومغادرة مكان الحادث في مركبة تجارية محركة كلاهما مخالفتان كبريان. وأي مخالفتين كبريين (في حوادث منفصلة) تؤديان إلى سحب أهلية CDL مدى الحياة، حتى لو كانتا نوعين مختلفين من المخالفات الكبرى. المصدر: دليل CDL الخاص بـ NJ MVC، القسم 1؛ 49 CFR 383.51 الجدول 1."},"58":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في ولاية نيوجيرسي، ماذا يجب على سائق المركبة التجارية أن يفعل عند الاقتراب من مركبة طوارئ متوقفة أو شاحنة قطر أو مركبة صيانة طرق تعرض أضواءً وامضة على طريق سريع متعدد المسارات؟","options":["تغيير المسار إلى مسار غير ملاصق للمركبة المتوقفة، إذا أمكن القيام بذلك بأمان","التوقف التام حتى تبتعد المركبة المتوقفة","المتابعة بالسرعة المقررة مع إطلاق البوق أثناء التجاوز","الانحراف إلى الكتف والانتظار حتى يلوّح ضابط لحركة المرور بالمرور"],"explanation":"يتطلب قانون \"أفسح الطريق\" في نيوجيرسي (N.J.S.A. 39:4-92.2) من السائق المقترب على طريق متعدد المسارات تغيير المسار إلى مسار غير ملاصق للمركبة المتوقفة عندما يكون ذلك آمناً. المصدر: N.J.S.A. 39:4-92.2؛ NJ MVC."},"59":{"q":"بموجب قانون \"أفسح الطريق\" في نيوجيرسي، إذا لم يتمكن السائق من تغيير المسار بأمان مبتعداً عن مركبة طوارئ أو خدمة متوقفة ذات أضواء وامضة، فما المطلوب؟","options":["تخفيض السرعة إلى سرعة معقولة ومناسبة أقل من الحد المقرر والمتابعة بحذر","الحفاظ على الحد الأقصى المقرر للسرعة لتجنب إعاقة حركة المرور","التوقف التام في المسار الحالي حتى يتم إطفاء الأضواء","الانتقال إلى الجزيرة الوسطى بغض النظر عن الظروف"],"explanation":"ينص N.J.S.A. 39:4-92.2 على أنه عندما لا يمكن تغيير المسار بأمان، يجب على السائق التباطؤ إلى سرعة معقولة ومناسبة أقل من الحد المقرر وأن يكون مستعداً للتوقف. المصدر: N.J.S.A. 39:4-92.2؛ NJ MVC."},"60":{"q":"في نيوجيرسي، على أي مسافة يجب أن تتوقف الحافلة من أقرب قضيب لتقاطع السكة الحديدية مع الطريق قبل المتابعة؟","options":["بين 15 و50 قدماً","بين 5 و15 قدماً","بين 50 و100 قدم","بين 10 و25 قدماً"],"explanation":"يتطلب دليل CDL في نيوجيرسي (القسم 4، نقل الركاب) أن تتوقف الحافلة بين 15 و50 قدماً قبل تقاطع السكة الحديدية، ثم تنظر وتستمع للقطارات. المصدر: NJ MVC Commercial Driver License Manual, Sec. 4.3.5."},"61":{"q":"يجب على مركبة تحمل لافتات مواد خطرة في نيوجيرسي أن تتوقف ضمن أي مسافة من أقرب قضيب قبل عبور سكك القطار؟","options":["ليس أقرب من 15 قدماً وليس أبعد من 50 قدماً","ليس أقرب من 25 قدماً وليس أبعد من 75 قدماً","ليس أقرب من 10 أقدام وليس أبعد من 40 قدماً","ليس أقرب من 5 أقدام وليس أبعد من 30 قدماً"],"explanation":"ينص دليل CDL في نيوجيرسي (القسم 9، المواد الخطرة) على أن المركبة التي تحمل لافتات، أو التي تنقل أي كمية من الكلور، أو التي تحمل خزانات شحن مستخدمة للمواد الخطرة، يجب أن تتوقف على بعد 15 إلى 50 قدماً قبل أقرب قضيب. المصدر: NJ MVC CDL Manual, Sec. 9.6.12."},"62":{"q":"على طريق سريع غير مقسوم ذي مسارين في نيوجيرسي، تتوقف حافلة مدرسية بأضوائها الحمراء وامضة لاصطحاب الأطفال. على المركبة المقتربة من الحافلة أو المتجاوزة لها أن تتوقف على بعد لا يقل عن كم؟","options":["25 قدماً","10 أقدام","20 قدماً","50 قدماً"],"explanation":"يتطلب N.J.S.A. 39:4-128.1 من السائق المقترب من حافلة مدرسية أو المتجاوز لها بأضوائها الحمراء الوامضة على طريق غير مقسوم أن يتوقف على بعد لا يقل عن 25 قدماً ويبقى متوقفاً حتى تتوقف الأضواء عن الوميض. المصدر: N.J.S.A. 39:4-128.1."},"63":{"q":"بموجب قانون نيوجيرسي، ماذا يجب على السائق الموجود على طريق منفصل من طريق سريع مزدوج أو مقسوم والذي يقترب من حافلة مدرسية متوقفة بأضواء حمراء وامضة على الطريق الآخر أن يفعل؟","options":["تخفيض السرعة إلى ما لا يزيد عن 10 ميل في الساعة والمتابعة بحذر بجانب الحافلة","التوقف على بعد لا يقل عن 25 قدماً من الحافلة والانتظار حتى تتوقف الأضواء عن الوميض","التوقف التام والانتظار حتى يلوّح سائق الحافلة لحركة المرور بالمرور","المتابعة بالسرعة المقررة لأنه لا يلزم اتخاذ أي إجراء"],"explanation":"يوفر N.J.S.A. 39:4-128.1 استثناءً للطريق المقسوم: لا يحتاج السائق الموجود على طريق آخر من طريق سريع مزدوج أو مقسوم إلى التوقف، لكن عليه التباطؤ إلى ما لا يزيد عن 10 ميل في الساعة حتى يتجاوز الحافلة وأي أطفال. المصدر: N.J.S.A. 39:4-128.1."},"64":{"q":"عندما تتوقف مركبة تجارية في نيوجيرسي على طريق باتجاه واحد أو طريق مقسوم، يجب على السائق وضع أجهزة التحذير الثلاثة (المثلثات) على أي مسافات باتجاه حركة المرور المقتربة؟","options":["10 أقدام، و100 قدم، و200 قدم","10 أقدام، و50 قدماً، و100 قدم","25 قدماً، و100 قدم، و150 قدماً","10 أقدام، و200 قدم، و300 قدم"],"explanation":"يوجّه دليل CDL في نيوجيرسي بأنه على طريق باتجاه واحد أو طريق مقسوم، توضع أجهزة التحذير على بعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المقتربة. المصدر: NJ MVC CDL Manual, Sec. 2 (Driving Safely)."},"65":{"q":"بعد إيقاف مركبة تجارية على كتف طريق في نيوجيرسي، خلال كم دقيقة يجب على السائق وضع أجهزة التحذير من الطوارئ؟","options":["10 دقائق","5 دقائق","15 دقيقة","30 دقيقة"],"explanation":"يتطلب دليل CDL في نيوجيرسي أنه إذا اضطررت إلى التوقف على طريق أو كتف، فعليك وضع أجهزة التحذير من الطوارئ خلال 10 دقائق. المصدر: NJ MVC CDL Manual, Sec. 2 (Driving Safely)."},"66":{"q":"على طريق ذي مسارين يحمل حركة المرور في كلا الاتجاهين في نيوجيرسي، أين ينبغي وضع مثلثات التحذير لمركبة تجارية متوقفة؟","options":["ضمن 10 أقدام من المركبة و100 قدم خلفها وأمامها","100 قدم و200 قدم خلف المركبة فقط","ضمن 25 قدماً من المركبة و200 قدم خلفها","10 أقدام، و100 قدم، و200 قدم خلف المركبة فقط"],"explanation":"يوجّه دليل CDL في نيوجيرسي بأنه على طريق ذي مسارين يحمل حركة المرور في كلا الاتجاهين، يوضع مثلث ضمن 10 أقدام من الزوايا الأمامية أو الخلفية وأخرى على بعد 100 قدم خلف المركبة وأمامها. المصدر: NJ MVC CDL Manual, Sec. 2 (Driving Safely)."},"67":{"q":"يُمنع على المركبات التجارية ذات الوزن الإجمالي المسجل الذي يتجاوز 10,000 رطل استخدام طريق Garden State Parkway شمال أي تقاطع؟","options":["التقاطع 105","التقاطع 80","التقاطع 142","التقاطع 9"],"explanation":"تُمنع المركبات التجارية المسجلة بأكثر من 10,000 رطل من طريق Garden State Parkway شمال التقاطع 105 (مع استثناءات محدودة للحافلات والمركبات المرخصة ومركبات الهيئة). المصدر: NJ Turnpike Authority Parkway regulations؛ N.J.A.C. 19:9-1.9."},"68":{"q":"في قسم \"المزدوج-المزدوج\" (dual-dual) من طريق New Jersey Turnpike، ما الصحيح بشأن الطريق الداخلي بين الانفصال الجنوبي والاندماج الشمالي؟","options":["إنه مقتصر على السيارات فقط، بينما يحمل الطريق الخارجي السيارات والشاحنات","إنه مقتصر على الشاحنات فقط، بينما يحمل الطريق الخارجي السيارات فقط","إنه مخصص حصرياً للحافلات ومركبات الطوارئ","إنه يحمل حركة المرور باتجاه الشمال فقط، بغض النظر عن نوع المركبة"],"explanation":"في تكوين \"المزدوج-المزدوج\" لطريق New Jersey Turnpike، الطريق الداخلي مخصص للسيارات فقط بينما يحمل الطريق الخارجي كلاً من السيارات والشاحنات؛ تُوجَّه الشاحنات والحافلات إلى المسارات الخارجية. المصدر: NJ Turnpike Authority؛ NJ MVC."},"69":{"q":"بموجب قانون \"البقاء يميناً\" في نيوجيرسي، على طريق سريع متعدد المسارات، ماذا يجب على السائق الذي لا يتجاوز ولا يستعد للانعطاف يساراً أن يفعل؟","options":["البقاء في المسار الأيمن المتاح لحركة المرور","استخدام المسار الأوسط في جميع الأوقات","استخدام المسار الأقل ازدحاماً أياً كان","البقاء في المسار الأيسر لإبقاء اليمين خالياً للشاحنات"],"explanation":"يتطلب N.J.S.A. 39:4-82 من السائقين البقاء يميناً والقيادة في المسار الأيمن إلا عند التجاوز أو الاستعداد للانعطاف يساراً؛ وتُحدد العقوبات بموجب N.J.S.A. 39:4-88.1. المصدر: N.J.S.A. 39:4-82, 39:4-88.1."},"70":{"q":"بموجب لوائح نيوجيرسي، متى يجوز لشاحنة تزيد عن خمسة أطنان أن تسير في المسار الأيسر من طريق سريع مقسوم متعدد المسارات؟","options":["فقط للدخول إلى الطريق أو الخروج منه، أو في حالة طارئة، أو عندما تكون ضمن ميل واحد من انعطاف يساراً","في أي وقت تتجاوز فيه مركبة أبطأ","فقط بين منتصف الليل والساعة 6 صباحاً","في أي وقت تكون فيه حركة المرور في المسار الأيمن كثيفة"],"explanation":"تقيّد نيوجيرسي الشاحنات التي تزيد عن خمسة أطنان على الطرق السريعة المقسومة بالمسارات اليمنى، مع السماح بالمسار الأيسر فقط للدخول إلى الطريق/الخروج منه، أو في حالة طارئة، أو عندما تكون ضمن ميل واحد من انعطاف يساراً. المصدر: NJ keep-right rules؛ N.J.S.A. 39:4-82 وأحكام Title 39 ذات الصلة."},"71":{"q":"بموجب N.J.S.A. 39:4-98.1، يجوز لمفوّض النقل تحديد حد أقصى أدنى للسرعة للشاحنات التي يبلغ وزنها المسجل 10,000 رطل أو أكثر بفارق كم أقل من الحد المقرر على الطرق السريعة الحكومية المؤهلة متعددة المسارات؟","options":["5 ميل في الساعة","10 ميل في الساعة","15 ميل في الساعة","20 ميل في الساعة"],"explanation":"يخوّل N.J.S.A. 39:4-98.1 تحديد حد سرعة أدنى مقرر للشاحنات بفارق 5 ميل في الساعة للشاحنات التي يبلغ وزنها 10,000 رطل أو أكثر على الطرق السريعة الحكومية ذات أربعة مسارات أو أكثر حيث يكون الحد 50 ميل في الساعة أو أكثر. المصدر: N.J.S.A. 39:4-98.1."},"72":{"q":"بموجب قانون السرعة العام في نيوجيرسي، في غياب حد مقرر، ما هو حد السرعة القانوني لـ\"جميع المواقع الأخرى\" (التي ليست مناطق تجارية أو سكنية أو مدرسية)؟","options":["50 ميل في الساعة","55 ميل في الساعة","65 ميل في الساعة","45 ميل في الساعة"],"explanation":"يحدد N.J.S.A. 39:4-98 حدوداً مبدئية ظاهرة قدرها 25 ميل في الساعة في المناطق التجارية/السكنية، و35 ميل في الساعة في بعض المناطق الضاحوية، و50 ميل في الساعة في جميع المواقع الأخرى، ما لم يُقرّر حد مختلف. المصدر: N.J.S.A. 39:4-98."},"73":{"q":"أثناء عبور سكك القطار في مركبة تجارية في نيوجيرسي بعد التوقف المطلوب، ماذا يجب على السائق ألا يفعل؟","options":["تبديل التروس بينما أي جزء من المركبة على السكك","استخدام أضواء الطوارئ الرباعية أثناء الاقتراب","النظر والاستماع في كلا الاتجاهين بحثاً عن قطار","إنزال النافذة قبل العبور"],"explanation":"يوجّه دليل CDL في نيوجيرسي السائقين بعدم تبديل التروس أثناء عبور سكك القطار، حتى لا تتعطل المركبة على المعبر. المصدر: NJ MVC CDL Manual, Secs. 2.15 and 9.6.12."},"74":{"q":"لا يُطلب من سائق حافلة في نيوجيرسي التوقف عند تقاطع سكة حديدية في أي من الحالات التالية؟","options":["التقاطع موسوم بأنه \"معفى\" (exempt) أو \"مهجور\" (abandoned)","التقاطع به علامة صليب (crossbuck) لكن بلا بوابة","التقاطع به مجموعتان من السكك","التقاطع في منطقة ريفية بلا إشارات"],"explanation":"يسرد دليل CDL في نيوجيرسي استثناءات متطلب توقف الحافلة، بما في ذلك حيث يوجّه ضابط شرطة أو حامل العلم حركة المرور، وحيث تكون إشارة المرور خضراء، وعند التقاطعات الموسومة بأنها \"معفاة\" أو \"مهجورة\". المصدر: NJ MVC CDL Manual, Sec. 4.3.5."},"75":{"q":"في نيوجيرسي، عند تقاطع سكة حديدية به علامة صليب لكن بلا خط توقف أبيض مرسوم على الرصيف، يجب على المركبات المطلوب منها التوقف أن تتوقف ضمن أي نطاق من أقرب قضيب؟","options":["ليس أقرب من 15 قدماً وليس أبعد من 50 قدماً","ليس أقرب من 10 أقدام وليس أبعد من 30 قدماً","ليس أقرب من 20 قدماً وليس أبعد من 60 قدماً","ليس أقرب من 25 قدماً وليس أبعد من 100 قدم"],"explanation":"ينص دليل CDL في نيوجيرسي على أنه حيث لا يوجد خط توقف أبيض مرسوم، يجب على المركبات المطلوب منها التوقف أن تتوقف ليس أقرب من 15 قدماً وليس أكثر من 50 قدماً من أقرب قضيب. المصدر: NJ MVC CDL Manual, Sec. 2.15."},"76":{"q":"بدون تصريح للحمولة الزائدة الحجم، ما هو الحد الأقصى القانوني لعرض المركبة على طرق نيوجيرسي السريعة؟","options":["8 أقدام و6 بوصات","8 أقدام و0 بوصة","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"الحد الأقصى القانوني للعرض في نيوجيرسي هو 8 أقدام و6 بوصات (102 بوصة)؛ تتطلب الحمولات التي تتجاوز ذلك تصريحاً للحجم الزائد من NJDOT. الارتفاع القانوني القياسي هو 13 قدماً و6 بوصات والوزن الإجمالي 80,000 رطل. المصدر: NJDOT Commercial Vehicle size/weight regulations؛ Title 39."},"77":{"q":"تعطلت حافلة مدرسية على تقاطع سكة حديدية مع طريق في نيوجيرسي. وفقاً لدليل CDL في نيوجيرسي، ماذا ينبغي على السائق أن يفعل أولاً؟","options":["إخلاء الطلاب وقيادتهم إلى مسافة لا تقل عن 100 قدم بعيداً عن السكك بزاوية باتجاه أي قطار قادم","إبقاء الطلاب جالسين ومحاولة إعادة تشغيل المحرك أثناء التواجد على المعبر","جعل الطلاب يستلقون على أرضية الحافلة حتى تصل المساعدة","ترك الحافلة والركض على طول السكك للتلويح للقطار"],"explanation":"يوجّه دليل CDL في نيوجيرسي (قسم الحافلات المدرسية) السائق بالإخلاء فوراً وقيادة الطلاب إلى مكان آمن لا يقل عن 100 قدم بعيداً عن السكك، متحركين باتجاه القطار المقترب وبعيداً عنه بزاوية حتى لا تصيبهم الشظايا. المصدر: NJ MVC CDL Manual, Sec. 10 (School Buses)."},"78":{"q":"أي جهة تصدر رخص القيادة التجارية (CDLs) في نيوجيرسي؟","options":["هيئة المركبات الآلية في نيوجيرسي (New Jersey Motor Vehicle Commission - MVC)","إدارة النقل في نيوجيرسي (New Jersey Department of Transportation - NJDOT)","المكتب التجاري لشرطة ولاية نيوجيرسي (New Jersey State Police Commercial Bureau)","الإدارة الفيدرالية لسلامة الناقلين بالمركبات (Motor Carrier Safety Administration - FMCSA)"],"explanation":"في نيوجيرسي، تُصدر رخص CDL من قبل هيئة المركبات الآلية في نيوجيرسي (MVC). تتولى NJDOT الطرق وتصاريح الحجم/الوزن الزائد، وتضع FMCSA المعايير الفيدرالية لكنها لا تصدر الرخصة. المصدر: NJ MVC, Getting your Commercial Driver License (nj.gov/mvc/drivertopics/gettingcdl.htm)."},"79":{"q":"قبل أن يتمكن مقدم طلب لأول مرة في نيوجيرسي من اختباره لرخصة CDL، كم نقطة إثبات هوية يجب أن يقدم إلى MVC؟","options":["6 نقاط إثبات هوية","4 نقاط إثبات هوية","8 نقاط إثبات هوية","نقطتا إثبات هوية"],"explanation":"تستخدم نيوجيرسي برنامج التحقق \"6 نقاط إثبات هوية\"؛ يجب على مقدمي طلبات CDL إثبات ست نقاط هوية (بما في ذلك إثبات رقم الضمان الاجتماعي والعنوان والوجود القانوني). المصدر: NJ MVC, Getting your Commercial Driver License وبرنامج NJ MVC 6 Points of ID."},"80":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في نيوجيرسي للتشغيل داخل الولاية (INTRASTATE) (ضمن نيوجيرسي فقط)؟","options":["18 عاماً","21 عاماً","19 عاماً","20 عاماً"],"explanation":"يجب أن يكون عمر الشخص 18 عاماً على الأقل للحصول على رخصة CDL في نيوجيرسي للقيادة داخل الولاية؛ يقتصر السائقون دون 21 عاماً على التشغيل داخل الولاية ويجب أن يصدّقوا ذاتياً على فئة التجارة 3 أو 4. يتطلب التشغيل بين الولايات عمر 21 عاماً. المصدر: NJ MVC, Getting your Commercial Driver License و Commercial Learner Permits (CLP)."},"81":{"q":"حامل رخصة CDL في نيوجيرسي عمره 20 عاماً يقتصر على أي نوع من التشغيل؟","options":["داخل الولاية فقط (ضمن نيوجيرسي)","بين الولايات فقط (عبر حدود الولايات)","كلاهما بين الولايات وداخل الولاية","نقل المواد الخطرة فقط"],"explanation":"يجوز للسائقين دون 21 عاماً التشغيل فقط في التجارة داخل الولاية (ضمن نيوجيرسي) ويجب أن يختاروا فئة التصديق الذاتي التجاري 3 أو 4. لا يُسمح بالتشغيل بين الولايات حتى سن 21 عاماً. المصدر: NJ MVC, Commercial Learner Permits (CLP)."},"82":{"q":"ما التدريب الذي يجب على مقدم الطلب في نيوجيرسي إكماله قبل إجراء اختبار مهارات CDL لأول مرة؟","options":["تدريب السائق المبتدئ (Entry-Level Driver Training - ELDT) من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA","دورة قيادة دفاعية تديرها الولاية في وكالة MVC","شهادة سلامة تجارية من OSHA مدتها 40 ساعة","صف معالجة الحمولات الزائدة الحجم معتمد من NJDOT"],"explanation":"اعتباراً من 7 فبراير 2022، يجب على مقدمي الطلبات إكمال تدريب السائق المبتدئ (ELDT) من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA قبل إجراء اختبار مهارات CDL (وقبل اختبار معرفة HAZMAT). المصدر: NJ MVC, Getting your Commercial Driver License؛ FMCSA ELDT rule (49 CFR Part 380)."},"83":{"q":"يتضمن التصديق الذاتي لرخصة CDL في نيوجيرسي كم فئة تجارة يجب على مقدم الطلب الاختيار من بينها؟","options":["4 فئات","فئتان","3 فئات","5 فئات"],"explanation":"هناك أربع فئات تصديق ذاتي تجاري: (1) بين الولايات غير معفاة، (2) بين الولايات معفاة، (3) داخل الولاية غير معفاة، و(4) داخل الولاية معفاة. يجب على مقدم الطلب اختيار واحدة. المصدر: NJ MVC, CDL Self-Certification and Medical Examiner Certificate (cdlmedcert.htm)."},"84":{"q":"أي فئات تصديق ذاتي تتطلب أن يكون لدى حامل رخصة CDL شهادة فاحص طبي سارية مُسجّلة في نيوجيرسي؟","options":["بين الولايات غير معفاة (1) وداخل الولاية غير معفاة (3)","بين الولايات معفاة (2) وداخل الولاية معفاة (4)","بين الولايات غير معفاة (1) وبين الولايات معفاة (2)","بين الولايات غير معفاة (1) فقط"],"explanation":"تتطلب الفئات \"غير المعفاة\" (1 و3) شهادة فاحص طبي سارية. أما الفئات \"المعفاة\" (2 و4) فلا تتطلب واحدة ما لم يكن لدى السائق تصديق نقل ركاب (P) أو حافلة مدرسية (S). المصدر: NJ MVC, CDL Self-Certification and Medical Examiner Certificate."},"85":{"q":"كيف تصل شهادة الفاحص الطبي للسائق عادةً إلى MVC في نيوجيرسي بموجب القواعد الحالية؟","options":["إلكترونياً، تُرسَل من السجل الوطني التابع لـ FMCSA إلى وكالة ترخيص الولاية","يرسل السائق نسخة ورقية مصدّقة بالبريد إلى مقر NJDOT","يقوم صاحب عمل السائق بتقديمها إلى شرطة ولاية نيوجيرسي","تُرسلها شركة الشحن بالفاكس إلى وكالة MVC المحلية"],"explanation":"يقدّم الفاحصون الطبيون نتائج الفحص إلكترونياً إلى السجل الوطني التابع لـ FMCSA، ويُرسَل التصديق إلكترونياً إلى وكالة ترخيص السائقين بالولاية (NJ MVC)؛ ولا يُطلب أي شهادة ورقية (نموذج MCSA-5876) كإثبات. المصدر: NJ MVC, CDL Self-Certification and Medical Examiner Certificate."},"86":{"q":"من المخوّل بإجراء الفحص البدني لشهادة الفاحص الطبي لحامل رخصة CDL؟","options":["فاحص طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA","أي طبيب مرخّص في نيوجيرسي، بغض النظر عن حالة إدراجه في السجل","ممرضة في وكالة ترخيص تابعة لـ MVC","ضابط صحة مهنية موظف لدى NJDOT"],"explanation":"يجب أن يُجرى الفحص من قبل فاحص طبي معتمد فيدرالياً ومدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA؛ ويقدّم ذلك الفاحص النتائج إلكترونياً. المصدر: NJ MVC, CDL Self-Certification and Medical Examiner Certificate."},"87":{"q":"ماذا يحصل عليه مقدم الطلب في نيوجيرسي بعد اجتياز اختبار(ات) معرفة CDL؟","options":["تصريح متعلّم القيادة التجارية (Commercial Learner's Permit - CLP)","رخصة قيادة تجارية كاملة (CDL)","بطاقة تصديق HAZMAT مؤقتة","شهادة إعفاء من اختبار المهارات"],"explanation":"يؤهّل اجتياز اختبار(ات) المعرفة المطلوبة مقدم الطلب للحصول على تصريح متعلّم القيادة التجارية (CLP)، الذي يسمح بالتدريب تحت الإشراف قبل اختبار المهارات. لا تُصدر رخصة CDL إلا بعد اجتياز اختبار المهارات. المصدر: NJ MVC, Getting your Commercial Driver License و Commercial Learner Permits (CLP)."},"88":{"q":"ما هي النسبة المئوية الدنيا التي يجب أن يحققها مقدم الطلب لاجتياز اختبار معرفة CDL في نيوجيرسي؟","options":["80%","70%","75%","90%"],"explanation":"يجب على كل مقدم طلب الإجابة بشكل صحيح على 80% على الأقل من الأسئلة لاجتياز اختبار معرفة CDL في نيوجيرسي. المصدر: NJ MVC, CDL Tests (cdltest.htm)."},"89":{"q":"يتكوّن اختبار المعرفة العامة لرخصة CDL في نيوجيرسي من كم سؤالاً؟","options":["50 سؤالاً","30 سؤالاً","100 سؤال","25 سؤالاً"],"explanation":"يتضمن اختبار معرفة CDL اختباراً عاماً من 50 سؤالاً، بالإضافة إلى اختبارات إضافية منفصلة لكل تصديق مطلوب. المصدر: NJ MVC, CDL Tests (cdltest.htm)."},"90":{"q":"كم تبلغ مدة صلاحية تصريح متعلّم القيادة التجارية (CLP) في نيوجيرسي بعد إصداره؟","options":["180 يوماً","90 يوماً","سنة واحدة","60 يوماً"],"explanation":"تصريح CLP في نيوجيرسي صالح لمدة 180 يوماً من تاريخ الإصدار. المصدر: NJ MVC, Commercial Learner Permits (CLP) (cdlclp.htm)."},"91":{"q":"كم مرة يمكن تجديد تصريح متعلّم القيادة التجارية (CLP) في نيوجيرسي؟","options":["مرة واحدة","لا يمكن تجديده","مرتان","عدداً غير محدود من المرات"],"explanation":"تصريح CLP في نيوجيرسي صالح لمدة 180 يوماً ويمكن تجديده مرة واحدة فقط (لفترة إضافية) دون إعادة اختبارات المعرفة. المصدر: NJ MVC, Commercial Learner Permits (CLP)."},"92":{"q":"بعد إصدار تصريح CLP في نيوجيرسي، ما هو الحد الأدنى للمدة التي يجب على السائق الاحتفاظ به قبل إجراء اختبار مهارات CDL؟","options":["14 يوماً","30 يوماً","7 أيام","10 أيام"],"explanation":"يجب على حامل تصريح CLP الانتظار 14 يوماً على الأقل بعد إصدار التصريح قبل إجراء اختبار مهارات CDL (اختبار الطريق). المصدر: NJ MVC, Getting your Commercial Driver License؛ القاعدة الفيدرالية لـ CLP (49 CFR 383.25)."},"93":{"q":"يتكوّن اختبار مهارات CDL في نيوجيرسي من أي ثلاثة أجزاء، بالترتيب؟","options":["الفحص قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","المعرفة التحريرية، وفحص النظر، والقيادة على الطريق","فحص فرامل الهواء، والركن الموازي، والاندماج على الطريق السريع","اختبار الربط، واختبار الرجوع للخلف، ومعالجة HAZMAT"],"explanation":"يتكوّن اختبار مهارات CDL (اختبار الطريق) من ثلاثة أجزاء تُجرى بالتسلسل: الفحص قبل الرحلة، واختبار مهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: NJ MVC, CDL Tests (cdltest.htm)."},"94":{"q":"خلال جزء الفحص قبل الرحلة من اختبار المهارات في نيوجيرسي، يجب على مقدم الطلب إظهار القدرة على فعل ماذا؟","options":["تحديد وشرح المكونات التي ينبغي فحصها وسبب ذلك","إصلاح غرفة فرامل هواء معطلة في أقل من خمس دقائق","تلاوة دليل CDL بأكمله من الذاكرة","تفكيك وإعادة تجميع العجلة الخامسة (fifth wheel)"],"explanation":"في اختبار الفحص قبل الرحلة، يجب على مقدم الطلب إظهار أنه قادر على تحديد كل مكوّن يجب فحصه وشرح سبب فحصه، مما يثبت أن المركبة آمنة للقيادة. المصدر: NJ MVC, CDL Tests (cdltest.htm)."},"95":{"q":"لاختبار المهارات، يجب على مقدم الطلب توفير مركبة تجارية ممثلة تستوفي أي شرط؟","options":["فحص ساري، وتسجيل وتأمين صالحان، وبلا حمولة أو مواد خطرة","مركبة محمّلة إلى أقصى تصنيف للوزن الإجمالي","مركبة لا يزيد عمرها عن سنتين","مركبة مملوكة فقط لناقل بمركبة آلية مرخّص"],"explanation":"يجب على مقدمي الطلبات توفير مركبة تجارية مناسبة وممثلة للفئة المطلوبة مع فحص ساري، وتسجيل وتأمين صالحين، وتصنيف وزن إجمالي/لافتات مناسبة، وبلا حمولة أو مواد خطرة على متنها. المصدر: NJ MVC, CDL Tests (cdltest.htm)."},"96":{"q":"كم مرة يجب تجديد رخصة CDL في نيوجيرسي؟","options":["كل 4 سنوات","كل سنتين","كل 5 سنوات","كل 8 سنوات"],"explanation":"تُصدر رخصة CDL القياسية في نيوجيرسي لمدة أربع سنوات ويجب تجديدها كل 4 سنوات (قد تُحتسب أول رخصة CDL بشكل نسبي لتطابق انتهاء صلاحية الرخصة الأساسية). المصدر: NJ MVC, Getting your Commercial Driver License (gettingcdl.htm)."},"97":{"q":"أي عبارة بشأن تجديد رخصة CDL في نيوجيرسي صحيحة؟","options":["يجب تجديدها شخصياً في وكالة MVC، وليس عبر الإنترنت أو بالبريد","يمكن تجديدها بالكامل عبر الإنترنت مثل رخصة Class D الأساسية","يمكن تجديدها بالبريد فقط إذا لم تكن هناك تصديقات","تُجدَّد تلقائياً دون الحاجة إلى أي إجراء من السائق"],"explanation":"على عكس رخصة القيادة الأساسية، لا يمكن تجديد رخصة CDL في نيوجيرسي عبر الإنترنت أو بالبريد؛ يجب على الحامل التجديد شخصياً في وكالة MVC وتقديم المستندات المطلوبة وحالة التصديق الطبي الحالية. ملاحظة: قد تتغير الرسوم الدقيقة، لذا تحقق من المبالغ الحالية مع MVC. المصدر: NJ MVC CDL renewal guidance."}}};
